def _lseg_window_request_item(
    *,
    stage: str,
    start_text: str = "2024-01-01",
    end_text: str = "2024-03-31",
) -> lseg_batching.RequestItem:
    return lseg_batching.RequestItem(
        item_id="item-1",
        stage=stage,
        instrument="AAA.N",
        batch_key=f"{start_text}|{end_text}",
        fields=("TR.Field",),
        parameters={"SDate": start_text, "EDate": end_text},
        payload={},
    )


def _lookup_request_item(
    item_id: str,
    *,
    bridge_row_id: str = "bridge-1",
    identifier_type: str = "ticker",
    instrument: str = "AAA.N",
) -> lseg_batching.RequestItem:
    return lseg_batching.RequestItem(
        item_id=item_id,
        stage="lookup",
        instrument=instrument,
        batch_key=identifier_type,
        fields=lseg_lookup_api.LOOKUP_FIELDS,
        parameters={},
        payload={
            "bridge_row_id": bridge_row_id,
            "identifier_type": identifier_type,
            "lookup_input": instrument,
        },
    )


