def test_sample_diagnostics_doc_id_sampler_uses_real_rust_extension_when_built() -> None:
    if not sample_diagnostics.get_sample_item_diagnostics_rust_accel_metrics()["rust_accel_available"]:
        pytest.skip("LM2011 Rust extension is not built in this environment")
    sample_diagnostics.reset_sample_item_diagnostics_rust_accel_metrics()

    pairs = _sample_scope_doc_item_pairs()
    actual = sample_diagnostics._sample_doc_ids_from_doc_item_pairs(
        pairs,
        item_codes=("item_1", "item_1a", "item_7"),
        sample_doc_count=4,
        seed=17,
    )
    expected = sample_diagnostics._sample_doc_ids_from_doc_item_pairs_py(
        pairs,
        item_codes=("item_1", "item_1a", "item_7"),
        sample_doc_count=4,
        seed=17,
    )

    assert actual["doc_id"].to_list() == expected["doc_id"].to_list()
    metrics = sample_diagnostics.get_sample_item_diagnostics_rust_accel_metrics()
    assert metrics["sample_doc_ids_fast_success"] == 1
    assert metrics["sample_doc_ids_fallbacks"] == 0


def test_sample_diagnostics_doc_id_sampler_matches_python_fallback_for_sample_values() -> None:
    pairs = _sample_scope_doc_item_pairs()
    cases = [
        (("item_1", "item_1a", "item_7"), 4, 17),
        (("missing", "item_7"), 3, 99),
        (("item_1",), 0, 3),
        (("item_1", "item_1a", "item_7"), 99, 7),
    ]
    for item_codes, sample_doc_count, seed in cases:
        actual = sample_diagnostics._sample_doc_ids_from_doc_item_pairs(
            pairs,
            item_codes=item_codes,
            sample_doc_count=sample_doc_count,
            seed=seed,
        )
        expected = sample_diagnostics._sample_doc_ids_from_doc_item_pairs_py(
            pairs,
            item_codes=item_codes,
            sample_doc_count=sample_doc_count,
            seed=seed,
        )
        assert actual["doc_id"].to_list() == expected["doc_id"].to_list()


