def test_sec_ccm_markdown_value_uses_real_rust_extension_when_built() -> None:
    if not sec_ccm_pipeline.get_sec_ccm_pipeline_rust_accel_metrics()["rust_accel_available"]:
        pytest.skip("LM2011 Rust extension is not built in this environment")
    sec_ccm_pipeline.reset_sec_ccm_pipeline_rust_accel_metrics()

    values = [
        None,
        math.nan,
        12.3456789,
        dt.date(2024, 1, 31),
        dt.datetime(2024, 1, 31, 12, 30, tzinfo=dt.timezone.utc),
        "return|mean",
    ]

    for value in values:
        assert sec_ccm_pipeline._fmt_markdown_value(value) == sec_ccm_pipeline._fmt_markdown_value_py(value)

    metrics = sec_ccm_pipeline.get_sec_ccm_pipeline_rust_accel_metrics()
    assert metrics["markdown_value_fast_success"] == len(values)
    assert metrics["markdown_value_fallbacks"] == 0


def test_sec_ccm_markdown_table_uses_real_rust_extension_when_built() -> None:
    if not sec_ccm_pipeline.get_sec_ccm_pipeline_rust_accel_metrics()["rust_accel_available"]:
        pytest.skip("LM2011 Rust extension is not built in this environment")
    sec_ccm_pipeline.reset_sec_ccm_pipeline_rust_accel_metrics()

    actual = sec_ccm_pipeline._to_markdown_table(_sec_ccm_markdown_frame(), max_rows=2)
    expected = sec_ccm_pipeline._to_markdown_table_py(_sec_ccm_markdown_frame(), max_rows=2)

    assert actual == expected
    assert "return\\|mean" in actual
    assert "Truncated to first 2 rows" in actual
    metrics = sec_ccm_pipeline.get_sec_ccm_pipeline_rust_accel_metrics()
    assert metrics["markdown_table_column_fast_success"] == 1
    assert metrics["markdown_table_fast_success"] == 0
    assert metrics["markdown_table_column_fallbacks"] == 0
    assert metrics["markdown_table_fallbacks"] == 0


def test_sec_ccm_markdown_table_falls_back_to_row_rust_bridge(monkeypatch) -> None:
    class FakeRust:
        def sec_ccm_markdown_table_columns(self, *_args):
            raise RuntimeError("column bridge unavailable")

        def sec_ccm_markdown_table(self, columns, rows, total_height, max_rows):
            lines = [
                "| " + " | ".join(columns) + " |",
                "| " + " | ".join(["---"] * len(columns)) + " |",
            ]
            for row in rows:
                lines.append(
                    "| "
                    + " | ".join(sec_ccm_pipeline._fmt_markdown_value_py(row[column]) for column in columns)
                    + " |"
                )
            out = "\n".join(lines)
            if total_height > max_rows:
                out += f"\n\n_Truncated to first {max_rows} rows._"
            return out

    monkeypatch.setattr(sec_ccm_pipeline, "_lm2011_rust", FakeRust())
    sec_ccm_pipeline.reset_sec_ccm_pipeline_rust_accel_metrics()

    assert sec_ccm_pipeline._to_markdown_table(_sec_ccm_markdown_frame(), max_rows=2) == (
        sec_ccm_pipeline._to_markdown_table_py(_sec_ccm_markdown_frame(), max_rows=2)
    )

    metrics = sec_ccm_pipeline.get_sec_ccm_pipeline_rust_accel_metrics()
    assert metrics["markdown_table_column_fast_failures"] == 1
    assert metrics["markdown_table_column_fallbacks"] == 1
    assert metrics["markdown_table_fast_success"] == 1
    assert metrics["markdown_table_fallbacks"] == 0


