def test_lm2011_real_rust_extension_counts_tokens_when_built() -> None:
    if not lm2011_text.get_lm2011_rust_accel_metrics()["rust_accel_available"]:
        pytest.skip("LM2011 Rust extension is not built in this environment")
    lm2011_text.reset_lm2011_rust_accel_metrics()

    assert lm2011_text.tokenize_lm2011_text("Alpha-\n beta LOSS") == ["alphabeta", "loss"]
    assert lm2011_text.count_lm2011_tokens("Alpha-\n beta LOSS loss") == 3
    counter = lm2011_text._build_lm2011_rust_token_counter(
        vocabulary=frozenset({"loss"}),
        master_dictionary_words=frozenset({"loss", "alphabeta"}),
    )

    assert counter is not None
    assert lm2011_text._count_document_tokens(
        "Alpha-\n beta LOSS loss",
        vocabulary=frozenset({"loss"}),
        master_dictionary_words=frozenset({"loss", "alphabeta"}),
        rust_counter=counter,
    ) == (3, 3, Counter({"loss": 2}))
    metrics = lm2011_text.get_lm2011_rust_accel_metrics()
    assert metrics["tokenize_fast_success"] == 1
    assert metrics["token_count_fast_success"] == 1
    assert metrics["counter_init_success"] == 1
    assert metrics["count_fast_success"] == 1


