def test_lm2011_visible_prefix_base_source_uses_batch_lm_token_expr_when_built() -> None:
    if not lm2011_text.get_lm2011_rust_accel_metrics()["rust_accel_available"]:
        pytest.skip("LM2011 Rust extension is not built in this environment")
    frame = _visible_prefix_sentence_source_frame()
    lm2011_text.reset_lm2011_rust_accel_metrics()

    out = lm2011_sample_runner._build_finbert_visible_prefix_base_source_lf(frame.lazy()).collect()

    by_doc = {row["doc_id"]: row for row in out.to_dicts()}
    assert by_doc["doc-1"]["original_lm_token_count"] == lm2011_text._count_lm2011_token_values_py(
        ["Alpha-\n beta LOSS\n\nSecond sentence"]
    )[0]
    assert by_doc["doc-1"]["visible_prefix_lm_token_count"] == lm2011_text._count_lm2011_token_values_py(
        ["Alpha beta\n\nSecond"]
    )[0]
    assert by_doc["doc-2"]["visible_prefix_lm_token_count"] == 1
    metrics = lm2011_text.get_lm2011_rust_accel_metrics()
