def _assert_document_stats_equal(
    actual: tuple[list[dict[str, object]], dict[str, Counter[str]], dict[str, int], dict[str, int], dict[str, float]],
    expected: tuple[list[dict[str, object]], dict[str, Counter[str]], dict[str, int], dict[str, int], dict[str, float]],
) -> None:
    actual_base, actual_counts, actual_totals, actual_recognized, actual_idf = actual
    expected_base, expected_counts, expected_totals, expected_recognized, expected_idf = expected
    assert actual_base == expected_base
    assert actual_counts == expected_counts
    assert actual_totals == expected_totals
    assert actual_recognized == expected_recognized
    assert set(actual_idf) == set(expected_idf)
    for token, expected_value in expected_idf.items():
        assert actual_idf[token] == pytest.approx(expected_value)


