def _pass1_feature_row_inputs() -> dict[str, object]:
    batch = pl.DataFrame(
        {
            "doc_id": ["d1", "d2", "d3"],
            "cik_10": ["0000000001", "0000000002", "0000000003"],
            "filing_date": [dt.date(2020, 1, 1), dt.date(2020, 2, 1), dt.date(2020, 3, 1)],
            "document_type_filename": ["10-K", "10-K/A", None],
            "normalized_form": ["10-K", "10-K/A", None],
            "item_id": ["7", "7", "7"],
            "full_text": ["Loss risk gain", "loss loss lawsuit-risk", None],
        }
    )
    pass1_rows, document_frequency = lm2011_text._prepare_pass1_rows_py(
        batch,
        **{
            **_pass1_kwargs(),
            "vocabulary": frozenset({"loss", "risk", "gain", "lawsuit-risk"}),
            "master_dictionary_words": frozenset({"loss", "gain", "lawsuit-risk"}),
        },
    )
    idf_by_token = {
        token: lm2011_text._lm2011_inverse_document_frequency(len(pass1_rows), doc_freq)
        for token, doc_freq in document_frequency.items()
    }
    return {
        "pass1_rows": pass1_rows,
        "raw_form_col": "document_type_filename",
        "token_count_col": "token_count_full_10k",
        "total_token_count_col": "total_token_count_full_10k",
        "signal_specs": (
            ("negative", frozenset({"loss", "risk", "lawsuit-risk"}), True),
            ("positive", frozenset({"gain"}), False),
        ),
        "idf_by_token": idf_by_token,
        "cleaning_policy_id": "raw_item_text",
    }


