def test_sec_identifier_utilities_use_real_rust_extension_when_built() -> None:
    if not sec_utilities.get_sec_utilities_rust_accel_metrics()["rust_accel_available"]:
        pytest.skip("LM2011 Rust extension is not built in this environment")
    sec_utilities.reset_sec_utilities_rust_accel_metrics()

    assert sec_utilities._digits_only("0000123456-23-000045") == "000012345623000045"
    assert sec_utilities._digits_only("abc") is None
    assert sec_utilities._cik_10(123456) == "0000123456"
    assert sec_utilities._cik_10(True) == "0000000001"
    assert sec_utilities._make_doc_id("0000123456", "000012345623000045") == "0000123456:000012345623000045"
    assert sec_utilities._make_doc_id(None, "000012345623000045") == "UNK:000012345623000045"
    assert sec_utilities._normalize_newlines("A\r\nB\rC") == "A\nB\nC"
    assert sec_utilities._parse_date("20240131") == dt.date(2024, 1, 31)
    assert sec_utilities._parse_date("2024-02-29") == dt.date(2024, 2, 29)
    assert sec_utilities._parse_date("2024-02-30") is None
    assert sec_utilities._roman_to_int(" iv ") == 4
    assert sec_utilities._roman_to_int("IL") == 49
    assert sec_utilities._roman_to_int("bad") is None
    assert sec_utilities._default_part_for_item_id("7A") == "II"
    assert sec_utilities._default_part_for_item_id("16") == "IV"
    assert sec_utilities._default_part_for_item_id("17") is None
    assert sec_utilities._prefix_is_bullet(" \t-*•·–— ") is True
    assert sec_utilities._prefix_is_bullet(" - Item ") is False

    metrics = sec_utilities.get_sec_utilities_rust_accel_metrics()
    assert metrics["digits_only_fast_success"] == 2
    assert metrics["cik10_fast_success"] == 2
    assert metrics["doc_id_fast_success"] == 2
    assert metrics["normalize_newlines_fast_success"] == 1
    assert metrics["parse_date_fast_success"] == 3
    assert metrics["roman_to_int_fast_success"] == 3
    assert metrics["default_part_fast_success"] == 3
    assert metrics["prefix_is_bullet_fast_success"] == 2
    assert metrics["digits_only_fallbacks"] == 0


def test_sec_identifier_utilities_match_python_fallback_for_sample_values() -> None:
    digit_values = [None, "", "abc", "0000123456-23-000045", "abc 123 def", "١٢-٣"]
    for value in digit_values:
        assert sec_utilities._digits_only(value) == sec_utilities._digits_only_py(value)

    cik_values = [None, 0, 1, 123456, True, False, "123", 12.9, -1]
    for value in cik_values:
        assert sec_utilities._cik_10(value) == sec_utilities._cik_10_py(value)

    doc_id_values = [
        ("0000123456", "000012345623000045"),
        (None, "000012345623000045"),
        ("", "000012345623000045"),
        ("0000123456", None),
    ]
    for cik10, accession in doc_id_values:
        assert sec_utilities._make_doc_id(cik10, accession) == sec_utilities._make_doc_id_py(cik10, accession)

    newline_values = ["A\r\nB\rC", "plain", ""]
    for value in newline_values:
        assert sec_utilities._normalize_newlines(value) == sec_utilities._normalize_newlines_py(value)

    date_values = [
        None,
        "",
        "20240131",
        "2024-01-31",
        "2024-02-30",
        "2024-01-31 00:00:00",
        dt.date(2024, 1, 31),
        dt.datetime(2024, 1, 31, 12, 30),
        20240131,
    ]
    for value in date_values:
        assert sec_utilities._parse_date(value) == sec_utilities._parse_date_py(value)

    roman_values = ["I", "iv", "IL", "IIII", "", "bad"]
    for value in roman_values:
        assert sec_utilities._roman_to_int(value) == sec_utilities._roman_to_int_py(value)

    item_id_values = [None, "", "1", "4A", "7A", "10", "14", "16", "17", "A1", " 7"]
    for value in item_id_values:
        assert sec_utilities._default_part_for_item_id(value) == (
            sec_utilities._default_part_for_item_id_py(value)
        )

    prefix_values = ["", " ", "\t-*•·–—", " - Item ", "abc", "\n\r\t", "•"]
    for value in prefix_values:
        assert sec_utilities._prefix_is_bullet(value) == sec_utilities._prefix_is_bullet_py(value)


