def _part_marker_case_match(line: str, mode: str):
    if mode == "line":
        match = sec_heuristics.PART_LINESTART_PATTERN.match(line)
    else:
        match = sec_heuristics.PART_MARKER_PATTERN.search(line)
    assert match is not None
    return match


