def _extraction_part_marker_lines() -> list[str]:
    return [
        "Table of Contents",
        "PART I Financial Information",
        "Item 1. Financial Statements",
        "See Part II for more detail",
        "FORM 10-Q COVER PAGE PART I FINANCIAL INFORMATION",
        "FORM 10-Q COVER PAGE PART II OTHER INFORMATION",
        "PART III Item 10. Directors",
        "PART IV see Item 15",
        "    PART II OTHER INFORMATION",
    ]


def _line_starts_for_lines(lines: list[str]) -> list[int]:
    starts: list[int] = []
    cursor = 0
    for line in lines:
        starts.append(cursor)
        cursor += len(line) + 1
    return starts


def _part_marker_tuples(markers: list[object]) -> list[tuple[int, str, int, bool]]:
    return [
        (
            int(marker.start),
            str(marker.part),
            int(marker.line_index),
            bool(marker.high_confidence),
        )
        for marker in markers
    ]


def test_extraction_scan_part_markers_uses_real_rust_extension_when_built() -> None:
    if not extraction.get_extraction_fastpath_metrics()["rust_accel_available"]:
        pytest.skip("LM2011 Rust extension is not built in this environment")
    extraction.reset_extraction_fastpath_metrics()
    lines = _extraction_part_marker_lines()
    line_starts = _line_starts_for_lines(lines)

    for scan_sparse_layout, is_10q in [(True, False), (True, True), (False, False)]:
        actual = extraction._scan_part_markers_v2(
            lines,
            line_starts,
            allowed_parts={"I", "II", "III", "IV"},
            scan_sparse_layout=scan_sparse_layout,
            toc_mask={0},
            is_10q=is_10q,
        )
        expected = extraction._scan_part_markers_v2_py(
            lines,
            line_starts,
            allowed_parts={"I", "II", "III", "IV"},
            scan_sparse_layout=scan_sparse_layout,
            toc_mask={0},
            is_10q=is_10q,
        )
        assert _part_marker_tuples(actual) == _part_marker_tuples(expected)

    metrics = extraction.get_extraction_fastpath_metrics()
    assert metrics["scan_part_markers_rust_fast_success"] == 3
    assert metrics["scan_part_markers_rust_fallbacks"] == 0


def test_extraction_scan_part_markers_matches_python_fallback_for_sample_values() -> None:
    lines = _extraction_part_marker_lines()
    line_starts = _line_starts_for_lines(lines)
    cases = [
        (True, False, {"I", "II", "III", "IV"}, {0}),
        (True, True, {"I", "II", "III", "IV"}, {0}),
        (False, False, {"I", "II"}, set()),
        (True, False, {"II"}, {0, 8}),
    ]

    for scan_sparse_layout, is_10q, allowed_parts, toc_mask in cases:
        assert _part_marker_tuples(
            extraction._scan_part_markers_v2(
                lines,
                line_starts,
                allowed_parts=allowed_parts,
                scan_sparse_layout=scan_sparse_layout,
                toc_mask=toc_mask,
                is_10q=is_10q,
            )
        ) == _part_marker_tuples(
            extraction._scan_part_markers_v2_py(
                lines,
                line_starts,
                allowed_parts=allowed_parts,
                scan_sparse_layout=scan_sparse_layout,
                toc_mask=toc_mask,
                is_10q=is_10q,
            )
        )


