def _embedded_heading_hit_tuples(hits: list[object]) -> list[tuple[object, ...]]:
    return [
        (
            hit.kind,
            hit.classification,
            hit.item_id,
            hit.part,
            hit.line_idx,
            hit.char_pos,
            hit.full_text_len,
            hit.snippet,
        )
        for hit in hits
    ]


