def test_sec_filename_parser_uses_real_rust_extension_when_built() -> None:
    if not filing_text.get_filing_text_rust_accel_metrics()["rust_accel_available"]:
        pytest.skip("LM2011 Rust extension is not built in this environment")
    filing_text.reset_filing_text_rust_accel_metrics()

    meta = filing_text.parse_filename_minimal("20240131_10-K_edgar_data_1234_0001234-24-000001.txt")
    invalid = filing_text.parse_filename_minimal("not-a-filing.txt")

    assert meta["filename_parse_ok"] is True
    assert meta["file_date_filename"] == "20240131"
    assert meta["document_type_filename"] == "10-K"
    assert meta["cik"] == 1234
    assert meta["cik_10"] == "0000001234"
    assert meta["accession_number"] == "0001234-24-000001"
    assert meta["accession_nodash"] == "000123424000001"
    assert meta["doc_id"] == "0000001234:0001234-24-000001"
    assert invalid == filing_text._filename_parse_failure()

    metrics = filing_text.get_filing_text_rust_accel_metrics()
    assert metrics["filename_parse_fast_success"] == 2
    assert metrics["filename_parse_fallbacks"] == 0


