def test_boundary_authority_status_uses_real_rust_extension_when_built() -> None:
    if not filing_text.get_filing_text_rust_accel_metrics()["rust_accel_available"]:
        pytest.skip("LM2011 Rust extension is not built in this environment")
    filing_text.reset_filing_text_rust_accel_metrics()

    trusted = _trusted_boundary_status_row()
    missing_offset = {**trusted, "boundary_content_end": None}
    verified_int = {**trusted, "boundary_start_selection_verified": 1}
    toc_rejected = {**trusted, "boundary_start_candidates_toc_rejected": "2"}
    truncated = {**trusted, "boundary_truncated_successor_heading": True}

    assert filing_text.classify_boundary_authority_status({}) == filing_text.BOUNDARY_AUTHORITY_STATUS_UNKNOWN
    assert filing_text.classify_boundary_authority_status(trusted) == filing_text.BOUNDARY_AUTHORITY_STATUS_TRUSTED
    assert (
        filing_text.classify_boundary_authority_status(missing_offset)
        == filing_text.BOUNDARY_AUTHORITY_STATUS_REVIEW_NEEDED
    )
    assert (
        filing_text.classify_boundary_authority_status(verified_int)
        == filing_text.BOUNDARY_AUTHORITY_STATUS_REVIEW_NEEDED
    )
    assert (
        filing_text.classify_boundary_authority_status(toc_rejected)
        == filing_text.BOUNDARY_AUTHORITY_STATUS_REVIEW_NEEDED
    )
    assert (
        filing_text.classify_boundary_authority_status(truncated)
        == filing_text.BOUNDARY_AUTHORITY_STATUS_REVIEW_NEEDED
    )

    metrics = filing_text.get_filing_text_rust_accel_metrics()
    assert metrics["boundary_status_fast_success"] == 6
    assert metrics["boundary_status_fallbacks"] == 0


