def test_html_audit_scalar_helpers_use_real_rust_extension_when_built() -> None:
    if not html_audit.get_html_audit_rust_accel_metrics()["rust_accel_available"]:
        pytest.skip("LM2011 Rust extension is not built in this environment")
    html_audit.reset_html_audit_rust_accel_metrics()

    assert html_audit._safe_slug(" 0000123456:abc/def ") == "0000123456_abc_def"
    assert html_audit._safe_slug("!!!") == "unknown"
    assert html_audit._parse_bool(True) is True
    assert html_audit._parse_bool(" yes ") is True
    assert html_audit._parse_bool("no") is False
    assert html_audit._parse_int(" 12 ", default=-1) == 12
    assert html_audit._parse_int("bad", default=-1) == -1
    assert html_audit._part_rank(" iii ") == 3
    assert html_audit._item_id_sort_key(" 7A ") == (7, "A")
    assert html_audit._quartile_edges([4, 1, 2, 3]) == (1, 2, 3)
    assert html_audit._quartile_bucket(4, (1, 2, 3)) == "Q4"
    assert html_audit.classify_filing_status({"any_fail": "yes", "any_warn": False}) == "fail"
    assert html_audit.classify_filing_status({"any_fail": False, "any_warn": "true"}) == "warning"
    assert html_audit.classify_filing_status({"filing_exclusion_reason": "  "}) == "pass"

    metrics = html_audit.get_html_audit_rust_accel_metrics()
    assert metrics["safe_slug_fast_success"] == 2
    assert metrics["parse_bool_fast_success"] == 3
    assert metrics["parse_int_fast_success"] == 2
    assert metrics["part_rank_fast_success"] == 1
    assert metrics["item_id_sort_key_fast_success"] == 1
    assert metrics["quartile_edges_fast_success"] == 1
    assert metrics["quartile_bucket_fast_success"] == 1
    assert metrics["filing_status_fast_success"] == 3
    assert metrics["safe_slug_fallbacks"] == 0


def test_html_audit_scalar_helpers_match_python_fallback_for_sample_values() -> None:
    for value in ["abc def", " 0000123456:abc/def ", "already_ok-1", "Straße", "!!!"]:
        assert html_audit._safe_slug(value) == html_audit._safe_slug_py(value)

    for value in [True, False, None, "1", "true", "yes", "Y", "t", "0", "no", ""]:
        assert html_audit._parse_bool(value) == html_audit._parse_bool_py(value)

    for value, default in [(None, -1), ("12", -1), ("bad", -1), (True, -1), ("1_000", -1)]:
        assert html_audit._parse_int(value, default=default) == html_audit._parse_int_py(value, default=default)

    for value in ["I", "ii", " IV ", "V", ""]:
        assert html_audit._part_rank(value) == html_audit._part_rank_py(value)

    for value in ["1", "7A", "10K", "abc", "", "١"]:
        assert html_audit._item_id_sort_key(value) == html_audit._item_id_sort_key_py(value)

    for values in [[], [1], [4, 1, 2, 3], [10, 20, 30, 40, 50]]:
        assert html_audit._quartile_edges(values) == html_audit._quartile_edges_py(values)

    for value in [0, 1, 2, 3, 4, 10]:
        assert html_audit._quartile_bucket(value, (1, 2, 3)) == html_audit._quartile_bucket_py(value, (1, 2, 3))

    status_rows = [
        {"any_fail": True, "any_warn": False, "filing_exclusion_reason": ""},
        {"any_fail": False, "any_warn": True, "filing_exclusion_reason": ""},
        {"any_fail": "0", "any_warn": "no", "filing_exclusion_reason": " filtered "},
        {"any_fail": None, "any_warn": None, "filing_exclusion_reason": None},
    ]
    for row in status_rows:
        assert html_audit.classify_filing_status(row) == html_audit._classify_filing_status_py(row)


def test_html_audit_scalar_helpers_fallback_when_rust_extension_is_unavailable(monkeypatch) -> None:
    monkeypatch.setattr(html_audit, "_lm2011_rust", None)
