def _ff4_ols_frame() -> pl.DataFrame:
    mkt_rf = [0.0, 0.1, -0.2, 0.3, 0.4, -0.1, 0.2, -0.3]
    smb = [0.2, -0.1, 0.0, 0.1, -0.2, 0.3, -0.3, 0.4]
    hml = [-0.1, 0.0, 0.2, -0.2, 0.1, 0.4, -0.4, 0.3]
    mom = [0.3, -0.2, 0.1, 0.0, -0.1, 0.2, 0.4, -0.3]
    residuals = [0.0, 0.001, -0.002, 0.003, -0.001, 0.002, -0.003, 0.0015]
    long_short_return = [
        0.01 + (0.8 * market) - (0.25 * size) + (0.35 * value) + (0.15 * momentum) + residual
        for market, size, value, momentum, residual in zip(mkt_rf, smb, hml, mom, residuals)
    ]
    return pl.DataFrame(
        {
            "long_short_return": long_short_return,
            "mkt_rf": mkt_rf,
            "smb": smb,
            "hml": hml,
            "mom": mom,
        }
    )


def _assert_ols_outcome_equal(
    actual: tuple[tuple[float | None, ...], tuple[float | None, ...], tuple[float | None, ...], float | None],
    expected: tuple[tuple[float | None, ...], tuple[float | None, ...], tuple[float | None, ...], float | None],
) -> None:
    actual_coefficients, actual_standard_errors, actual_t_stats, actual_r2 = actual
    expected_coefficients, expected_standard_errors, expected_t_stats, expected_r2 = expected
    for actual_values, expected_values in (
        (actual_coefficients, expected_coefficients),
        (actual_standard_errors, expected_standard_errors),
        (actual_t_stats, expected_t_stats),
    ):
        assert len(actual_values) == len(expected_values)
        for actual_value, expected_value in zip(actual_values, expected_values):
            if expected_value is None:
                assert actual_value is None
            else:
                assert actual_value == pytest.approx(expected_value)
    if expected_r2 is None:
        assert actual_r2 is None
    else:
        assert actual_r2 == pytest.approx(expected_r2)


