def _strategy_factor_loading_df() -> pl.DataFrame:
    base = _ff4_ols_frame()
    shifted = base.with_columns((pl.col("long_short_return") + 0.02).alias("long_short_return"))
    rows: list[dict[str, object]] = []
    for idx in range(base.height):
        left = base.row(idx, named=True)
        left["sort_signal_name"] = "h4n_inf_tfidf"
        rows.append(left)
        right = shifted.row(idx, named=True)
        right["sort_signal_name"] = "fin_neg_tfidf"
        rows.append(right)
    rows.append(
        {
            "sort_signal_name": "too_short",
            "long_short_return": None,
            "mkt_rf": 0.1,
            "smb": 0.2,
            "hml": 0.3,
            "mom": 0.4,
        }
    )
    return pl.DataFrame(rows)


def _assert_strategy_factor_rows_equal(
    actual: list[dict[str, object]],
    expected: list[dict[str, object]],
) -> None:
    assert len(actual) == len(expected)
    for actual_row, expected_row in zip(actual, expected):
        assert set(actual_row) == set(expected_row)
        for key, expected_value in expected_row.items():
            actual_value = actual_row[key]
            if isinstance(expected_value, float):
                assert actual_value == pytest.approx(expected_value)
            else:
                assert actual_value == expected_value


