def test_lm2011_validation_packet_a_mda_rows_fall_back_to_row_rust_bridge(monkeypatch) -> None:
    class FakeRust:
        def lm2011_validation_packet_a_mda_row_columns(self, *_args):
            raise RuntimeError("column bridge unavailable")

        def lm2011_validation_packet_a_mda_rows(
            self,
            records,
            filing_year,
            master_dictionary,
            _threshold,
            snippet_char_limit,
        ):
            return lm2011_validation_audit._packet_a_mda_rows_from_items_py(
                pl.DataFrame(list(records)),
                filing_year,
                frozenset(master_dictionary),
                snippet_char_limit,
            )

        def lm2011_validation_truncate_text(self, text, limit):
            return lm2011_validation_audit._truncate_text_py(text, limit)

    monkeypatch.setattr(lm2011_validation_audit, "_lm2011_rust", FakeRust())
    lm2011_validation_audit.reset_lm2011_validation_audit_rust_accel_metrics()

    items_df = _validation_mda_items_frame()
    assert lm2011_validation_audit._packet_a_mda_rows_from_items(
        items_df,
        2006,
        frozenset({"gain", "lawsuit", "loss"}),
        20,
    ) == lm2011_validation_audit._packet_a_mda_rows_from_items_py(
        items_df,
        2006,
        frozenset({"gain", "lawsuit", "loss"}),
        20,
    )

    metrics = lm2011_validation_audit.get_lm2011_validation_audit_rust_accel_metrics()
    assert metrics["packet_a_mda_rows_column_fast_failures"] == 1
    assert metrics["packet_a_mda_rows_column_fallbacks"] == 1
    assert metrics["packet_a_mda_rows_fast_success"] == 1
    assert metrics["packet_a_mda_rows_fallbacks"] == 0


