def _packet_a_summary_rows() -> list[dict[str, object]]:
    rows: list[dict[str, object]] = [
        {
            "text_scope": "full_10k",
            "filing_year": 2020,
            "any_marker": True,
            "edgar_stripped_any_marker": False,
            "paper_cleaned_any_marker": False,
            "paper_cleaned_has_exhibit_marker": False,
            "current_threshold_pass": True,
            "appendix_threshold_pass": False,
            "recognized_threshold_pass": False,
            "threshold_flip": True,
            "paper_cleaned_threshold_flip": False,
            "paper_cleaned_appendix_threshold_pass": True,
            "paper_cleaned_cut_reason": "strong_anchor",
            "current_token_count": 100,
            "edgar_stripped_current_token_count": 90,
            "paper_cleaned_current_token_count": 70,
            "edgar_stripped_recognized_word_count": 80,
            "paper_cleaned_recognized_word_count": 60,
        },
        {
            "text_scope": "full_10k",
            "filing_year": 2020,
            "any_marker": False,
            "edgar_stripped_any_marker": False,
            "paper_cleaned_any_marker": False,
            "paper_cleaned_has_exhibit_marker": False,
            "current_threshold_pass": True,
            "appendix_threshold_pass": True,
            "recognized_threshold_pass": True,
            "threshold_flip": False,
            "paper_cleaned_threshold_flip": True,
            "paper_cleaned_appendix_threshold_pass": False,
            "paper_cleaned_cut_reason": "no_tail_anchor",
            "current_token_count": 80,
            "edgar_stripped_current_token_count": 78,
            "paper_cleaned_current_token_count": 78,
            "edgar_stripped_recognized_word_count": 50,
            "paper_cleaned_recognized_word_count": 50,
        },
        {
            "text_scope": "full_10k",
            "filing_year": 2021,
            "any_marker": True,
            "edgar_stripped_any_marker": True,
            "paper_cleaned_any_marker": True,
            "paper_cleaned_has_exhibit_marker": True,
            "current_threshold_pass": False,
            "appendix_threshold_pass": False,
            "recognized_threshold_pass": False,
            "threshold_flip": False,
            "paper_cleaned_threshold_flip": True,
            "paper_cleaned_appendix_threshold_pass": True,
            "paper_cleaned_cut_reason": "weak_anchor",
            "current_token_count": 30,
            "edgar_stripped_current_token_count": 20,
            "paper_cleaned_current_token_count": 10,
            "edgar_stripped_recognized_word_count": 15,
            "paper_cleaned_recognized_word_count": 5,
        },
        {
            "text_scope": "mda",
            "filing_year": 2020,
            "any_marker": False,
            "edgar_stripped_any_marker": False,
            "paper_cleaned_any_marker": False,
            "paper_cleaned_has_exhibit_marker": False,
            "current_threshold_pass": True,
            "appendix_threshold_pass": True,
            "recognized_threshold_pass": False,
            "threshold_flip": False,
            "paper_cleaned_threshold_flip": False,
            "paper_cleaned_appendix_threshold_pass": True,
            "paper_cleaned_cut_reason": "no_tail_anchor",
            "current_token_count": 20,
            "edgar_stripped_current_token_count": 18,
            "paper_cleaned_current_token_count": 17,
            "edgar_stripped_recognized_word_count": 12,
            "paper_cleaned_recognized_word_count": 11,
        },
    ]
    marker_defaults = {
        "edgar_stripped_has_sec_header": False,
        "edgar_stripped_has_html_marker": False,
        "edgar_stripped_has_table_marker": False,
        "edgar_stripped_has_exhibit_marker": False,
        "paper_cleaned_has_sec_header": False,
        "paper_cleaned_has_html_marker": False,
        "paper_cleaned_has_table_marker": False,
        "paper_cleaned_has_exhibit_marker": False,
    }
    for row in rows:
        for key, value in marker_defaults.items():
            row.setdefault(key, value)
    rows[2].update(
        {
            "edgar_stripped_has_sec_header": True,
            "edgar_stripped_has_table_marker": True,
            "edgar_stripped_has_exhibit_marker": True,
            "paper_cleaned_has_html_marker": True,
            "paper_cleaned_has_exhibit_marker": True,
        }
    )
    for index, row in enumerate(rows, start=1):
        row["doc_id"] = f"doc_{index}"
        row["paper_cleaned_cut_share"] = (
            0.25 if row["paper_cleaned_cut_reason"] != "no_tail_anchor" else None
        )
        row["example_snippet"] = f"example {index}"
        row["edgar_stripped_example_snippet"] = f"edgar example {index}"
        row["paper_cleaned_example_snippet"] = f"paper example {index}"
        row["paper_cleaned_pre_cut_tail_snippet"] = (
            f"pre cut {index}" if row["paper_cleaned_cut_reason"] != "no_tail_anchor" else None
        )
        row["paper_cleaned_post_cut_tail_snippet"] = f"post cut {index}"
    return rows


def _assert_packet_a_summary_frames_equal(actual: pl.DataFrame, expected: pl.DataFrame) -> None:
    assert actual.columns == expected.columns
    actual_rows = actual.to_dicts()
    expected_rows = expected.to_dicts()
    assert len(actual_rows) == len(expected_rows)
    for actual_row, expected_row in zip(actual_rows, expected_rows, strict=True):
        assert actual_row.keys() == expected_row.keys()
        for key, expected_value in expected_row.items():
            actual_value = actual_row[key]
            if isinstance(expected_value, float):
                assert actual_value == pytest.approx(expected_value)
            else:
                assert actual_value == expected_value


