    values = [None, 0.0, 0.5, 1.96, -1.96, 2.58, "3.0", float("inf"), float("nan")]
    for value in values:
        actual = lm2011_extension._normal_approx_two_sided_p_value(value)
        expected = lm2011_extension._normal_approx_two_sided_p_value_py(value)
        if expected is None:
            assert actual is None
        else:
            assert actual == pytest.approx(expected, rel=1e-6)


