def _extension_result_kwargs() -> dict[str, object]:
    return {
        "run_id": "run_unit",
        "sample_window": "2009_2024",
        "outcome_name": "filing_period_excess_return",
        "comparison_spec": lm2011_extension._comparison_spec_by_name("dictionary_finbert_joint"),
        "control_set": lm2011_extension._control_set_by_id("C2"),
    }


def _assert_lm2011_extension_result_rows_equal(
    actual: list[dict[str, object]],
    expected: list[dict[str, object]],
) -> None:
    assert len(actual) == len(expected)
    for actual_row, expected_row in zip(actual, expected):
        assert set(actual_row) == set(expected_row)
        for key, expected_value in expected_row.items():
            actual_value = actual_row[key]
            if isinstance(expected_value, float):
                assert isinstance(actual_value, float)
                if math.isnan(expected_value):
                    assert math.isnan(actual_value)
                elif not math.isfinite(expected_value):
                    assert actual_value == expected_value
                else:
                    assert actual_value == pytest.approx(expected_value, rel=1e-6, abs=1e-12)
            else:
                assert actual_value == expected_value


