def test_lm2011_cleaning_exhibit_tail_detector_matches_python_fallback_for_sample_values() -> None:
    body = "ITEM 1. Business\n" + " ".join(["body"] * 800)
    samples = [
        "",
        body,
        "\n".join([body, "EXHIBIT INDEX", "EXHIBIT 21"]),
        "\n".join([body, "</EX-13>", "<EX-21>"]),
        "\n".join([body, "EXHIBIT 21", "Subsidiaries", "EXHIBIT 23.1", "Consent"]),
        "\n".join(["EXHIBIT INDEX", "EXHIBIT 21", body]),
        body + "\nSee Exhibit 21 for a list of subsidiaries.",
    ]
    for text in samples:
        assert lm2011_cleaning._detect_exhibit_tail(text) == lm2011_cleaning._detect_exhibit_tail_py(text)


