            "0100-0199 Agricultural production - crops",
            "0200-0299 Agricultural production - livestock",
            "",
            "not a range",
            " 2 Food Food Products",
            "2000-2046 Food and kindred products",
            " 10 Hlth  Healthcare, Medical Equipment, and Drugs  ",
            "2830-2839 Drugs",
