def _write_doc_ownership_filing_artifact(path: Path, *, permno_column: str = "kypermno") -> list[str | None]:
    kypermno_values = [" 00123 ", "", None, "100.25"]
    pl.DataFrame(
        {
            "doc_id": ["doc_a", "doc_b", "doc_c", "doc_d"],
            "filing_date": [
                dt.date(2024, 4, 15),
                dt.date(2024, 5, 20),
                dt.date(2024, 6, 25),
                dt.date(2024, 7, 30),
            ],
            permno_column: kypermno_values,
        }
    ).write_parquet(path)
    return kypermno_values


