def test_doc_ownership_date_window_helpers_use_real_rust_extension_when_built() -> None:
    if not doc_ownership.get_doc_ownership_rust_accel_metrics()["rust_accel_available"]:
        pytest.skip("LM2011 Rust extension is not built in this environment")
    doc_ownership.reset_doc_ownership_rust_accel_metrics()

    assert doc_ownership._target_effective_date_for_quarter_end(dt.date(2023, 12, 31)) == dt.date(2024, 1, 1)
    assert doc_ownership._target_effective_date_for_quarter_end(dt.date(2024, 2, 29)) == dt.date(2024, 3, 1)
    assert doc_ownership._clip_date_lower(dt.date(2024, 1, 1), dt.date(2024, 1, 15)) == dt.date(2024, 1, 15)
    assert doc_ownership._clip_date_lower(dt.date(2024, 2, 1), dt.date(2024, 1, 15)) == dt.date(2024, 2, 1)
    assert doc_ownership._clip_date_lower(None, dt.date(2024, 1, 15)) is None
    assert doc_ownership._clip_date_upper(dt.date(2024, 2, 1), dt.date(2024, 1, 31)) == dt.date(2024, 1, 31)
    assert doc_ownership._clip_date_upper(dt.date(2024, 1, 1), dt.date(2024, 1, 31)) == dt.date(2024, 1, 1)
    assert doc_ownership._clip_date_upper(dt.date(2024, 1, 1), None) == dt.date(2024, 1, 1)

    metrics = doc_ownership.get_doc_ownership_rust_accel_metrics()
    assert metrics["target_effective_date_fast_success"] == 2
    assert metrics["target_effective_date_fallbacks"] == 0
    assert metrics["date_clip_fast_success"] == 6
    assert metrics["date_clip_fallbacks"] == 0


