def test_doc_ownership_request_builder_uses_request_rows() -> None:
    doc_ownership.reset_doc_ownership_rust_accel_metrics()
    doc_rows, decision_rows, exception_rows = _doc_ownership_request_row_inputs()

    out = doc_ownership.build_refinitiv_lm2011_doc_ownership_requests(
        pl.DataFrame(doc_rows),
        pl.DataFrame(decision_rows),
        pl.DataFrame(exception_rows),
        request_min_date=dt.date(2024, 4, 1),
        request_max_date=dt.date(2024, 8, 1),
    )

    assert out.columns == list(doc_ownership.DOC_OWNERSHIP_REQUEST_COLUMNS)
    assert out.height == len(doc_rows)
    assert out.filter(pl.col("doc_id") == "doc_exception").select("retrieval_eligible").item() is True
    metrics = doc_ownership.get_doc_ownership_rust_accel_metrics()
    if metrics["rust_accel_available"]:
        assert metrics["request_row_build_column_fast_success"] == 1
        assert metrics["request_row_build_fast_success"] == 0
        assert metrics["request_row_build_column_fallbacks"] == 0
        assert metrics["request_row_build_fallbacks"] == 0


def test_doc_ownership_request_builder_falls_back_to_row_rust_bridge(monkeypatch) -> None:
    class FakeRust:
        def doc_ownership_request_rows_columns(self, *_args):
            raise RuntimeError("column bridge unavailable")

        def doc_ownership_request_rows(
            self,
            doc_rows,
            decision_rows,
            exception_rows,
            request_min_date,
            request_max_date,
            _fallback_days,
        ):
            return doc_ownership._build_doc_ownership_request_rows_py(
                doc_rows,
                decision_rows,
                exception_rows,
                request_min_date=request_min_date,
                request_max_date=request_max_date,
            )

    monkeypatch.setattr(doc_ownership, "_lm2011_rust", FakeRust())
    doc_ownership.reset_doc_ownership_rust_accel_metrics()
    doc_rows, decision_rows, exception_rows = _doc_ownership_request_row_inputs()

    out = doc_ownership.build_refinitiv_lm2011_doc_ownership_requests(
        pl.DataFrame(doc_rows),
        pl.DataFrame(decision_rows),
        pl.DataFrame(exception_rows),
        request_min_date=dt.date(2024, 4, 1),
        request_max_date=dt.date(2024, 8, 1),
    )
    expected = doc_ownership._build_explicit_schema_df(
        doc_ownership._build_doc_ownership_request_rows_py(
            doc_rows,
            decision_rows,
            exception_rows,
            request_min_date=dt.date(2024, 4, 1),
            request_max_date=dt.date(2024, 8, 1),
        ),
        doc_ownership._doc_ownership_request_schema(),
    ).select(doc_ownership.DOC_OWNERSHIP_REQUEST_COLUMNS)

    assert out.equals(expected)
    metrics = doc_ownership.get_doc_ownership_rust_accel_metrics()
    assert metrics["request_row_build_column_fast_failures"] == 1
    assert metrics["request_row_build_column_fallbacks"] == 1
