def test_doc_ownership_universe_diagnostics_membership_prep_uses_batch_normalizers() -> None:
    if not doc_ownership.get_doc_ownership_rust_accel_metrics()["rust_accel_available"]:
        pytest.skip("LM2011 Rust extension is not built in this environment")
    doc_ownership.reset_doc_ownership_rust_accel_metrics()
    backbone_df = pl.DataFrame(
        {
            "doc_id": [" doc_a ", "doc_b"],
            "cik_10": [" 0000000001 ", "0000000002"],
            "filing_date": [dt.date(2024, 4, 15), dt.date(2024, 5, 20)],
            "normalized_form": [" 10-K ", "10-K"],
            "KYPERMNO": [100.0, 200.0],
        }
    )
    request_df = pl.DataFrame(
        {
            "doc_id": ["doc_a", " doc_b "],
            "filing_date": [dt.date(2024, 4, 15), dt.date(2024, 5, 20)],
            "kypermno": [" 100 ", "200"],
            "retrieval_eligible": [True, False],
            "retrieval_exclusion_reason": [None, " excluded "],
        }
    )
    final_df = pl.DataFrame(
        {
            "doc_id": ["doc_a", "doc_b"],
            "filing_date": [dt.date(2024, 4, 15), dt.date(2024, 5, 20)],
            "KYPERMNO": [100, 200],
            "retrieval_status": [" EXACT_TARGET_HIT ", "NO_RESPONSE"],
            "institutional_ownership_pct": [61.0, None],
        }
    )

    tables, summary = doc_ownership._build_lm2011_doc_ownership_universe_diagnostics(
        backbone_df,
        request_df,
        final_df,
    )

    assert summary["all_doc_sets_equal"] is True
    rows = {row["doc_id"]: row for row in tables["detail"].to_dicts()}
    assert rows["doc_a"]["KYPERMNO"] == "100"
    assert rows["doc_b"]["request_retrieval_exclusion_reason"] == "excluded"
    assert rows["doc_a"]["final_retrieval_status"] == "EXACT_TARGET_HIT"
    metrics = doc_ownership.get_doc_ownership_rust_accel_metrics()
    assert metrics["lookup_text_batch_fast_success"] >= 1
    assert metrics["kypermno_batch_fast_success"] >= 1
    assert metrics["universe_summary_column_fast_success"] == 1
    assert metrics["universe_summary_fast_success"] == 0


