def _doc_ownership_rows_from_columns(column_names: list[str], column_values: list[list[object]]) -> list[dict[str, object]]:
    return [dict(zip(column_names, row_values)) for row_values in zip(*column_values)]


def _doc_ownership_selected_row_tuples(
    source_rows: list[dict[str, object]],
    selected: dict[str, dict[str, object]],
    conflicts: set[str],
) -> tuple[list[tuple[str, int, float]], list[str]]:
    selected_rows: list[tuple[str, int, float]] = []
    for doc_id, selected_row in selected.items():
        for row_index, source_row in enumerate(source_rows):
            if (
                doc_ownership._normalize_lookup_text(source_row.get("doc_id")) == doc_id
                and source_row.get("response_date") == selected_row.get("response_date")
                and source_row.get("returned_value") == selected_row.get("returned_value")
            ):
                selected_rows.append((doc_id, row_index, float(selected_row["_cleaned_value"])))
                break
    conflict_rows: list[str] = []
    for source_row in source_rows:
        doc_id = doc_ownership._normalize_lookup_text(source_row.get("doc_id"))
        if doc_id in conflicts and doc_id not in conflict_rows:
            conflict_rows.append(doc_id)
    return selected_rows, conflict_rows


def _doc_ownership_exact_row_bridge(
    rows: list[dict[str, object]],
) -> tuple[list[tuple[str, int, float]], list[str]]:
    selected, conflicts = doc_ownership._select_exact_hits_py(pl.DataFrame(rows))
    return _doc_ownership_selected_row_tuples(rows, selected, conflicts)


