def test_doc_ownership_fallback_request_selection_falls_back_to_row_rust_bridge(monkeypatch) -> None:
    class FakeRust:
        def doc_ownership_select_exact_hit_columns(self, column_names, column_values):
            return _doc_ownership_exact_row_bridge(
                _doc_ownership_rows_from_columns(column_names, column_values)
            )

        def doc_ownership_fallback_request_row_indices_columns(self, *_args):
            raise RuntimeError("column bridge unavailable")

        def doc_ownership_fallback_request_row_indices(self, request_rows, selected_doc_ids, conflict_doc_ids):
            excluded = {
                normalized
                for value in [*selected_doc_ids, *conflict_doc_ids]
                if (normalized := doc_ownership._normalize_lookup_text(value)) is not None
            }
            out: list[int] = []
            for row_index, row in enumerate(request_rows):
                doc_id = doc_ownership._normalize_lookup_text(row.get("doc_id"))
                if doc_id is None or not bool(row.get("retrieval_eligible")) or doc_id in excluded:
                    continue
                out.append(row_index)
            return out

    monkeypatch.setattr(doc_ownership, "_lm2011_rust", FakeRust())
    doc_ownership.reset_doc_ownership_rust_accel_metrics()

    assert doc_ownership._build_fallback_request_df(
        _doc_ownership_fallback_request_selection_frame(),
        _doc_ownership_exact_selection_frame(),
    ).equals(
        doc_ownership._build_fallback_request_df_py(
            _doc_ownership_fallback_request_selection_frame(),
            _doc_ownership_exact_selection_frame(),
        )
    )
    metrics = doc_ownership.get_doc_ownership_rust_accel_metrics()
    assert metrics["fallback_request_selection_column_fast_failures"] == 1
    assert metrics["fallback_request_selection_column_fallbacks"] == 1
    assert metrics["fallback_request_selection_fast_success"] == 1
    assert metrics["fallback_request_selection_fallbacks"] == 0


