def test_doc_ownership_final_rows_use_real_rust_extension_when_built() -> None:
    if not doc_ownership.get_doc_ownership_rust_accel_metrics()["rust_accel_available"]:
        pytest.skip("LM2011 Rust extension is not built in this environment")
    doc_ownership.reset_doc_ownership_rust_accel_metrics()

    rows = doc_ownership._doc_ownership_final_rows(*_doc_ownership_final_row_inputs())

    assert rows == doc_ownership._doc_ownership_final_rows_py(*_doc_ownership_final_row_inputs())
    status_by_doc = {row["doc_id"]: row["retrieval_status"] for row in rows}
    assert status_by_doc == {
        "doc_exact": "EXACT_TARGET_HIT",
        "doc_fallback": "FALLBACK_WINDOW_HIT",
        "doc_conflict": "FALLBACK_CONFLICT_REVIEW",
        "doc_review": "AUTHORITY_REVIEW_REQUIRED",
        "doc_no_ric": "NO_AUTHORITATIVE_RIC",
        "doc_no_hit": "NO_USABLE_INSTITUTIONAL_ROW",
    }
    exact_row = next(row for row in rows if row["doc_id"] == "doc_exact")
    assert exact_row["selected_response_date"] == dt.date(2024, 4, 1)
    assert exact_row["returned_category"] == "Holdings by Institutions"
    assert exact_row["institutional_ownership_pct"] == 100.0
    assert exact_row["KYPERMNO"] == "100"
    assert not exact_row["fallback_used"]
    fallback_row = next(row for row in rows if row["doc_id"] == "doc_fallback")
    assert fallback_row["institutional_ownership_pct"] == 25.5
    assert fallback_row["fallback_used"]

    metrics = doc_ownership.get_doc_ownership_rust_accel_metrics()
    assert metrics["final_row_build_fast_success"] == 1
    assert metrics["final_row_build_fallbacks"] == 0


