def _write_lseg_request_log(path: Path, lines: list[str]) -> None:
    path.write_text("\n".join(lines) + "\n", encoding="utf-8")


def test_lseg_ownership_request_log_event_count_uses_real_rust_extension_when_built(tmp_path) -> None:
    if not lseg_ownership_api.get_lseg_ownership_rust_accel_metrics()["rust_accel_available"]:
        pytest.skip("LM2011 Rust extension is not built in this environment")
    lseg_ownership_api.reset_lseg_ownership_rust_accel_metrics()
    request_log_path = tmp_path / "requests.jsonl"
    _write_lseg_request_log(
        request_log_path,
        [
            json.dumps({"event": "request_succeeded", "batch_id": "batch-1"}),
            "",
            json.dumps({"event": "request_failed", "payload": {"event": "request_succeeded"}}),
            '{"event":"request_failed","event":"request_succeeded"}',
            json.dumps({"message": "no event"}),
        ],
    )

    assert lseg_ownership_api._count_request_log_events(request_log_path, "request_succeeded") == (
        lseg_ownership_api._count_request_log_events_py(request_log_path, "request_succeeded")
    )
    assert lseg_ownership_api._count_request_log_events(request_log_path, "request_succeeded") == 2

    metrics = lseg_ownership_api.get_lseg_ownership_rust_accel_metrics()
    assert metrics["request_log_event_count_fast_success"] == 2
    assert metrics["request_log_event_count_fast_failures"] == 0
    assert metrics["request_log_event_count_fallbacks"] == 0


def test_lseg_ownership_request_log_event_count_matches_python_fallback_for_sample_values(tmp_path) -> None:
    request_log_path = tmp_path / "requests.jsonl"
    _write_lseg_request_log(
        request_log_path,
        [
            json.dumps({"event": "request_succeeded", "batch_id": "batch-1"}),
            json.dumps({"event": "request_failed", "error": "temporary"}),
            json.dumps({"event": "request_succeeded", "message": "a|b"}),
            json.dumps({"event": None}),
            json.dumps({"payload": {"event": "request_failed"}}),
        ],
    )

    for event_name in ["request_succeeded", "request_failed", "missing_event"]:
        assert lseg_ownership_api._count_request_log_events(request_log_path, event_name) == (
            lseg_ownership_api._count_request_log_events_py(request_log_path, event_name)
        )
    assert lseg_ownership_api._count_request_log_events(tmp_path / "missing.jsonl", "request_succeeded") == 0


