def test_lseg_ownership_item_builders_use_real_rust_extension_when_built() -> None:
    if not lseg_ownership_api.get_lseg_ownership_rust_accel_metrics()["rust_accel_available"]:
        pytest.skip("LM2011 Rust extension is not built in this environment")
    lseg_ownership_api.reset_lseg_ownership_rust_accel_metrics()

    universe_items = lseg_ownership_api._build_ownership_universe_items(_lseg_ownership_handoff_frame())
    exact_items = lseg_ownership_api._build_doc_ownership_exact_items(_lseg_doc_ownership_request_frame())
    fallback_items = lseg_ownership_api._build_doc_ownership_fallback_items(_lseg_doc_ownership_request_frame())

    assert [(item.instrument, item.batch_key, item.parameters["SDate"], item.parameters["EDate"]) for item in universe_items] == [
        ("AAA.N", "2024-02-01|2024-02-29", "2024-02-01", "2024-02-29")
    ]
    assert [(item.instrument, item.batch_key, item.parameters["SDate"], item.parameters["EDate"]) for item in exact_items] == [
        ("AAA.N", "2024-04-01", "2024-04-01", "2024-04-01")
    ]
    assert [(item.instrument, item.batch_key, item.parameters["SDate"], item.parameters["EDate"]) for item in fallback_items] == [
        ("AAA.N", "2024-04-01|2024-04-30", "2024-04-01", "2024-04-30")
    ]

    metrics = lseg_ownership_api.get_lseg_ownership_rust_accel_metrics()
    assert metrics["ownership_universe_items_column_fast_success"] == 1
    assert metrics["ownership_universe_items_fast_success"] == 0
    assert metrics["doc_exact_items_column_fast_success"] == 1
    assert metrics["doc_exact_items_fast_success"] == 0
    assert metrics["doc_fallback_items_column_fast_success"] == 1
    assert metrics["doc_fallback_items_fast_success"] == 0
    assert metrics["ownership_universe_items_column_fallbacks"] == 0
    assert metrics["doc_exact_items_column_fallbacks"] == 0
    assert metrics["doc_fallback_items_column_fallbacks"] == 0
    assert metrics["ownership_universe_items_fallbacks"] == 0
    assert metrics["doc_exact_items_fallbacks"] == 0
    assert metrics["doc_fallback_items_fallbacks"] == 0


