    assert metrics["ownership_universe_items_column_fast_failures"] == 1
    assert metrics["ownership_universe_items_column_fallbacks"] == 1
    assert metrics["ownership_universe_items_fast_success"] == 1
    assert metrics["ownership_universe_items_fallbacks"] == 0


