def test_lseg_ownership_universe_response_falls_back_to_row_rust_bridge(monkeypatch) -> None:
    universe_items = lseg_ownership_api._build_ownership_universe_items_py(_lseg_ownership_handoff_frame())

    class FakeRust:
        def normalize_ownership_universe_batch_response_columns(self, *_args):
            raise RuntimeError("column bridge unavailable")

        def normalize_ownership_universe_batch_response_rows_value(self, item_rows, response_rows):
            result = lseg_ownership_api._normalize_ownership_universe_batch_response_py(
                universe_items,
                pl.DataFrame(list(response_rows)),
            )
            item_index_by_id = {item.item_id: item_index for item_index, item in enumerate(universe_items)}
            return [
                (
                    item_index_by_id[row["item_id"]],
                    row["returned_ric"],
                    row["returned_date"],
                    row["returned_category"],
                    row["returned_value"],
                )
                for row in result.to_dicts()
            ]

        def lseg_item_window_dates(self, start_text, end_text):
            return (dt.date.fromisoformat(str(start_text)), dt.date.fromisoformat(str(end_text)))

    monkeypatch.setattr(lseg_ownership_api, "_lm2011_rust", FakeRust())
    lseg_ownership_api.reset_lseg_ownership_rust_accel_metrics()

    assert lseg_ownership_api._normalize_ownership_universe_batch_response(
        universe_items,
        _lseg_ownership_response_frame(),
    ).equals(
        lseg_ownership_api._normalize_ownership_universe_batch_response_py(
            universe_items,
            _lseg_ownership_response_frame(),
        )
    )

    metrics = lseg_ownership_api.get_lseg_ownership_rust_accel_metrics()
    assert metrics["ownership_universe_response_column_fast_failures"] == 1
    assert metrics["ownership_universe_response_column_fallbacks"] == 1
    assert metrics["ownership_universe_response_fast_success"] == 1
    assert metrics["ownership_universe_response_fallbacks"] == 0


def test_lseg_doc_ownership_response_falls_back_to_row_rust_bridge(monkeypatch) -> None:
    exact_items = lseg_ownership_api._build_doc_ownership_exact_items_py(_lseg_doc_ownership_request_frame())
    fallback_items = lseg_ownership_api._build_doc_ownership_fallback_items_py(_lseg_doc_ownership_request_frame())

    class FakeRust:
        def __init__(self) -> None:
            self.row_bridge_calls = 0

        def normalize_doc_ownership_batch_response_columns(self, *_args):
            raise RuntimeError("column bridge unavailable")

        def normalize_doc_ownership_batch_response_rows_value(self, item_rows, response_rows):
            self.row_bridge_calls += 1
            if self.row_bridge_calls == 1:
                items = exact_items
                result = lseg_ownership_api._normalize_doc_exact_batch_response_py(
                    exact_items,
                    pl.DataFrame(list(response_rows)),
                )
            else:
                items = fallback_items
                result = lseg_ownership_api._normalize_doc_fallback_batch_response_py(
                    fallback_items,
                    pl.DataFrame(list(response_rows)),
                )
            item_index_by_id = {item.item_id: item_index for item_index, item in enumerate(items)}
            return [
                (
                    item_index_by_id[row["item_id"]],
                    row["response_date"],
                    row["returned_category"],
                    row["returned_value"],
                    row["is_institutional_category"],
                )
                for row in result.to_dicts()
            ]

    monkeypatch.setattr(lseg_ownership_api, "_lm2011_rust", FakeRust())
    lseg_ownership_api.reset_lseg_ownership_rust_accel_metrics()

    assert lseg_ownership_api._normalize_doc_exact_batch_response(
        exact_items,
        _lseg_ownership_response_frame(),
    ).equals(
        lseg_ownership_api._normalize_doc_exact_batch_response_py(
            exact_items,
            _lseg_ownership_response_frame(),
        )
    )
    assert lseg_ownership_api._normalize_doc_fallback_batch_response(
        fallback_items,
        _lseg_ownership_response_frame(),
    ).equals(
        lseg_ownership_api._normalize_doc_fallback_batch_response_py(
            fallback_items,
            _lseg_ownership_response_frame(),
        )
    )

    metrics = lseg_ownership_api.get_lseg_ownership_rust_accel_metrics()
    assert metrics["doc_exact_response_column_fast_failures"] == 1
    assert metrics["doc_exact_response_column_fallbacks"] == 1
    assert metrics["doc_exact_response_fast_success"] == 1
    assert metrics["doc_exact_response_fallbacks"] == 0
    assert metrics["doc_fallback_response_column_fast_failures"] == 1
    assert metrics["doc_fallback_response_column_fallbacks"] == 1
    assert metrics["doc_fallback_response_fast_success"] == 1
    assert metrics["doc_fallback_response_fallbacks"] == 0


