def test_refinitiv_authority_scalar_helpers_use_real_rust_extension_when_built() -> None:
    if not refinitiv_authority.get_refinitiv_authority_rust_accel_metrics()["rust_accel_available"]:
        pytest.skip("LM2011 Rust extension is not built in this environment")
    refinitiv_authority.reset_refinitiv_authority_rust_accel_metrics()

    assert refinitiv_authority._date_span_days(dt.date(2024, 1, 1), dt.date(2024, 1, 3)) == 3
    assert refinitiv_authority._date_span_days(dt.date(2024, 1, 3), dt.date(2024, 1, 1)) == 0
    assert refinitiv_authority._values_match(1.0, 1.0 + 5e-7)
    assert not refinitiv_authority._values_match(1.0, 1.0 + 2e-6)
    assert refinitiv_authority._distinct_values({None, 3.0, 1.0, 2.0}) == [1.0, 2.0, 3.0]
    assert refinitiv_authority._candidate_key({"KYPERMNO": " 10001 ", "candidate_ric": " AAA.N "}) == (
        "10001",
        "AAA.N",
    )
    assert refinitiv_authority._source_family_from_flags(True, True) == "MIXED"
    assert refinitiv_authority._source_family_from_flags(True, False) == "CONVENTIONAL"
    assert refinitiv_authority._source_family_from_flags(False, True) == "TICKER"
    assert refinitiv_authority._component_id("10001", 3) == "10001|COMPONENT|03"
    assert refinitiv_authority._component_id("10001", 12) == "10001|COMPONENT|12"

    metrics = refinitiv_authority.get_refinitiv_authority_rust_accel_metrics()
    assert metrics["date_span_fast_success"] == 2
    assert metrics["values_match_fast_success"] == 2
    assert metrics["distinct_values_fast_success"] == 1
    assert metrics["candidate_key_fast_success"] == 1
    assert metrics["source_family_fast_success"] == 3
    assert metrics["component_id_fast_success"] == 2
    assert metrics["date_span_fallbacks"] == 0


def test_refinitiv_authority_scalar_helpers_match_python_fallback_for_sample_values() -> None:
    date_spans = [
        (None, None),
        (None, dt.date(2024, 1, 1)),
        (dt.date(2024, 1, 1), None),
        (dt.date(2024, 1, 1), dt.date(2024, 1, 1)),
        (dt.date(2024, 1, 1), dt.date(2024, 1, 3)),
        (dt.date(2024, 1, 3), dt.date(2024, 1, 1)),
    ]
    for start_date, end_date in date_spans:
        assert refinitiv_authority._date_span_days(start_date, end_date) == (
            refinitiv_authority._date_span_days_py(start_date, end_date)
        )

    value_pairs = [
        (None, None),
        (None, 1.0),
        (1.0, None),
        (1.0, 1.0),
        (1.0, 1.0 + 5e-7),
        (1.0, 1.0 + 2e-6),
    ]
    for left, right in value_pairs:
        assert refinitiv_authority._values_match(left, right) == refinitiv_authority._values_match_py(left, right)

    for values in [set(), {None}, {None, 2.0, 1.0, -1.0}, {1, 1.5, None}]:
        assert refinitiv_authority._distinct_values(values) == refinitiv_authority._distinct_values_py(values)

    for record in [
        {},
        {"KYPERMNO": None, "candidate_ric": " AAA.N "},
        {"KYPERMNO": " 10001 ", "candidate_ric": ""},
        {"KYPERMNO": 10001, "candidate_ric": " AAA.N "},
    ]:
        assert refinitiv_authority._candidate_key(record) == refinitiv_authority._candidate_key_py(record)

    for conventional, ticker in [(False, False), (False, True), (True, False), (True, True)]:
        assert refinitiv_authority._source_family_from_flags(conventional, ticker) == (
            refinitiv_authority._source_family_from_flags_py(conventional, ticker)
        )

    for kypermno, index in [("10001", 0), ("10001", 3), ("10001", 12), ("ABC", -1)]:
        assert refinitiv_authority._component_id(kypermno, index) == (
            refinitiv_authority._component_id_py(kypermno, index)
        )


