def _assert_candidate_metric_outputs_equal(
    left: tuple[
        pl.DataFrame,
        dict[tuple[str, str], dict[str, object]],
        dict[str, set[dt.date]],
        dict[str, set[tuple[dt.date, str, float | None]]],
    ],
    right: tuple[
        pl.DataFrame,
        dict[tuple[str, str], dict[str, object]],
        dict[str, set[dt.date]],
        dict[str, set[tuple[dt.date, str, float | None]]],
    ],
) -> None:
    def normalized_meta(
        meta: dict[tuple[str, str], dict[str, object]],
    ) -> dict[tuple[str, str], dict[str, object]]:
        out: dict[tuple[str, str], dict[str, object]] = {}
        for key, value in meta.items():
            row = dict(value)
            row.pop("request_rows", None)
            row.pop("result_rows", None)
            out[key] = row
        return out

    assert left[0].to_dicts() == right[0].to_dicts()
    assert normalized_meta(left[1]) == normalized_meta(right[1])
    assert dict(left[2]) == dict(right[2])
    assert dict(left[3]) == dict(right[3])


