def _authority_candidate_metric_raw_records_from_python(
    row_summary_records: list[dict[str, object]],
    results_records: list[dict[str, object]],
) -> list[dict[str, object]]:
    df, candidate_meta, _permno_date_sets, _permno_row_sets = refinitiv_authority._build_candidate_metrics_py(
        row_summary_records,
        results_records,
    )
    raw_records: list[dict[str, object]] = []
    for row in df.to_dicts():
        key = (str(row["KYPERMNO"]), str(row["candidate_ric"]))
        meta = candidate_meta[key]
        raw_records.append(
            {
                **{name: row.get(name) for name in refinitiv_authority.CANDIDATE_METRIC_COLUMNS},
                "role_set": list(meta["role_set"]),
                "request_rows": list(meta["request_rows"]),
                "result_rows": list(meta["result_rows"]),
                "observation_value_sets": [
                    (date_value, category, list(values))
                    for (date_value, category), values in meta["observation_value_sets"].items()
                ],
                "unique_row_set": list(meta["unique_row_set"]),
            }
        )
    return raw_records


