def _authority_alias_observations(
    dates: list[dt.date],
    categories: list[str],
    *,
    offset: float = 0.0,
) -> dict[tuple[dt.date, str], set[float | None]]:
    return {
        (date_value, category): {float((date_index + 1) * 100 + category_index) + offset}
        for date_index, date_value in enumerate(dates)
        for category_index, category in enumerate(categories)
    }


def _authority_alias_candidate(
    *,
    source_family: str,
    conventional: bool,
    effective: bool,
    observations: dict[tuple[dt.date, str], set[float | None]],
    bridge_start: dt.date,
    bridge_end: dt.date,
    internal_conflicts: int = 0,
) -> dict[str, object]:
    ownership_dates = [date_value for date_value, _ in observations]
    return {
        "candidate_source_family": source_family,
        "candidate_has_conventional_support": conventional,
        "candidate_has_effective_support": effective,
        "candidate_first_ownership_date": min(ownership_dates) if ownership_dates else None,
        "candidate_last_ownership_date": max(ownership_dates) if ownership_dates else None,
        "candidate_bridge_start_date": bridge_start,
        "candidate_bridge_end_date": bridge_end,
        "candidate_internal_same_date_same_category_differing_value_count": internal_conflicts,
        "observation_value_sets": observations,
    }


def _authority_alias_candidate_meta() -> tuple[list[str], dict[tuple[str, str], dict[str, object]]]:
    overlap_dates = [dt.date(2024, 1, 31), dt.date(2024, 2, 29), dt.date(2024, 3, 31)]
    categories = ["Institutional", "Fund", "Retail", "Strategic"]
    old_dates = [dt.date(2023, 1, 31), dt.date(2023, 2, 28), dt.date(2023, 3, 31)]
    new_dates = [dt.date(2024, 7, 31), dt.date(2024, 8, 31), dt.date(2024, 9, 30)]
    return [
        "10001",
        "20001",
    ], {
        ("10001", "AAA.N"): _authority_alias_candidate(
            source_family="CONVENTIONAL",
            conventional=True,
            effective=True,
            observations=_authority_alias_observations(overlap_dates, categories),
            bridge_start=dt.date(2024, 1, 1),
            bridge_end=dt.date(2024, 3, 31),
        ),
        ("10001", "AAB.N"): _authority_alias_candidate(
            source_family="CONVENTIONAL",
            conventional=True,
            effective=False,
            observations=_authority_alias_observations(overlap_dates, categories),
            bridge_start=dt.date(2024, 1, 1),
            bridge_end=dt.date(2024, 3, 31),
        ),
        ("10001", "AAC.N"): _authority_alias_candidate(
            source_family="TICKER",
            conventional=False,
            effective=False,
            observations=_authority_alias_observations(overlap_dates, categories, offset=12.0),
            bridge_start=dt.date(2024, 1, 1),
            bridge_end=dt.date(2024, 3, 31),
        ),
        ("20001", "NEW.N"): _authority_alias_candidate(
            source_family="CONVENTIONAL",
            conventional=True,
            effective=True,
            observations=_authority_alias_observations(new_dates, categories),
            bridge_start=dt.date(2024, 7, 1),
            bridge_end=dt.date(2024, 9, 30),
        ),
        ("20001", "OLD.N"): _authority_alias_candidate(
            source_family="CONVENTIONAL",
            conventional=True,
            effective=True,
            observations=_authority_alias_observations(old_dates, categories),
            bridge_start=dt.date(2023, 1, 1),
            bridge_end=dt.date(2023, 3, 31),
        ),
    }


