def _authority_component_candidate(
    *,
    conventional: bool,
    effective: bool,
    observations: dict[tuple[dt.date, str], set[float | None]],
    bridge_start: dt.date | None,
    bridge_end: dt.date | None,
) -> dict[str, object]:
    ownership_dates = {date_value for date_value, _ in observations}
    unique_row_set = {
        (date_value, category, value)
        for (date_value, category), values in observations.items()
        for value in values
    }
    bridge_span = (
        (bridge_end - bridge_start).days + 1
        if isinstance(bridge_start, dt.date) and isinstance(bridge_end, dt.date) and bridge_end >= bridge_start
        else 0
    )
    return {
        "candidate_has_conventional_support": conventional,
        "candidate_has_effective_support": effective,
        "candidate_ownership_date_count": len(ownership_dates),
        "candidate_bridge_span_day_count": bridge_span,
        "candidate_bridge_start_date": bridge_start,
        "candidate_bridge_end_date": bridge_end,
        "observation_value_sets": observations,
        "unique_row_set": unique_row_set,
    }


def _authority_component_inputs() -> tuple[
    list[str],
    dict[tuple[str, str], dict[str, object]],
    dict[tuple[str, str, str], dict[str, object]],
]:
    shared_observations = {
        (dt.date(2024, 1, 31), "Institutional"): {10.0},
        (dt.date(2024, 2, 29), "Institutional"): {11.0},
        (dt.date(2024, 3, 31), "Fund"): {None},
    }
    candidate_meta = {
        ("10001", "AAA.N"): _authority_component_candidate(
            conventional=True,
            effective=True,
            observations=shared_observations,
            bridge_start=dt.date(2024, 1, 1),
            bridge_end=dt.date(2024, 3, 31),
        ),
        ("10001", "AAB.N"): _authority_component_candidate(
            conventional=True,
            effective=False,
            observations={
                (dt.date(2024, 1, 31), "Institutional"): {10.0},
                (dt.date(2024, 2, 29), "Institutional"): {11.0},
                (dt.date(2024, 4, 30), "Fund"): {12.0},
            },
            bridge_start=dt.date(2024, 3, 1),
            bridge_end=dt.date(2024, 4, 30),
        ),
        ("10001", "TICK.N"): _authority_component_candidate(
            conventional=False,
            effective=False,
            observations={(dt.date(2024, 5, 31), "Institutional"): {99.0}},
            bridge_start=dt.date(2024, 5, 1),
            bridge_end=dt.date(2024, 5, 31),
        ),
        ("10001", "REVIEW.N"): _authority_component_candidate(
            conventional=True,
            effective=False,
            observations={(dt.date(2024, 6, 30), "Institutional"): {20.0, 21.0}},
            bridge_start=dt.date(2024, 6, 1),
            bridge_end=dt.date(2024, 6, 30),
        ),
        ("20001", "OLD.N"): _authority_component_candidate(
            conventional=True,
            effective=True,
            observations={(dt.date(2023, 1, 31), "Institutional"): {30.0}},
            bridge_start=dt.date(2023, 1, 1),
            bridge_end=dt.date(2023, 1, 31),
        ),
        ("20001", "NEW.N"): _authority_component_candidate(
            conventional=True,
            effective=True,
            observations={(dt.date(2024, 1, 31), "Institutional"): {31.0}},
            bridge_start=dt.date(2024, 1, 1),
            bridge_end=dt.date(2024, 1, 31),
        ),
    }
    benign_pair = {
        "pair_benign_alias_supported": True,
        "pair_value_conflict_present": False,
        "pair_regime_split_supported": False,
        "pair_requires_review": False,
    }
    regime_pair = {
        "pair_benign_alias_supported": False,
        "pair_value_conflict_present": False,
        "pair_regime_split_supported": True,
        "pair_requires_review": False,
    }
    pair_meta = {
        ("10001", "AAA.N", "AAB.N"): benign_pair,
        ("10001", "AAB.N", "AAA.N"): benign_pair,
        ("20001", "OLD.N", "NEW.N"): regime_pair,
        ("20001", "NEW.N", "OLD.N"): regime_pair,
    }
    for (kypermno, candidate_ric), meta in candidate_meta.items():
        meta["KYPERMNO"] = kypermno
        meta["candidate_ric"] = candidate_ric
    return ["10001", "20001", "30001"], candidate_meta, pair_meta


def _canonical_component_outputs(
    result: tuple[dict[str, dict[str, str]], dict[str, dict[str, dict[str, object]]]],
) -> tuple[dict[str, dict[str, str]], dict[str, dict[str, dict[str, object]]]]:
    component_map_by_permno, component_meta_by_permno = result
    canonical_meta: dict[str, dict[str, dict[str, object]]] = {}
    for kypermno, components in component_meta_by_permno.items():
        canonical_meta[kypermno] = {}
        for component_id, component in components.items():
            union_value_sets = tuple(
                sorted(
                    (
                        date_value,
                        category,
                        tuple(sorted(values, key=lambda value: (value is not None, value))),
                    )
                    for (date_value, category), values in component["union_value_sets"].items()
                )
            )
            canonical_meta[kypermno][component_id] = {
                "component_id": component["component_id"],
                "member_rics": tuple(component["member_rics"]),
                "canonical_ric": component["canonical_ric"],
                "canonical_best_candidate_date_count": component["canonical_best_candidate_date_count"],
                "ownership_date_count": component["ownership_date_count"],
                "ownership_row_count": component["ownership_row_count"],
                "bridge_start_date": component["bridge_start_date"],
                "bridge_end_date": component["bridge_end_date"],
                "first_ownership_date": component["first_ownership_date"],
                "last_ownership_date": component["last_ownership_date"],
                "merged_bridge_windows": tuple(component["merged_bridge_windows"]),
                "union_value_sets": union_value_sets,
                "component_requires_review": component["component_requires_review"],
                "coverage_share_of_best_candidate": component["coverage_share_of_best_candidate"],
            }
    return (
        {kypermno: dict(sorted(mapping.items())) for kypermno, mapping in component_map_by_permno.items()},
        {kypermno: dict(sorted(components.items())) for kypermno, components in canonical_meta.items()},
    )


def test_refinitiv_authority_conventional_components_use_real_rust_extension_when_built() -> None:
    if not refinitiv_authority.get_refinitiv_authority_rust_accel_metrics()["rust_accel_available"]:
        pytest.skip("LM2011 Rust extension is not built in this environment")
    refinitiv_authority.reset_refinitiv_authority_rust_accel_metrics()

    permno_order, candidate_meta, pair_meta = _authority_component_inputs()
    actual = refinitiv_authority._build_conventional_components(
        permno_order=permno_order,
        candidate_meta=candidate_meta,
        pair_meta=pair_meta,
    )
    expected = refinitiv_authority._build_conventional_components_py(
        permno_order=permno_order,
        candidate_meta=candidate_meta,
        pair_meta=pair_meta,
    )

    assert _canonical_component_outputs(actual) == _canonical_component_outputs(expected)
    component_map = actual[0]
    assert component_map["10001"]["AAA.N"] == component_map["10001"]["AAB.N"]
    assert "TICK.N" not in component_map["10001"]
    assert actual[1]["10001"]["10001|COMPONENT|02"]["component_requires_review"] is True
    assert actual[0]["30001"] == {}

    metrics = refinitiv_authority.get_refinitiv_authority_rust_accel_metrics()
    assert metrics["conventional_components_meta_fast_success"] == 1
    assert metrics["conventional_components_fast_success"] == 0
    assert metrics["conventional_components_meta_fallbacks"] == 0
    assert metrics["conventional_components_fallbacks"] == 0


