def _authority_component_raw_records_from_python(
    permno_order: list[str],
    candidate_meta: dict[tuple[str, str], dict[str, object]],
    pair_meta: dict[tuple[str, str, str], dict[str, object]],
) -> tuple[list[dict[str, object]], list[dict[str, object]]]:
    component_map_by_permno, component_meta_by_permno = refinitiv_authority._build_conventional_components_py(
        permno_order=permno_order,
        candidate_meta=candidate_meta,
        pair_meta=pair_meta,
    )
    map_records = [
        {"KYPERMNO": kypermno, "candidate_ric": candidate_ric, "component_id": component_id}
        for kypermno, component_map in component_map_by_permno.items()
        for candidate_ric, component_id in component_map.items()
    ]
    component_records: list[dict[str, object]] = []
    for kypermno, components in component_meta_by_permno.items():
        for component_id, component in components.items():
            component_records.append(
                {
                    "KYPERMNO": kypermno,
                    "component_id": component_id,
                    "member_rics": list(component["member_rics"]),
                    "canonical_ric": component["canonical_ric"],
                    "canonical_best_candidate_date_count": component["canonical_best_candidate_date_count"],
                    "ownership_date_count": component["ownership_date_count"],
                    "ownership_row_count": component["ownership_row_count"],
                    "bridge_start_date": component["bridge_start_date"],
                    "bridge_end_date": component["bridge_end_date"],
                    "first_ownership_date": component["first_ownership_date"],
                    "last_ownership_date": component["last_ownership_date"],
                    "merged_bridge_windows": list(component["merged_bridge_windows"]),
                    "union_value_sets": [
                        (date_value, category, list(values))
                        for (date_value, category), values in component["union_value_sets"].items()
                    ],
                    "component_requires_review": component["component_requires_review"],
                    "coverage_share_of_best_candidate": component["coverage_share_of_best_candidate"],
                }
            )
    return map_records, component_records


def test_refinitiv_authority_conventional_components_fall_back_to_row_rust_bridge(monkeypatch) -> None:
    permno_order, candidate_meta, pair_meta = _authority_component_inputs()

    class FakeRust:
        def refinitiv_authority_conventional_components_from_meta(self, *_args):
            raise RuntimeError("meta bridge unavailable")

        def refinitiv_authority_conventional_components(
            self,
            _permno_order,
            _candidate_records,
            _pair_records,
            _max_gap_days,
        ):
            return _authority_component_raw_records_from_python(permno_order, candidate_meta, pair_meta)

    monkeypatch.setattr(refinitiv_authority, "_lm2011_rust", FakeRust())
    refinitiv_authority.reset_refinitiv_authority_rust_accel_metrics()

    actual = refinitiv_authority._build_conventional_components(
        permno_order=permno_order,
        candidate_meta=candidate_meta,
        pair_meta=pair_meta,
    )
    expected = refinitiv_authority._build_conventional_components_py(
        permno_order=permno_order,
        candidate_meta=candidate_meta,
        pair_meta=pair_meta,
    )
    assert _canonical_component_outputs(actual) == _canonical_component_outputs(expected)

    metrics = refinitiv_authority.get_refinitiv_authority_rust_accel_metrics()
    assert metrics["conventional_components_meta_fast_failures"] == 1
    assert metrics["conventional_components_meta_fallbacks"] == 1
    assert metrics["conventional_components_fast_success"] == 1
    assert metrics["conventional_components_fallbacks"] == 0


