def _analyst_normalized_success_frames() -> tuple[pl.DataFrame, pl.DataFrame]:
    actuals = pl.DataFrame(
        {
            "item_id": ["actual-direct", "actual-derived"],
            "response_row_index": [0, 1],
            "request_group_id": ["group-a", "group-b"],
            "gvkey_int": [1000, 1001],
            "effective_collection_ric": ["AAA.N", "BBB.N"],
            "announcement_date": [dt.date(2024, 10, 5), dt.date(2023, 10, 15)],
            "fiscal_period_end": [dt.date(2024, 9, 30), None],
            "actual_eps": [2.5, 1.5],
            "raw_fperiod": ["FY2024Q4", None],
            "row_parse_status": ["OK", "OK"],
        }
    )
    estimates = pl.DataFrame(
        {
            "item_id": [
                "estimate-a-selected",
                "estimate-a-1m",
                "estimate-a-4m",
                "estimate-a-after",
                "estimate-b-selected",
                "estimate-b-4m",
                "estimate-b-mid",
            ],
            "response_row_index": list(range(7)),
            "request_group_id": ["group-a"] * 4 + ["group-b"] * 3,
            "request_period": ["FQ"] * 7,
            "gvkey_int": [1000, 1000, 1000, 1000, 1001, 1001, 1001],
            "effective_collection_ric": ["AAA.N"] * 4 + ["BBB.N"] * 3,
            "calc_date": [
                dt.date(2024, 9, 29),
                dt.date(2024, 8, 15),
                dt.date(2024, 5, 31),
                dt.date(2024, 10, 10),
                dt.date(2023, 10, 1),
                dt.date(2023, 6, 1),
                dt.date(2023, 9, 1),
            ],
            "fiscal_period_end": [
                dt.date(2024, 9, 30),
                dt.date(2024, 9, 30),
                dt.date(2024, 9, 30),
                dt.date(2024, 9, 30),
                dt.date(2023, 9, 30),
                dt.date(2023, 9, 30),
                dt.date(2023, 9, 30),
            ],
            "raw_fperiod": ["FY2024Q4"] * 4 + ["FY2023Q3"] * 3,
            "forecast_consensus_mean": [2.1, 1.9, 1.7, 2.3, 1.2, 1.0, 1.1],
            "forecast_dispersion": [0.25, 0.2, 0.15, 0.3, 0.2, 0.1, 0.15],
            "estimate_count": [8, 8, 8, 8, 10, 9, 9],
            "row_parse_status": ["OK"] * 7,
        }
    )
    return actuals, estimates


def _analyst_normalized_rejection_frames() -> tuple[pl.DataFrame, pl.DataFrame]:
    actuals = pl.DataFrame(
        {
            "item_id": [
                "actual-conflict-direct",
                "actual-conflict-derived",
                "actual-nonunique-derived",
            ],
            "response_row_index": [0, 1, 2],
            "request_group_id": ["group-c", "group-d", "group-e"],
            "gvkey_int": [2000, 2000, 2001],
            "effective_collection_ric": ["CCC.N", "CCC.N", "EEE.N"],
            "announcement_date": [dt.date(2024, 10, 1)] * 3,
            "fiscal_period_end": [dt.date(2024, 9, 30), None, None],
            "actual_eps": [1.0, 1.0, 2.0],
            "raw_fperiod": ["FY2024Q4", None, None],
            "row_parse_status": ["OK", "OK", "OK"],
        }
    )
    estimates = pl.DataFrame(
        {
            "item_id": [
                "estimate-c-selected",
                "estimate-c-base",
                "estimate-e-period-a",
                "estimate-e-period-b",
            ],
            "response_row_index": [0, 1, 2, 3],
            "request_group_id": ["group-c", "group-c", "group-e", "group-e"],
            "request_period": ["FQ"] * 4,
            "gvkey_int": [2000, 2000, 2001, 2001],
            "effective_collection_ric": ["CCC.N", "CCC.N", "EEE.N", "EEE.N"],
            "calc_date": [
                dt.date(2024, 9, 30),
                dt.date(2024, 5, 31),
                dt.date(2024, 9, 30),
                dt.date(2024, 9, 30),
            ],
            "fiscal_period_end": [
                dt.date(2024, 9, 30),
                dt.date(2024, 9, 30),
                dt.date(2024, 9, 30),
                dt.date(2024, 6, 30),
            ],
            "raw_fperiod": ["FY2024Q4", "FY2024Q4", "FY2024Q4", "FY2024Q3"],
            "forecast_consensus_mean": [0.8, 0.7, 1.8, 1.7],
            "forecast_dispersion": [0.1, 0.1, 0.2, 0.2],
            "estimate_count": [5, 5, 6, 6],
            "row_parse_status": ["OK"] * 4,
        }
    )
    return actuals, estimates


def _assert_analyst_normalized_outputs_equal(
    left: tuple[pl.DataFrame, pl.DataFrame],
    right: tuple[pl.DataFrame, pl.DataFrame],
) -> None:
    left_normalized, left_rejections = left
    right_normalized, right_rejections = right
    assert left_normalized.sort(["gvkey_int", "announcement_date", "fiscal_period_end"]).to_dicts() == (
        right_normalized.sort(["gvkey_int", "announcement_date", "fiscal_period_end"]).to_dicts()
    )
    assert left_rejections.sort(
        ["gvkey_int", "announcement_date", "rejection_status", "fiscal_period_end"]
    ).to_dicts() == right_rejections.sort(
        ["gvkey_int", "announcement_date", "rejection_status", "fiscal_period_end"]
    ).to_dicts()


def test_refinitiv_analyst_normalized_event_rows_use_real_rust_extension_when_built(monkeypatch) -> None:
    if not refinitiv_analyst.get_refinitiv_analyst_rust_accel_metrics()["rust_accel_available"]:
        pytest.skip("LM2011 Rust extension is not built in this environment")
    actuals, estimates = _analyst_normalized_success_frames()

    refinitiv_analyst.reset_refinitiv_analyst_rust_accel_metrics()
    rust_outputs = refinitiv_analyst.build_refinitiv_analyst_normalized_outputs(actuals, estimates)
    metrics = refinitiv_analyst.get_refinitiv_analyst_rust_accel_metrics()
    assert metrics["normalized_event_rows_fast_success"] == 1
    assert metrics["normalized_event_rows_fallbacks"] == 0
    assert rust_outputs[0].height == 2
    assert rust_outputs[1].height == 0

    monkeypatch.setattr(refinitiv_analyst, "_lm2011_rust", None)
    python_outputs = refinitiv_analyst.build_refinitiv_analyst_normalized_outputs(actuals, estimates)
    _assert_analyst_normalized_outputs_equal(rust_outputs, python_outputs)


def test_refinitiv_analyst_normalized_event_rows_match_python_fallback_for_rejection_cases(monkeypatch) -> None:
    actuals, estimates = _analyst_normalized_rejection_frames()

    rust_outputs = refinitiv_analyst.build_refinitiv_analyst_normalized_outputs(actuals, estimates)
    monkeypatch.setattr(refinitiv_analyst, "_lm2011_rust", None)
    python_outputs = refinitiv_analyst.build_refinitiv_analyst_normalized_outputs(actuals, estimates)

    _assert_analyst_normalized_outputs_equal(rust_outputs, python_outputs)
    rejection_statuses = set(rust_outputs[1].get_column("rejection_status").to_list())
    assert "CONFLICTING_NORMALIZED_EVENT" in rejection_statuses
    assert "NONUNIQUE_DERIVED_FISCAL_PERIOD_END" in rejection_statuses


