def _prepared_interval_item(
    item_id: str,
    *,
    instrument: str,
    start_date: dt.date,
    end_date: dt.date,
) -> lseg_batching._PreparedIntervalItem:
    request_item = lseg_batching.RequestItem(
        item_id=item_id,
        stage="ownership",
        instrument=instrument,
        batch_key=f"{start_date.isoformat()}|{end_date.isoformat()}",
        fields=("TR.InvestorSharesHeld",),
        parameters={"SDate": start_date.isoformat(), "EDate": end_date.isoformat()},
        payload={},
    )
    return lseg_batching._PreparedIntervalItem(
        request_item=request_item,
        signature="sig-ownership",
        start_date=start_date,
        end_date=end_date,
    )


def _assert_interval_candidate_decision_equal(
    actual: lseg_batching._CandidateDecision | None,
    expected: lseg_batching._CandidateDecision | None,
) -> None:
    if expected is None:
        assert actual is None
        return
    assert actual is not None
    assert actual.candidate == expected.candidate
    assert actual.delta_rows == pytest.approx(expected.delta_rows)
    assert actual.resulting_state.start_date == expected.resulting_state.start_date
    assert actual.resulting_state.end_date == expected.resulting_state.end_date
    assert actual.resulting_state.item_ids == expected.resulting_state.item_ids
    assert actual.resulting_state.unique_instruments == expected.resulting_state.unique_instruments
    assert actual.resulting_state.standalone_rows_estimate == pytest.approx(
        expected.resulting_state.standalone_rows_estimate
    )
    assert actual.resulting_state.batched_rows_estimate == pytest.approx(
        expected.resulting_state.batched_rows_estimate
    )
    assert actual.resulting_state.extra_rows_abs == pytest.approx(
        expected.resulting_state.extra_rows_abs
    )
    assert actual.resulting_state.extra_rows_ratio == pytest.approx(
        expected.resulting_state.extra_rows_ratio
    )
    assert actual.resulting_state.union_span_days == expected.resulting_state.union_span_days


def test_lseg_batching_evaluate_candidate_uses_real_rust_extension_when_built() -> None:
    if not lseg_batching.get_lseg_batching_rust_accel_metrics()["rust_accel_available"]:
        pytest.skip("LM2011 Rust extension is not built in this environment")
    base = _prepared_interval_item(
        "item-base",
        instrument="AAA.N",
        start_date=dt.date(2024, 1, 1),
        end_date=dt.date(2024, 1, 10),
    )
    accepted = _prepared_interval_item(
        "item-accepted",
        instrument="BBB.N",
        start_date=dt.date(2024, 1, 5),
        end_date=dt.date(2024, 1, 12),
    )
    rejected = _prepared_interval_item(
        "item-rejected",
        instrument="CCC.N",
        start_date=dt.date(2024, 1, 6),
        end_date=dt.date(2024, 1, 8),
    )
    state = lseg_batching._BatchState.from_items([base], row_density_rows_per_day=1.25)
    accepted_config = lseg_batching.IntervalBatchPlannerConfig(
        max_batch_size=2,
        max_batch_items=2,
        max_union_span_days=20,
        max_extra_rows_abs=10.0,
        max_extra_rows_ratio=1.0,
        row_density_rows_per_day=1.25,
    )
    rejected_config = lseg_batching.IntervalBatchPlannerConfig(
        max_batch_size=1,
        row_density_rows_per_day=1.25,
    )
    expected_accepted = lseg_batching._evaluate_candidate_py(
        accepted,
        batch_state=state,
        config=accepted_config,
    )
    expected_rejected = lseg_batching._evaluate_candidate_py(
        rejected,
        batch_state=state,
        config=rejected_config,
    )

    lseg_batching.reset_lseg_batching_rust_accel_metrics()
    _assert_interval_candidate_decision_equal(
        lseg_batching._evaluate_candidate(accepted, batch_state=state, config=accepted_config),
        expected_accepted,
    )
    _assert_interval_candidate_decision_equal(
        lseg_batching._evaluate_candidate(rejected, batch_state=state, config=rejected_config),
        expected_rejected,
    )
    metrics = lseg_batching.get_lseg_batching_rust_accel_metrics()
    assert metrics["evaluate_candidate_fast_success"] == 2
    assert metrics["evaluate_candidate_fallbacks"] == 0


