def test_lseg_provider_error_classifier_uses_real_rust_extension_when_built() -> None:
    if not lseg_provider.get_lseg_provider_rust_accel_metrics()["rust_accel_available"]:
        pytest.skip("LM2011 Rust extension is not built in this environment")
    lseg_provider.reset_lseg_provider_rust_accel_metrics()

    assert lseg_provider.classify_lseg_error_message(
        "Unable to resolve all requested identifiers in ['QRHC']."
    ) == ("unresolved_identifiers", ("QRHC",))
    assert lseg_provider.classify_lseg_error_message(
        "Session is not opened, can't send any request"
    ) == ("session_open_failed", ())
    assert lseg_provider.classify_lseg_error_message(
        "Request timeout via localhost:9000 /api/udf"
    ) == ("workspace_proxy_timeout", ())

    metrics = lseg_provider.get_lseg_provider_rust_accel_metrics()
    assert metrics["classify_error_fast_success"] == 3
    assert metrics["classify_error_fallbacks"] == 0


