def test_lseg_api_common_classify_error_policy_uses_real_rust_extension_when_built() -> None:
    if not lseg_api_common.get_lseg_api_common_rust_accel_metrics()["rust_accel_available"]:
        pytest.skip("LM2011 Rust extension is not built in this environment")
    lseg_api_common.reset_lseg_api_common_rust_accel_metrics()

    unresolved = lseg_provider.LsegRequestError(
        "Unable to resolve all requested identifiers in ['QRHC'].",
        error_kind="unresolved_identifiers",
        unresolved_identifiers=("QRHC",),
    )
    daily_limit = lseg_provider.LsegRequestError(
        "daily request limit exceeded",
        status_code=429,
        headers={"X-Daily-Remaining": "1"},
    )
    overload = lseg_provider.LsegRequestError(
        "service unavailable",
        status_code=503,
    )

    assert lseg_api_common.classify_error(
        unresolved,
        batch_size=2,
        attempt_no=1,
        max_attempts=4,
    ) == {
        "state": "retryable_error",
        "split_batch": True,
        "stop_stage": False,
        "defer_stage": False,
    }
    assert lseg_api_common.classify_error(
        daily_limit,
        batch_size=1,
        attempt_no=1,
        max_attempts=4,
    )["state"] == "deferred_daily_limit"
    assert lseg_api_common.classify_error(
        overload,
        batch_size=2,
        attempt_no=2,
        max_attempts=4,
    )["split_batch"] is True
    assert lseg_api_common.classify_error(
        RuntimeError("unexpected failure"),
        batch_size=1,
        attempt_no=4,
        max_attempts=4,
    ) == {
        "state": "fatal_error",
        "split_batch": False,
        "stop_stage": True,
        "defer_stage": False,
    }

    metrics = lseg_api_common.get_lseg_api_common_rust_accel_metrics()
    assert metrics["classify_policy_fast_success"] == 4
    assert metrics["classify_policy_fallbacks"] == 0


def test_lseg_api_common_classify_error_policy_matches_python_fallback_for_sample_values() -> None:
    samples = [
        (None, {}, "unresolved_identifiers", "unable to resolve", 1, 1, 4, 2, False),
        (None, {}, "unresolved_identifiers", "unable to resolve", 1, 4, 4, 2, False),
        (429, {"X-Daily-Remaining": "1"}, None, "rate limited", 1, 1, 4, 2, False),
        (403, {}, None, "forbidden", 1, 1, 4, 2, False),
        (503, {}, None, "service unavailable", 2, 2, 4, 2, False),
        (503, {}, None, "service unavailable", 1, 4, 4, 2, False),
        (None, {}, None, "bad value", 1, 1, 4, 2, True),
        (None, {}, None, "unexpected", 1, 4, 4, 2, False),
        (None, {}, None, "unexpected", 1, 1, 4, 2, False),
    ]
    for (
        status_code,
        headers,
        error_kind,
        message,
        batch_size,
        attempt_no,
        max_attempts,
        split_after_attempt,
        fatal_exception,
    ) in samples:
        assert lseg_api_common._classify_error_policy(
            status_code=status_code,
            headers=headers,
            error_kind=error_kind,
            message=message,
            batch_size=batch_size,
            attempt_no=attempt_no,
            max_attempts=max_attempts,
            split_after_attempt=split_after_attempt,
            fatal_exception=fatal_exception,
        ) == lseg_api_common._classify_error_policy_py(
            status_code=status_code,
            headers=headers,
            error_kind=error_kind,
            message=message,
            batch_size=batch_size,
            attempt_no=attempt_no,
            max_attempts=max_attempts,
            split_after_attempt=split_after_attempt,
            fatal_exception=fatal_exception,
        )


