def test_lseg_analyst_api_item_builders_use_real_rust_extension_when_built() -> None:
    if not lseg_analyst_api.get_lseg_analyst_api_rust_accel_metrics()["rust_accel_available"]:
        pytest.skip("LM2011 Rust extension is not built in this environment")
    lseg_analyst_api.reset_lseg_analyst_api_rust_accel_metrics()
    request_df = _analyst_request_frame()

    actual_items = lseg_analyst_api._build_analyst_actuals_items(request_df)
    estimate_items = lseg_analyst_api._build_analyst_estimate_items(request_df)

    assert [(item.instrument, item.batch_key) for item in actual_items] == [("AAA.N", "2024-01-01|2024-03-31")]
    assert actual_items[0].item_id == lseg_batching.stable_hash_id(
        "analyst_actuals",
        "group-a",
        prefix="item",
    )
    assert [(item.instrument, item.batch_key, item.parameters["Period"]) for item in estimate_items] == [
        ("AAA.N", "2023-10-01|2024-03-31|FQ1", "FQ1"),
        ("AAA.N", "2023-10-01|2024-03-31|FQ2", "FQ2"),
    ]
    assert estimate_items[1].item_id == lseg_batching.stable_hash_id(
        "analyst_estimates_monthly",
        "group-a",
        "FQ2",
        prefix="item",
    )
    metrics = lseg_analyst_api.get_lseg_analyst_api_rust_accel_metrics()
    assert metrics["actual_items_column_fast_success"] == 1
    assert metrics["actual_items_fast_success"] == 0
    assert metrics["estimate_items_column_fast_success"] == 1
    assert metrics["estimate_items_fast_success"] == 0
    assert metrics["actual_items_column_fallbacks"] == 0
    assert metrics["estimate_items_column_fallbacks"] == 0
    assert metrics["actual_items_fallbacks"] == 0
    assert metrics["estimate_items_fallbacks"] == 0


def test_lseg_analyst_api_item_builders_fall_back_to_row_rust_bridge(monkeypatch) -> None:
    class FakeRust:
        def build_analyst_actual_item_row_columns(self, *_args):
            raise RuntimeError("actual column bridge unavailable")

        def build_analyst_estimate_item_row_columns(self, *_args):
            raise RuntimeError("estimate column bridge unavailable")

        def build_analyst_actual_item_rows_value(self, source_rows):
            rows = list(source_rows)
            items = lseg_analyst_api._build_analyst_actuals_items_py(pl.DataFrame(rows))
            return [
                (
                    rows.index(item.payload["request_row"]),
                    item.item_id,
                    item.instrument,
                    item.parameters["SDate"],
                    item.parameters["EDate"],
                    None,
                )
                for item in items
            ]

        def build_analyst_estimate_item_rows_value(self, source_rows, _request_periods):
            rows = list(source_rows)
            items = lseg_analyst_api._build_analyst_estimate_items_py(pl.DataFrame(rows))
            return [
                (
                    rows.index(item.payload["request_row"]),
                    item.item_id,
                    item.instrument,
                    item.parameters["SDate"],
                    item.parameters["EDate"],
                    item.parameters["Period"],
                )
                for item in items
            ]

    monkeypatch.setattr(lseg_analyst_api, "_lm2011_rust", FakeRust())
    lseg_analyst_api.reset_lseg_analyst_api_rust_accel_metrics()
    request_df = _analyst_request_frame()

    assert lseg_analyst_api._build_analyst_actuals_items(request_df) == (
        lseg_analyst_api._build_analyst_actuals_items_py(request_df)
    )
    assert lseg_analyst_api._build_analyst_estimate_items(request_df) == (
        lseg_analyst_api._build_analyst_estimate_items_py(request_df)
    )

    metrics = lseg_analyst_api.get_lseg_analyst_api_rust_accel_metrics()
    assert metrics["actual_items_column_fast_failures"] == 1
    assert metrics["actual_items_column_fallbacks"] == 1
    assert metrics["actual_items_fast_success"] == 1
    assert metrics["actual_items_fallbacks"] == 0
    assert metrics["estimate_items_column_fast_failures"] == 1
    assert metrics["estimate_items_column_fallbacks"] == 1
    assert metrics["estimate_items_fast_success"] == 1
    assert metrics["estimate_items_fallbacks"] == 0


