def test_excel_ownership_universe_block_payloads_use_real_rust_extension_when_built() -> None:
    if not excel_io.get_excel_rust_accel_metrics()["rust_accel_available"]:
        pytest.skip("LM2011 Rust extension is not built in this environment")
    excel_io.reset_excel_rust_accel_metrics()

    payloads = excel_io._ownership_universe_block_payloads(
        _ownership_universe_payload_df(),
        input_field_order=_OWNERSHIP_UNIVERSE_INPUT_FIELDS,
        block_headers=_OWNERSHIP_UNIVERSE_BLOCK_HEADERS,
    )

    assert payloads[0]["base_col"] == 0
    assert payloads[0]["input_values"][:5] == [
        "9010:01:111111111:US1111111111:EFF",
        "EFF.N",
        "2024-01-01",
        "2024-01-31",
        "UNIVERSE_EFFECTIVE",
    ]
    assert payloads[0]["formula"] == (
        '=@RDP.Data(A3,'
        '"TR.CategoryOwnershipPct.Date;TR.CategoryOwnershipPct;TR.InstrStatTypeValue",'
        '"StatType=7 SDate="&A4&" EDate="&A5&" CH=Fd RH=IN")'
    )
    assert payloads[1]["base_col"] == 5
    assert payloads[1]["input_values"][6:] == ["", "", "", ""]
    assert payloads[1]["formula"] == (
        '=@RDP.Data(F3,'
        '"TR.CategoryOwnershipPct.Date;TR.CategoryOwnershipPct;TR.InstrStatTypeValue",'
        '"StatType=7 SDate="&F4&" EDate="&F5&" CH=Fd RH=IN")'
    )
    metrics = excel_io.get_excel_rust_accel_metrics()
    assert metrics["ownership_universe_block_payloads_fast_success"] == 1
    assert metrics["ownership_universe_block_payloads_fallbacks"] == 0


