def test_excel_doc_ownership_block_payloads_use_real_rust_extension_when_built() -> None:
    if not excel_io.get_excel_rust_accel_metrics()["rust_accel_available"]:
        pytest.skip("LM2011 Rust extension is not built in this environment")
    excel_io.reset_excel_rust_accel_metrics()
    df = _doc_ownership_payload_df()

    exact_payloads = excel_io._lm2011_doc_ownership_block_payloads(
        df,
        input_field_order=_DOC_OWNERSHIP_INPUT_FIELDS,
        block_headers=_DOC_OWNERSHIP_BLOCK_HEADERS,
        request_stage="EXACT",
    )
    fallback_payloads = excel_io._lm2011_doc_ownership_block_payloads(
        df,
        input_field_order=_DOC_OWNERSHIP_INPUT_FIELDS,
        block_headers=_DOC_OWNERSHIP_BLOCK_HEADERS,
        request_stage="FALLBACK",
    )

    assert exact_payloads[0]["base_col"] == 0
    assert exact_payloads[0]["input_values"][:4] == [
        "doc_exact",
        "AAA.N",
        dt.date(2024, 3, 31),
        dt.date(2024, 4, 1),
    ]
    assert exact_payloads[0]["authoritative_ric_formula"] == "=A3"
    assert exact_payloads[0]["data_formula"] == (
        '=@RDP.Data(A3,'
        '"TR.CategoryOwnershipPct.Date;TR.CategoryOwnershipPct;TR.InstrStatTypeValue",'
        '"StatType=7 SDate="&TEXT(A5,"yyyy-mm-dd")&'
        '" EDate="&TEXT(A5,"yyyy-mm-dd")&" CH=Fd RH=IN")'
    )
    assert exact_payloads[1]["base_col"] == 5
    assert exact_payloads[1]["authoritative_ric_formula"] == "=F3"
    assert fallback_payloads[0]["data_formula"] == (
        '=@RDP.Data(A3,'
        '"TR.CategoryOwnershipPct.Date;TR.CategoryOwnershipPct;TR.InstrStatTypeValue",'
        '"StatType=7 SDate="&TEXT(A6,"yyyy-mm-dd")&'
        '" EDate="&TEXT(A7,"yyyy-mm-dd")&" CH=Fd RH=IN")'
    )

    metrics = excel_io.get_excel_rust_accel_metrics()
    assert metrics["doc_ownership_block_payloads_fast_success"] == 2
    assert metrics["doc_ownership_block_payloads_fallbacks"] == 0


