def test_excel_extended_summary_formula_payloads_use_real_rust_extension_when_built() -> None:
    if not excel_io.get_excel_rust_accel_metrics()["rust_accel_available"]:
        pytest.skip("LM2011 Rust extension is not built in this environment")
    excel_io.reset_excel_rust_accel_metrics()

    payloads = excel_io._extended_summary_formula_payloads(
        _extended_summary_payload_df(),
        lookup_sheet_name="lookup_diagnostics",
        lookup_column_names=_EXTENDED_SUMMARY_LOOKUP_COLUMNS,
        lookup_row_count=3,
    )

    assert payloads[0] == {
        "row_idx": 1,
        "formula": "=COUNTIF('lookup_diagnostics'!$A$2:$A$4,TRUE)",
        "value": 0,
    }
    assert payloads[2]["formula"] == "=COUNTIF('lookup_diagnostics'!$C$2:$C$4,TRUE)"
    assert payloads[3]["formula"] == "=COUNTIF('lookup_diagnostics'!$D$2:$D$4,FALSE)"
    assert payloads[6]["formula"] == (
        "=SUMPRODUCT(--('lookup_diagnostics'!$F$2:$F$4=TRUE),"
        "--('lookup_diagnostics'!$B$2:$B$4<>TRUE),"
        "--('lookup_diagnostics'!$G$2:$G$4<>TRUE))"
    )
    assert payloads[-1]["formula"] == "=SUM(C8,C9,C10)"
    metrics = excel_io.get_excel_rust_accel_metrics()
    assert metrics["extended_summary_formula_payloads_fast_success"] == 1
    assert metrics["extended_summary_formula_payloads_fallbacks"] == 0


