def test_excel_extended_lookup_prefill_uses_formula_payloads(tmp_path: Path) -> None:
    from openpyxl import load_workbook
    import xlsxwriter

    out_path = tmp_path / "extended_lookup.xlsx"
    workbook = xlsxwriter.Workbook(str(out_path))
    try:
        worksheet = workbook.add_worksheet("lookup_diagnostics")
        for col_idx, name in enumerate(_EXTENDED_LOOKUP_COLUMNS):
            worksheet.write(0, col_idx, name)
        excel_io._prefill_refinitiv_extended_lookup_formulas(
            worksheet,
            column_names=_EXTENDED_LOOKUP_COLUMNS,
            row_count=1,
        )
    finally:
        workbook.close()

    loaded = load_workbook(out_path, data_only=False)
    try:
        ws = loaded["lookup_diagnostics"]
        assert ws["C2"].value == '=IF(B2="","",_xll.TR(B2,"TR.RIC"))'
        assert ws["G2"].value == "=LEN(B2)>0"
        assert ws["H2"].value == '=IFERROR(C2<>"",FALSE)'
        assert ws["W2"].value == (
            '=IF(AND(IFERROR(C2<>"",FALSE),IFERROR(J2<>"",FALSE)),'
            'IFERROR(C2=J2,FALSE),"")'
        )
        assert ws["AF2"].value == (
            '=IF((N(H2)+N(O2)+N(V2))<2,"",AND('
            'IF(W2="",TRUE,W2),IF(X2="",TRUE,X2),IF(Y2="",TRUE,Y2),'
            'IF(Z2="",TRUE,Z2),IF(AA2="",TRUE,AA2),IF(AB2="",TRUE,AB2),'
            'IF(AC2="",TRUE,AC2),IF(AD2="",TRUE,AD2),IF(AE2="",TRUE,AE2)))'
        )
    finally:
        loaded.close()


