def test_refinitiv_bridge_lookup_result_and_liid_match_python_fallback_for_sample_values() -> None:
    result_values = [None, "", "NULL", "NO UNIVERSE DEFINED.", "invalid identifier", " ABC.N "]
    for value in result_values:
        assert refinitiv_bridge_pipeline._normalized_lookup_result_value(value) == (
            refinitiv_bridge_pipeline._normalized_lookup_result_value_py(value)
        )
    bridge_ids = [None, "", "bad", "100:01:AAA:BBB:CCC", "100:-:AAA:BBB:CCC", "100:01:A:B:C:D:E"]
    for bridge_id in bridge_ids:
        if bridge_id == "bad":
            with pytest.raises(ValueError):
                refinitiv_bridge_pipeline._parse_bridge_row_id_liid(bridge_id)
            with pytest.raises(ValueError):
                refinitiv_bridge_pipeline._parse_bridge_row_id_liid_py(bridge_id)
            continue
        assert refinitiv_bridge_pipeline._parse_bridge_row_id_liid(bridge_id) == (
            refinitiv_bridge_pipeline._parse_bridge_row_id_liid_py(bridge_id)
        )


