def _resolution_handoff_case_record() -> dict[str, object]:
    return {
        "diagnostic_case_id": "missing_conventional:100:01",
        "case_target_bridge_row_id": "100:01:2020-01-01:2020-12-31:ABC.N",
        "target_class": "missing_conventional",
        "ISIN_returned_ric": " ISIN.N ",
        "CUSIP_returned_ric": "invalid identifier for CUSIP",
        "ticker_candidate_ric": " TICK.N ",
        "case_previous_effective_collection_ric": " PREV.N ",
        "case_next_effective_collection_ric": "NULL",
    }


def _resolution_handoff_source_record() -> dict[str, object]:
    return {
        "bridge_row_id": " 100:01:2019-01-01:2019-12-31:PREV.N ",
        "KYPERMNO": 12345,
        "CUSIP": " 123456789 ",
        "ISIN": " US1234567890 ",
        "TICKER": " ABC ",
        "first_seen_caldt": dt.date(2019, 1, 1),
        "last_seen_caldt": " 2019-12-31 ",
        "effective_collection_ric": " PREV.N ",
        "effective_collection_ric_source": " EXTENDED_FROM_PRIOR_ISIN ",
        "accepted_ric": "NULL",
        "accepted_ric_source": "",
    }


def _append_resolution_handoff_with(
    append_func,
    *,
    lookup_input: object = " TICK.N ",
    sequence_index: int = 4,
) -> tuple[int, list[dict[str, object]]]:
    rows: list[dict[str, object]] = []
    next_index = append_func(
        rows,
        case_record=_resolution_handoff_case_record(),
        source_record=_resolution_handoff_source_record(),
        retrieval_sequence_index=sequence_index,
        retrieval_role="TARGET_TICKER_CANDIDATE",
        diagnostic_role="TARGET",
        lookup_input=lookup_input,
        lookup_input_source="ticker_candidate_ric",
    )
    return next_index, rows


def test_refinitiv_bridge_resolution_handoff_row_uses_real_rust_extension_when_built() -> None:
    if not refinitiv_bridge_pipeline.get_refinitiv_bridge_rust_accel_metrics()["rust_accel_available"]:
        pytest.skip("LM2011 Rust extension is not built in this environment")
    refinitiv_bridge_pipeline.reset_refinitiv_bridge_rust_accel_metrics()

    next_index, rows = _append_resolution_handoff_with(
        refinitiv_bridge_pipeline._append_resolution_diagnostic_handoff_row
    )
    assert next_index == 5
    assert rows == [
        {
            "diagnostic_case_id": "missing_conventional:100:01",
            "case_target_bridge_row_id": "100:01:2020-01-01:2020-12-31:ABC.N",
            "target_class": "missing_conventional",
            "retrieval_sequence_index": 4,
            "retrieval_role": "TARGET_TICKER_CANDIDATE",
            "diagnostic_role": "TARGET",
            "bridge_row_id": "100:01:2019-01-01:2019-12-31:PREV.N",
            "KYPERMNO": "12345",
            "CUSIP": "123456789",
            "ISIN": "US1234567890",
            "TICKER": "ABC",
            "lookup_input": "TICK.N",
            "lookup_input_source": "ticker_candidate_ric",
            "request_start_date": "2019-01-01",
            "request_end_date": "2019-12-31",
            "effective_collection_ric": "PREV.N",
            "effective_collection_ric_source": "EXTENDED_FROM_PRIOR_ISIN",
            "accepted_ric": None,
            "accepted_ric_source": None,
            "ISIN_returned_ric": "ISIN.N",
            "CUSIP_returned_ric": None,
            "ticker_candidate_ric": "TICK.N",
            "case_previous_effective_collection_ric": "PREV.N",
            "case_next_effective_collection_ric": None,
        }
    ]

    unchanged_index, unchanged_rows = _append_resolution_handoff_with(
        refinitiv_bridge_pipeline._append_resolution_diagnostic_handoff_row,
        lookup_input="NULL",
        sequence_index=8,
    )
    assert unchanged_index == 8
