def test_refinitiv_bridge_resolution_diagnostic_helpers_use_real_rust_extension_when_built() -> None:
    if not refinitiv_bridge_pipeline.get_refinitiv_bridge_rust_accel_metrics()["rust_accel_available"]:
        pytest.skip("LM2011 Rust extension is not built in this environment")
    refinitiv_bridge_pipeline.reset_refinitiv_bridge_rust_accel_metrics()

    conflict_record = {
        "conventional_identity_conflict": True,
        "effective_collection_ric": "AAA.N",
        "ticker_candidate_available": False,
        "ISIN": "US1234567890",
    }
    unresolved_ticker_record = {
        "conventional_identity_conflict": False,
        "effective_collection_ric": None,
        "ticker_candidate_available": True,
    }
    resolved_record = {
        "conventional_identity_conflict": False,
        "effective_collection_ric": " AAA.N ",
        "ticker_candidate_available": False,
    }

    assert refinitiv_bridge_pipeline._resolution_diagnostic_target_class(conflict_record) == (
        "conventional_conflict"
    )
    assert refinitiv_bridge_pipeline._resolution_diagnostic_target_class(unresolved_ticker_record) == (
        "unresolved_ticker_only_candidate"
    )
    assert refinitiv_bridge_pipeline._resolution_diagnostic_target_class(resolved_record) is None
    assert refinitiv_bridge_pipeline._has_conventional_source({"CUSIP": "123456789"}) is True
    assert refinitiv_bridge_pipeline._has_conventional_source(
        {"ISIN": None, "CUSIP": "", "ISIN_returned_ric": None, "CUSIP_returned_ric": None}
    ) is False
    assert (
        refinitiv_bridge_pipeline._resolution_diagnostic_support_scope(
            same_liid_effective_support_available=True,
            cross_liid_effective_support_available=True,
        )
        == "same_liid_support"
    )
    assert (
        refinitiv_bridge_pipeline._resolution_diagnostic_support_scope(
            same_liid_effective_support_available=False,
            cross_liid_effective_support_available=True,
        )
        == "cross_liid_only_support"
    )
    assert (
        refinitiv_bridge_pipeline._resolution_diagnostic_support_scope(
            same_liid_effective_support_available=False,
            cross_liid_effective_support_available=False,
        )
        == "no_support"
    )
    assert (
        refinitiv_bridge_pipeline._resolution_diagnostic_block_reason(
            conflict_record,
            extension_support_scope="same_liid_support",
            case_any_adjacent_effective_available=True,
        )
        == "conflicting_neighbors"
    )
    assert (
        refinitiv_bridge_pipeline._resolution_diagnostic_block_reason(
            {"CUSIP": "123456789"},
            extension_support_scope="no_support",
            case_any_adjacent_effective_available=True,
        )
        == "no_effective_support_on_permno"
    )

    metrics = refinitiv_bridge_pipeline.get_refinitiv_bridge_rust_accel_metrics()
    assert metrics["resolution_target_class_fast_success"] == 3
    assert metrics["resolution_has_conventional_source_fast_success"] == 2
    assert metrics["resolution_support_scope_fast_success"] == 3
    assert metrics["resolution_block_reason_fast_success"] == 2
    assert metrics["resolution_target_class_fallbacks"] == 0


def test_refinitiv_bridge_resolution_diagnostic_helpers_match_python_fallback_for_sample_values() -> None:
    records = [
        {"conventional_identity_conflict": True, "effective_collection_ric": "AAA.N"},
        {"conventional_identity_conflict": False, "effective_collection_ric": "NULL"},
        {
            "conventional_identity_conflict": False,
            "effective_collection_ric": None,
            "ticker_candidate_available": True,
        },
        {
            "conventional_identity_conflict": False,
            "effective_collection_ric": "AAA.N",
            "ISIN": "US1234567890",
            "CUSIP": "",
            "ISIN_returned_ric": None,
            "CUSIP_returned_ric": None,
        },
        {
            "conventional_identity_conflict": False,
            "effective_collection_ric": "AAA.N",
            "ISIN": None,
            "CUSIP": "",
            "ISIN_returned_ric": None,
            "CUSIP_returned_ric": None,
        },
    ]
    for record in records:
        assert refinitiv_bridge_pipeline._resolution_diagnostic_target_class(record) == (
            refinitiv_bridge_pipeline._resolution_diagnostic_target_class_py(record)
        )
        assert refinitiv_bridge_pipeline._has_conventional_source(record) == (
            refinitiv_bridge_pipeline._has_conventional_source_py(record)
        )

    support_cases = [(False, False), (False, True), (True, False), (True, True)]
    for same_support, cross_support in support_cases:
        assert refinitiv_bridge_pipeline._resolution_diagnostic_support_scope(
            same_liid_effective_support_available=same_support,
            cross_liid_effective_support_available=cross_support,
        ) == refinitiv_bridge_pipeline._resolution_diagnostic_support_scope_py(
            same_liid_effective_support_available=same_support,
            cross_liid_effective_support_available=cross_support,
        )

    block_cases = [
        ({**records[0], "CUSIP": "123456789"}, "same_liid_support", True),
        ({}, "cross_liid_only_support", True),
        ({}, "same_liid_support", True),
        ({"CUSIP": "123456789"}, "same_liid_support", False),
        ({"CUSIP": "123456789"}, "no_support", True),
        ({"CUSIP": "123456789"}, "same_liid_support", True),
    ]
    for record, support_scope, adjacent_available in block_cases:
        assert refinitiv_bridge_pipeline._resolution_diagnostic_block_reason(
            record,
            extension_support_scope=support_scope,
            case_any_adjacent_effective_available=adjacent_available,
        ) == refinitiv_bridge_pipeline._resolution_diagnostic_block_reason_py(
            record,
            extension_support_scope=support_scope,
            case_any_adjacent_effective_available=adjacent_available,
        )


