def _bridge_ownership_validation_compare_frames(
    *,
    adjacent_ric: str = "AAA.N",
    value_offset: float = 0.25,
    extra_adjacent_category: bool = False,
    date_count: int = 3,
) -> tuple[pl.DataFrame, pl.DataFrame]:
    dates = [dt.date(2024, 1, 31), dt.date(2024, 2, 29), dt.date(2024, 3, 31)][:date_count]
    categories = ["Institutional", "Retail", "Fund", "Strategic"]
    target_rows: list[dict[str, object]] = []
    adjacent_rows: list[dict[str, object]] = []
    for date_index, returned_date in enumerate(dates):
        for category_index, returned_category in enumerate(categories):
            value = float((date_index + 1) * 100 + category_index)
            target_rows.append(
                {
                    "returned_date": returned_date,
                    "returned_category": returned_category,
                    "returned_value": value,
                    "returned_ric": "AAA.N",
                }
            )
            adjacent_rows.append(
                {
                    "returned_date": returned_date,
                    "returned_category": returned_category,
                    "returned_value": value + value_offset,
                    "returned_ric": adjacent_ric,
                }
            )
        if extra_adjacent_category:
            adjacent_rows.append(
                {
                    "returned_date": returned_date,
                    "returned_category": "Insider",
                    "returned_value": 999.0,
                    "returned_ric": adjacent_ric,
                }
            )
    return pl.DataFrame(target_rows), pl.DataFrame(adjacent_rows)


def test_refinitiv_bridge_ownership_validation_compare_uses_real_rust_extension_when_built() -> None:
    if not refinitiv_bridge_pipeline.get_refinitiv_bridge_rust_accel_metrics()["rust_accel_available"]:
        pytest.skip("LM2011 Rust extension is not built in this environment")
    refinitiv_bridge_pipeline.reset_refinitiv_bridge_rust_accel_metrics()

    target_results, adjacent_results = _bridge_ownership_validation_compare_frames()
    out = refinitiv_bridge_pipeline._compare_ownership_result_frames(target_results, adjacent_results)

    assert out == refinitiv_bridge_pipeline._compare_ownership_result_frames_py(target_results, adjacent_results)
    assert out["overlap_date_count"] == 3
    assert out["overlap_category_count"] == 4
    assert out["matched_value_pair_count"] == 12
    assert out["pair_has_useful_overlap"] is True
    assert out["pair_supports_corrobation"] is True
    assert out["pair_supports_same_identity_ric_variant"] is False
    assert out["pair_conflicts"] is False

    metrics = refinitiv_bridge_pipeline.get_refinitiv_bridge_rust_accel_metrics()
    assert metrics["ownership_validation_compare_fast_success"] == 1
    assert metrics["ownership_validation_compare_fallbacks"] == 0


def test_refinitiv_bridge_ownership_validation_compare_matches_python_fallback_for_sample_values() -> None:
    cases = [
        _bridge_ownership_validation_compare_frames(),
        _bridge_ownership_validation_compare_frames(adjacent_ric="ALT.N"),
        _bridge_ownership_validation_compare_frames(extra_adjacent_category=True),
        _bridge_ownership_validation_compare_frames(value_offset=12.0),
        _bridge_ownership_validation_compare_frames(date_count=2),
    ]
    for target_results, adjacent_results in cases:
        assert refinitiv_bridge_pipeline._compare_ownership_result_frames(
            target_results,
            adjacent_results,
        ) == refinitiv_bridge_pipeline._compare_ownership_result_frames_py(
            target_results,
            adjacent_results,
        )


def test_refinitiv_bridge_ownership_validation_compare_classifies_variant_and_conflict_cases() -> None:
    target_results, adjacent_results = _bridge_ownership_validation_compare_frames(adjacent_ric="ALT.N")
    variant = refinitiv_bridge_pipeline._compare_ownership_result_frames(target_results, adjacent_results)
    assert variant["same_returned_ric"] is False
    assert variant["pair_supports_corrobation"] is False
    assert variant["pair_supports_same_identity_ric_variant"] is True
    assert variant["pair_conflicts"] is False

    target_results, adjacent_results = _bridge_ownership_validation_compare_frames(extra_adjacent_category=True)
    category_conflict = refinitiv_bridge_pipeline._compare_ownership_result_frames(target_results, adjacent_results)
    assert category_conflict["same_category_set_on_overlap"] is False
    assert category_conflict["pair_supports_corrobation"] is False
    assert category_conflict["pair_conflicts"] is True

    target_results, adjacent_results = _bridge_ownership_validation_compare_frames(value_offset=12.0)
    value_conflict = refinitiv_bridge_pipeline._compare_ownership_result_frames(target_results, adjacent_results)
    assert value_conflict["pair_has_useful_overlap"] is True
    assert value_conflict["mean_abs_value_diff"] == 12.0
    assert value_conflict["max_abs_value_diff"] == 12.0
    assert value_conflict["pair_conflicts"] is True


