def _bridge_ownership_validation_case_inputs() -> tuple[
    list[dict[str, object]],
    list[dict[str, object]],
    list[dict[str, object]],
    list[str],
]:
    handoff_records: list[dict[str, object]] = [
        {
            "diagnostic_case_id": "case-a",
            "target_class": " conflict ",
            "case_target_bridge_row_id": " bridge-a ",
        },
        {
            "diagnostic_case_id": "case-b",
            "target_class": "conflict",
            "case_target_bridge_row_id": "bridge-b",
        },
        {
            "diagnostic_case_id": "case-c",
            "target_class": "unresolved",
            "case_target_bridge_row_id": "bridge-c",
        },
        {
            "diagnostic_case_id": "case-d",
            "target_class": "unresolved",
            "case_target_bridge_row_id": "bridge-d",
        },
        {
            "diagnostic_case_id": "case-e",
            "target_class": "sparse",
            "case_target_bridge_row_id": "bridge-e",
        },
    ]
    retrieval_records: list[dict[str, object]] = [
        {"diagnostic_case_id": "case-a", "retrieval_role": "TARGET_ISIN_CANDIDATE", "ownership_rows_returned": 2},
        {"diagnostic_case_id": "case-a", "retrieval_role": "PREVIOUS_EFFECTIVE", "ownership_rows_returned": 1},
        {"diagnostic_case_id": "case-b", "retrieval_role": "TARGET_CUSIP_CANDIDATE", "ownership_rows_returned": "3"},
        {"diagnostic_case_id": "case-b", "retrieval_role": "NEXT_EFFECTIVE", "ownership_rows_returned": 4},
        {"diagnostic_case_id": "case-c", "retrieval_role": "TARGET_TICKER_CANDIDATE", "ownership_rows_returned": 0},
        {"diagnostic_case_id": "case-c", "retrieval_role": "NEXT_EFFECTIVE", "ownership_rows_returned": 1},
        {"diagnostic_case_id": "case-d", "retrieval_role": "TARGET_ISIN_CANDIDATE", "ownership_rows_returned": 1},
        {"diagnostic_case_id": "case-d", "retrieval_role": "PREVIOUS_EFFECTIVE", "ownership_rows_returned": 1},
        {"diagnostic_case_id": "case-e", "retrieval_role": "TARGET_ISIN_CANDIDATE", "ownership_rows_returned": 1},
        {"diagnostic_case_id": "case-e", "retrieval_role": "NEXT_EFFECTIVE", "ownership_rows_returned": 1},
    ]
    pair_records: list[dict[str, object]] = [
        {
            "diagnostic_case_id": "case-a",
            "adjacent_direction": "PREVIOUS",
            "pair_supports_corrobation": True,
            "pair_supports_same_identity_ric_variant": False,
            "pair_conflicts": False,
        },
        {
            "diagnostic_case_id": "case-b",
            "adjacent_direction": "NEXT",
            "pair_supports_corrobation": False,
            "pair_supports_same_identity_ric_variant": False,
            "pair_conflicts": "conflict",
        },
        {
            "diagnostic_case_id": "case-d",
            "adjacent_direction": "PREVIOUS",
            "pair_supports_corrobation": False,
            "pair_supports_same_identity_ric_variant": 1,
            "pair_conflicts": False,
        },
    ]
    return handoff_records, retrieval_records, pair_records, ["case-a", "case-b", "case-c", "case-d", "case-e"]


