def test_refinitiv_bridge_ownership_universe_handoff_rows_match_python_fallback_for_sample_values() -> None:
    records = _bridge_ownership_universe_handoff_records()
    enabled_rows = refinitiv_bridge_pipeline._ownership_universe_handoff_rows(
        records,
        include_ticker_fallback=True,
    )
    disabled_rows = refinitiv_bridge_pipeline._ownership_universe_handoff_rows(
        records,
        include_ticker_fallback=False,
    )

    assert enabled_rows == refinitiv_bridge_pipeline._ownership_universe_handoff_rows_py(
        records,
        include_ticker_fallback=True,
    )
    assert disabled_rows == refinitiv_bridge_pipeline._ownership_universe_handoff_rows_py(
        records,
        include_ticker_fallback=False,
    )
    assert [row["ownership_lookup_role"] for row in enabled_rows] == [
        "UNIVERSE_EFFECTIVE",
        "UNIVERSE_TARGET_ISIN_CANDIDATE",
        "UNIVERSE_TARGET_CUSIP_CANDIDATE",
        "UNIVERSE_TARGET_TICKER_CANDIDATE",
        "UNIVERSE_NOT_RETRIEVABLE",
    ]
    ticker_disabled = next(row for row in disabled_rows if row["diagnostic_case_id"] == "row-ticker")
    assert ticker_disabled["retrieval_eligible"] is False
    assert ticker_disabled["retrieval_exclusion_reason"] == "ticker_fallback_disabled"
    missing = next(row for row in enabled_rows if row["diagnostic_case_id"] == "row-missing")
    assert missing["request_start_date"] == "2024-07-01"
    assert missing["retrieval_exclusion_reason"] == "no_usable_lookup_input"


