def test_refinitiv_bridge_extension_selection_helpers_use_real_rust_extension_when_built() -> None:
    if not refinitiv_bridge_pipeline.get_refinitiv_bridge_rust_accel_metrics()["rust_accel_available"]:
        pytest.skip("LM2011 Rust extension is not built in this environment")
    refinitiv_bridge_pipeline.reset_refinitiv_bridge_rust_accel_metrics()

    assert refinitiv_bridge_pipeline._accepted_source_matches_target(
        {"ISIN": " US1234567890 ", "CUSIP": "999999999"},
        _lookup_identity_candidate(
            source="ISIN",
            returned_isin="US1234567890",
            returned_cusip="123456789",
        ),
    )
    assert not refinitiv_bridge_pipeline._accepted_source_matches_target(
        {"ISIN": "US9999999999", "CUSIP": "123456789"},
        _lookup_identity_candidate(
            source="CUSIP",
            returned_isin="US1234567890",
            returned_cusip="123456789",
        ),
    )
    prior_record = {"bridge_row_id": "prior"}
    next_record = {"bridge_row_id": "next"}
    assert refinitiv_bridge_pipeline._choose_adjacent_extension_source(
        _lookup_identity_candidate(source="CUSIP"),
        _lookup_identity_candidate(source="ISIN"),
        prior_record=prior_record,
        next_record=next_record,
    ) == (next_record, "ADJACENT")
    assert refinitiv_bridge_pipeline._choose_adjacent_extension_source(
        _lookup_identity_candidate(source="ISIN"),
        _lookup_identity_candidate(source="CUSIP"),
        prior_record=prior_record,
        next_record=next_record,
    ) == (prior_record, "ADJACENT")

    metrics = refinitiv_bridge_pipeline.get_refinitiv_bridge_rust_accel_metrics()
    assert metrics["accepted_source_match_fast_success"] == 2
    assert metrics["adjacent_extension_choice_fast_success"] == 2
    assert metrics["accepted_source_match_fallbacks"] == 0


def test_refinitiv_bridge_extension_selection_helpers_match_python_fallback_for_sample_values() -> None:
    match_cases = [
        (
            {"ISIN": " US1234567890 ", "CUSIP": "999999999"},
            _lookup_identity_candidate(
                source="ISIN",
                returned_isin="US1234567890",
                returned_cusip="123456789",
            ),
        ),
        (
            {"ISIN": None, "CUSIP": "123456789"},
            _lookup_identity_candidate(
                source="CUSIP",
                returned_isin=None,
                returned_cusip="123456789",
            ),
        ),
        (
            {"ISIN": "US9999999999", "CUSIP": "123456789"},
            _lookup_identity_candidate(
                source="CUSIP",
                returned_isin="US1234567890",
                returned_cusip="123456789",
            ),
        ),
        ({}, _lookup_identity_candidate(source="ISIN", returned_isin="US1234567890")),
    ]
    for target_record, source_candidate in match_cases:
        assert refinitiv_bridge_pipeline._accepted_source_matches_target(
            target_record,
            source_candidate,
        ) == refinitiv_bridge_pipeline._accepted_source_matches_target_py(
            target_record,
            source_candidate,
        )

    prior_record = {"bridge_row_id": "prior"}
    next_record = {"bridge_row_id": "next"}
    choice_cases = [
        ("CUSIP", "ISIN"),
        ("TICKER", "CUSIP"),
        ("ISIN", "CUSIP"),
    ]
    for prior_source, next_source in choice_cases:
        assert refinitiv_bridge_pipeline._choose_adjacent_extension_source(
            _lookup_identity_candidate(source=prior_source),
            _lookup_identity_candidate(source=next_source),
            prior_record=prior_record,
            next_record=next_record,
        ) == refinitiv_bridge_pipeline._choose_adjacent_extension_source_py(
            _lookup_identity_candidate(source=prior_source),
            _lookup_identity_candidate(source=next_source),
            prior_record=prior_record,
            next_record=next_record,
        )


