def test_sentence_quality_classifiers_use_real_rust_extension_when_built() -> None:
    if not sentence_quality.get_sentence_quality_rust_accel_metrics()["rust_accel_available"]:
        pytest.skip("LM2011 Rust extension is not built in this environment")
    sentence_quality.reset_sentence_quality_rust_accel_metrics()

    assert sentence_quality._is_separator_line("---")
    assert sentence_quality._numeric_only_fragment("3.")
    assert sentence_quality._short_fragment("3.", 1, 2)
    assert sentence_quality._very_short_fragment("Risk", 1, 4)
    assert sentence_quality._lower_fragment("and related matters", 3, 19)
    assert sentence_quality._one_word_fragment("RISK.")
    assert sentence_quality._has_terminal_punct('Management discussion."')
    assert sentence_quality._table_like_sentence(
        "CONSOLIDATED STATEMENTS OF CASH FLOWS\n1999 1998 1997\n100 200 300",
        140,
    )
    assert sentence_quality._generic_no_with_continuation(
        "revised Statement No.",
        "158), we recorded a charge",
    )

    metrics = sentence_quality.get_sentence_quality_rust_accel_metrics()
    assert metrics["separator_fast_success"] >= 1
    assert metrics["numeric_only_fast_success"] == 1
    assert metrics["short_fragment_fast_success"] == 1
    assert metrics["very_short_fragment_fast_success"] == 1
    assert metrics["lower_fragment_fast_success"] == 1
    assert metrics["one_word_fast_success"] == 1
    assert metrics["terminal_punct_fast_success"] == 1
    assert metrics["table_like_fast_success"] == 1
    assert metrics["generic_no_continuation_fast_success"] == 1


def test_sentence_quality_rust_classifiers_match_python_fallback_for_sample_values() -> None:
    samples = [
        "",
        "---",
        "3.",
        "(1.2)",
        "RISK FACTORS.",
        "Management discussion.",
        "CONSOLIDATED STATEMENTS OF CASH FLOWS\n1999 1998 1997\n100 200 300",
        "We monitor credit quality and adjust pricing as needed.",
    ]
    for text in samples:
        assert sentence_quality._numeric_only_fragment(text) == sentence_quality._numeric_only_fragment_py(text)
        assert sentence_quality._short_fragment(text, 4, 16) == sentence_quality._short_fragment_py(text, 4, 16)
        assert sentence_quality._very_short_fragment(text, 4, 16) == sentence_quality._very_short_fragment_py(text, 4, 16)
        assert sentence_quality._lower_fragment(text, 4, 16) == sentence_quality._lower_fragment_py(text, 4, 16)
        assert sentence_quality._one_word_fragment(text) == sentence_quality._one_word_fragment_py(text)
        assert sentence_quality._has_terminal_punct(text) == sentence_quality._has_terminal_punct_py(text)
        assert sentence_quality._table_like_sentence(text, 140) == sentence_quality._table_like_sentence_py(text, 140)
    continuation_pairs = [
        ("revised Statement No.", "158), we recorded a charge"),
        ("revised Statement No.", "ordinary continuation"),
        ("ordinary sentence.", "158), we recorded a charge"),
        ("", ""),
    ]
    for text, next_text in continuation_pairs:
        assert sentence_quality._generic_no_with_continuation(text, next_text) == (
            sentence_quality._generic_no_with_continuation_py(text, next_text)
        )


