def test_item_cleaning_row_audit_payload_helpers_use_real_rust_extension_when_built() -> None:
    if not item_text_cleaning.get_item_cleaning_rust_accel_metrics()["rust_accel_available"]:
        pytest.skip("LM2011 Rust extension is not built in this environment")
    item_text_cleaning.reset_item_cleaning_rust_accel_metrics()

    payload = item_text_cleaning._base_row_payload(_item_cleaning_base_row(), text_scope="item_7_mda")
    assert payload == item_text_cleaning._base_row_payload_py(_item_cleaning_base_row(), text_scope="item_7_mda")
    assert payload["calendar_year"] == 2020
    assert payload["text_scope"] == "item_7_mda"
    assert (
        item_text_cleaning._review_status(
            manual_audit_candidate=False,
            boundary_authority_status="accepted",
        )
        == item_text_cleaning.REVIEW_STATUS_NOT_REQUIRED
    )
    assert (
        item_text_cleaning._review_status(
            manual_audit_candidate=False,
            boundary_authority_status="review_needed",
        )
        == item_text_cleaning.REVIEW_STATUS_REQUIRED_UNREVIEWED
    )
    assert (
        item_text_cleaning._review_status(
            manual_audit_candidate=True,
            boundary_authority_status="accepted",
            existing_review_status=item_text_cleaning.REVIEW_STATUS_APPROVED,
        )
        == item_text_cleaning.REVIEW_STATUS_APPROVED
    )
    assert item_text_cleaning._production_eligible(item_text_cleaning.REVIEW_STATUS_NOT_REQUIRED)
    assert not item_text_cleaning._production_eligible(item_text_cleaning.REVIEW_STATUS_REQUIRED_UNREVIEWED)

    metrics = item_text_cleaning.get_item_cleaning_rust_accel_metrics()
    assert metrics["base_row_payload_fast_success"] == 1
    assert metrics["base_row_payload_fallbacks"] == 0
    assert metrics["review_status_fast_success"] == 3
    assert metrics["review_status_fallbacks"] == 0
    assert metrics["production_eligible_fast_success"] == 2
    assert metrics["production_eligible_fallbacks"] == 0


def test_item_cleaning_row_audit_payload_helpers_match_python_fallback_for_sample_values() -> None:
    rows = [
        _item_cleaning_base_row(),
        {"doc_id": "doc-2", "filing_year": None, "boundary_authority_status": None},
    ]
    for row in rows:
        assert item_text_cleaning._base_row_payload(row, text_scope="item_1a_risk_factors") == (
            item_text_cleaning._base_row_payload_py(row, text_scope="item_1a_risk_factors")
        )

    review_cases = [
        (False, "accepted", None),
        (False, "review_needed", None),
        (True, "accepted", None),
        (False, "", None),
        (False, None, None),
        (False, "accepted", item_text_cleaning.REVIEW_STATUS_APPROVED),
        (True, "review_needed", item_text_cleaning.REVIEW_STATUS_REJECTED),
    ]
    for manual_audit_candidate, boundary_authority_status, existing_review_status in review_cases:
        assert item_text_cleaning._review_status(
            manual_audit_candidate=manual_audit_candidate,
            boundary_authority_status=boundary_authority_status,
            existing_review_status=existing_review_status,
        ) == item_text_cleaning._review_status_py(
            manual_audit_candidate=manual_audit_candidate,
            boundary_authority_status=boundary_authority_status,
            existing_review_status=existing_review_status,
        )

    for review_status in [
        item_text_cleaning.REVIEW_STATUS_NOT_REQUIRED,
        item_text_cleaning.REVIEW_STATUS_REQUIRED_UNREVIEWED,
        item_text_cleaning.REVIEW_STATUS_APPROVED,
        item_text_cleaning.REVIEW_STATUS_REJECTED,
        "custom",
    ]:
        assert item_text_cleaning._production_eligible(review_status) == (
            item_text_cleaning._production_eligible_py(review_status)
        )


