def _item_cleaning_finalize_inputs() -> tuple[list[dict[str, object]], list[int], ItemTextCleaningConfig]:
    kept_row = {
        **_item_cleaning_base_row(),
        "doc_id": "doc-kept",
        "benchmark_row_id": "row-kept",
        "benchmark_item_code": "item_1a",
        "benchmark_item_label": "Risk Factors",
        "item_id": "1A",
        "canonical_item": "item_1a",
    }
    dropped_row = {
        **_item_cleaning_base_row(),
        "doc_id": "doc-dropped",
        "benchmark_row_id": "row-dropped",
        "review_status": item_text_cleaning.REVIEW_STATUS_APPROVED,
    }
    prepared_rows: list[dict[str, object]] = [
        {
            "row": kept_row,
            "text_scope": "item_1a_risk_factors",
            "original_text": "A" * 600,
            "cleaning_result": item_text_cleaning.CleanedTextResult(
                cleaned_text="risk factors",
                page_marker_lines_removed=1,
                report_header_footer_lines_removed=2,
                structural_tag_lines_removed=0,
                table_like_lines_removed=3,
                toc_prefix_trimmed=True,
                toc_prefix_trimmed_char_count=25,
                tail_truncated=True,
                tail_truncated_char_count=40,
                reference_only_stub=False,
                effectively_non_body_text=False,
            ),
            "cleaned_text": "risk factors",
            "original_char_count": 600,
            "cleaned_char_count": 12,
            "removed_char_count": 588,
            "removal_ratio": 0.98,
        },
        {
            "row": dropped_row,
            "text_scope": "item_7_mda",
            "original_text": "management discussion",
            "cleaning_result": item_text_cleaning.CleanedTextResult(
                cleaned_text="short",
                page_marker_lines_removed=0,
                report_header_footer_lines_removed=0,
                structural_tag_lines_removed=0,
                table_like_lines_removed=0,
                toc_prefix_trimmed=False,
                toc_prefix_trimmed_char_count=0,
                tail_truncated=False,
                tail_truncated_char_count=0,
                reference_only_stub=False,
                effectively_non_body_text=False,
            ),
            "cleaned_text": "short",
            "original_char_count": 21,
            "cleaned_char_count": 5,
            "removed_char_count": 16,
            "removal_ratio": 16 / 21,
        },
    ]
    cfg = ItemTextCleaningConfig(
        item7_min_lm_tokens=5,
        warn_below_clean_char_count=20,
        large_removal_warning_threshold=0.40,
    )
    return prepared_rows, [2, 1], cfg


def test_item_cleaning_finalize_rows_use_real_rust_extension_when_built() -> None:
    if not item_text_cleaning.get_item_cleaning_rust_accel_metrics()["rust_accel_available"]:
        pytest.skip("LM2011 Rust extension is not built in this environment")
    item_text_cleaning.reset_item_cleaning_rust_accel_metrics()
    prepared_rows, token_counts, cfg = _item_cleaning_finalize_inputs()

    actual = item_text_cleaning._finalize_cleaning_rows(
        prepared_rows,
        token_counts,
        cfg=cfg,
        segment_policy="sentence_policy_v1",
    )
    expected = item_text_cleaning._finalize_cleaning_rows_py(
        prepared_rows,
        token_counts,
        cfg=cfg,
        segment_policy="sentence_policy_v1",
    )

    assert actual == expected
    audit_rows, cleaned_rows = actual
    assert len(audit_rows) == 2
    assert len(cleaned_rows) == 1
    assert audit_rows[0]["manual_audit_reason"] == "large_removal|toc_prefix_trimmed|tail_truncated|below_clean_char_warning"
    assert audit_rows[1]["drop_reason"] == "item7_below_lm_token_floor"
    assert audit_rows[1]["review_status"] == item_text_cleaning.REVIEW_STATUS_APPROVED
    metrics = item_text_cleaning.get_item_cleaning_rust_accel_metrics()
    assert metrics["finalize_rows_fast_success"] == 1
    assert metrics["finalize_rows_fallbacks"] == 0


