    assert metrics["table_intro_fast_success"] == 1
    assert metrics["table_support_fast_success"] == 1
    assert metrics["toc_like_fast_success"] == 1
    assert metrics["tail_truncate_fast_success"] == 1
    assert metrics["reference_stub_fast_success"] == 1
