def test_item_cleaning_scope_status_helpers_use_real_rust_extension_when_built() -> None:
    if not item_text_cleaning.get_item_cleaning_rust_accel_metrics()["rust_accel_available"]:
        pytest.skip("LM2011 Rust extension is not built in this environment")
    item_text_cleaning.reset_item_cleaning_rust_accel_metrics()

    assert item_text_cleaning.benchmark_item_code_to_text_scope(" item-7 ") == "item_7_mda"
    assert item_text_cleaning.benchmark_item_code_to_text_scope("item_1a") == "item_1a_risk_factors"
    assert item_text_cleaning.benchmark_item_code_to_text_scope("custom-scope") == "custom_scope"
    assert item_text_cleaning.benchmark_item_code_to_text_scope("   ") is None
    assert item_text_cleaning._activation_status("item_7_mda") == "blocked_pending_manual_audit"
    assert item_text_cleaning._activation_status("item_1_business") == "robustness_only_pending_manual_audit"
