    assert item_text_cleaning._audit_period(2016) == "2009_2016"
    assert item_text_cleaning._audit_period(2017) == "2017_2024"

    metrics = item_text_cleaning.get_item_cleaning_rust_accel_metrics()
    assert metrics["benchmark_scope_fast_success"] == 4
    assert metrics["activation_status_fast_success"] == 3
    assert metrics["audit_period_fast_success"] == 4
    assert metrics["benchmark_scope_fallbacks"] == 0


