def _cleaning_result_for_reason(
    *,
    reference_only_stub: bool = False,
    effectively_non_body_text: bool = False,
) -> item_text_cleaning.CleanedTextResult:
    return item_text_cleaning.CleanedTextResult(
        cleaned_text="",
        page_marker_lines_removed=0,
        report_header_footer_lines_removed=0,
        structural_tag_lines_removed=0,
        table_like_lines_removed=0,
        toc_prefix_trimmed=False,
        toc_prefix_trimmed_char_count=0,
        tail_truncated=False,
        tail_truncated_char_count=0,
        reference_only_stub=reference_only_stub,
        effectively_non_body_text=effectively_non_body_text,
    )


def _manual_audit_reason_row(**overrides) -> dict[str, object]:
    row: dict[str, object] = {
        "dropped_after_cleaning": False,
        "drop_reason": None,
        "warning_large_removal": False,
        "toc_prefix_trimmed": False,
        "tail_truncated": False,
        "reference_only_stub": False,
        "item7_lm_token_floor_failed": False,
        "warning_below_clean_char_count": False,
    }
    row.update(overrides)
    return row


def test_item_cleaning_drop_and_audit_reasons_use_real_rust_extension_when_built() -> None:
    if not item_text_cleaning.get_item_cleaning_rust_accel_metrics()["rust_accel_available"]:
        pytest.skip("LM2011 Rust extension is not built in this environment")
    item_text_cleaning.reset_item_cleaning_rust_accel_metrics()

    assert (
        item_text_cleaning._drop_reason(
            cleaned_text="  \n",
            text_scope="item_7_mda",
            cleaning_result=_cleaning_result_for_reason(),
            cleaned_lm_total_token_count=0,
            cfg=ItemTextCleaningConfig(),
        )
        == "blank_after_cleaning"
    )
    assert (
        item_text_cleaning._drop_reason(
            cleaned_text="Management discusses liquidity.",
            text_scope="item_7_mda",
            cleaning_result=_cleaning_result_for_reason(reference_only_stub=True),
            cleaned_lm_total_token_count=300,
            cfg=ItemTextCleaningConfig(),
        )
        == "reference_only_stub"
    )
    assert (
        item_text_cleaning._manual_audit_reason(
            _manual_audit_reason_row(
                dropped_after_cleaning=True,
                drop_reason="reference_only_stub",
                warning_large_removal=True,
                toc_prefix_trimmed=True,
                reference_only_stub=True,
                item7_lm_token_floor_failed=True,
                warning_below_clean_char_count=True,
            )
        )
        == "reference_only_stub|large_removal|toc_prefix_trimmed|item7_lm_token_floor_failed|below_clean_char_warning"
    )

    metrics = item_text_cleaning.get_item_cleaning_rust_accel_metrics()
    assert metrics["drop_reason_fast_success"] == 2
    assert metrics["manual_audit_reason_fast_success"] == 1
    assert metrics["drop_reason_fallbacks"] == 0
    assert metrics["manual_audit_reason_fallbacks"] == 0


