def _item_cleaning_manual_audit_sample_frame() -> pl.DataFrame:
    rows: list[dict[str, object]] = []
    for idx in range(7):
        rows.append(
            {
                "doc_id": f"mda-{idx}",
                "filing_date": dt.date(2008, 3, min(idx + 1, 28)),
                "calendar_year": 2008,
                "audit_period": "ignored",
                "text_scope": "item_7_mda",
                "benchmark_row_id": f"mda-row-{idx:02}",
                "cleaning_policy_id": "clean-v1",
                "boundary_authority_status": "accepted",
                "review_status": "required_unreviewed",
                "production_eligible": False,
                "original_start_snippet": f"original start {idx}",
                "cleaned_start_snippet": f"cleaned start {idx}",
                "original_end_snippet": f"original end {idx}",
                "cleaned_end_snippet": f"cleaned end {idx}",
                "manual_audit_candidate": idx % 2 == 0,
                "manual_audit_reason": "tail_truncated" if idx % 2 == 0 else None,
                "dropped_after_cleaning": idx == 4,
                "warning_large_removal": idx == 2,
                "toc_prefix_trimmed": False,
                "tail_truncated": idx % 2 == 0,
                "reference_only_stub": False,
                "item7_lm_token_floor_failed": idx == 4,
            }
        )
    for idx in range(3):
        rows.append(
            {
                "doc_id": f"risk-{idx}",
                "filing_date": dt.date(2018, 4, idx + 1),
                "calendar_year": 2018,
                "audit_period": "ignored",
                "text_scope": "item_1a_risk_factors",
                "benchmark_row_id": f"risk-row-{idx:02}",
                "cleaning_policy_id": "clean-v2",
                "boundary_authority_status": "review_needed",
                "review_status": "required_unreviewed",
                "production_eligible": False,
                "original_start_snippet": f"risk original start {idx}",
                "cleaned_start_snippet": f"risk cleaned start {idx}",
                "original_end_snippet": f"risk original end {idx}",
                "cleaned_end_snippet": f"risk cleaned end {idx}",
                "manual_audit_candidate": idx == 1,
                "manual_audit_reason": "large_removal" if idx == 1 else "",
                "dropped_after_cleaning": False,
                "warning_large_removal": idx == 1,
                "toc_prefix_trimmed": idx == 2,
                "tail_truncated": False,
                "reference_only_stub": False,
                "item7_lm_token_floor_failed": False,
            }
        )
    return pl.DataFrame(rows)


