    assert metrics["page_marker_fallbacks"] == 1
    assert metrics["report_header_fallbacks"] == 1
    assert metrics["structural_residue_fallbacks"] == 1
    assert metrics["table_like_fallbacks"] == 1
    assert metrics["table_header_fallbacks"] == 1
    assert metrics["strong_table_title_fallbacks"] == 1
    assert metrics["table_intro_fallbacks"] == 1
    assert metrics["table_support_fallbacks"] == 1
    assert metrics["toc_like_fallbacks"] == 1
    assert metrics["tail_truncate_fallbacks"] == 1
    assert metrics["reference_stub_fallbacks"] == 1
    assert metrics["benchmark_scope_fallbacks"] == 1
    assert metrics["activation_status_fallbacks"] == 1
    assert metrics["audit_period_fallbacks"] == 1


