def test_sentence_chunk_end_uses_real_rust_extension_when_built(monkeypatch) -> None:
    if not sentences.get_sentence_postprocess_rust_accel_metrics()["rust_accel_available"]:
        pytest.skip("LM2011 Rust extension is not built in this environment")
    monkeypatch.setattr(sentences, "SENTENCE_CHUNK_CHAR_LIMIT", 20)
    sentences.reset_sentence_postprocess_rust_accel_metrics()

    assert sentences._choose_chunk_end("Alpha.\n\nBeta sentence continues beyond limit", start=0) == (
        8,
        "double_newline",
    )
    assert sentences._choose_chunk_end("Alpha\nBeta sentence continues beyond limit", start=0) == (6, "newline")
    assert sentences._choose_chunk_end("Alpha. Beta sentence continues beyond limit", start=0) == (
        7,
        "sentence_punct",
    )
    assert sentences._choose_chunk_end("Alpha BetaGammaDelta continues", start=0) == (6, "whitespace")
    assert sentences._choose_chunk_end("AlphaBetaGammaDeltaX", start=0) == (20, "end_of_text")
    assert sentences._choose_chunk_end("AlphaBetaGammaDeltaLonger", start=0) == (20, "hard_limit_250k")

    metrics = sentences.get_sentence_postprocess_rust_accel_metrics()
    assert metrics["chunk_end_fast_success"] == 6
    assert metrics["chunk_end_fallbacks"] == 0


