def test_multisurface_normalized_match_bounds_uses_real_rust_extension_when_built() -> None:
    if not multisurface_audit.get_multisurface_audit_rust_accel_metrics()["rust_accel_available"]:
        pytest.skip("LM2011 Rust extension is not built in this environment")
    multisurface_audit.reset_multisurface_audit_rust_accel_metrics()

    full_text = "Intro.\nAlpha beta gamma delta epsilon zeta eta theta iota kappa lambda.\nOutro."
    query = "alpha   beta gamma delta epsilon zeta eta theta iota kappa lambda."
    index = multisurface_audit._normalize_with_positions(full_text)

    assert multisurface_audit._normalized_match_bounds(index, query) == (
        full_text.index("Alpha"),
        full_text.index("lambda.") + len("lambda."),
    )
    assert multisurface_audit._normalized_match_bounds(index, "too short") is None
    assert (
        multisurface_audit._normalized_match_bounds(
            index,
            "missing beta gamma delta epsilon zeta eta theta iota kappa lambda.",
        )
        is None
    )

    metrics = multisurface_audit.get_multisurface_audit_rust_accel_metrics()
    assert metrics["normalized_match_bounds_fast_success"] == 3
    assert metrics["normalized_match_bounds_fallbacks"] == 0


