def test_multisurface_mark_escalated_cases_use_real_rust_extension_when_built() -> None:
    if not multisurface_audit.get_multisurface_audit_rust_accel_metrics()["rust_accel_available"]:
        pytest.skip("LM2011 Rust extension is not built in this environment")
    multisurface_audit.reset_multisurface_audit_rust_accel_metrics()

    cases = _multisurface_escalation_cases_sample()
    result = multisurface_audit._mark_escalated_cases(cases, cap=3)

    assert result == multisurface_audit._mark_escalated_cases_py(cases, cap=3)
    assert [row["case_id"] for row in result[:3]] == ["boundary-1", "long-1", "short-1"]
    assert sum(bool(row["full_report_needed"]) for row in result) == 3
    assert result[0]["escalation_reason"] == (
        "boundary_context_required|item_sentence_disagreement"
    )
    assert all(row["full_report_needed"] is False for row in cases)

    metrics = multisurface_audit.get_multisurface_audit_rust_accel_metrics()
    assert metrics["mark_escalated_cases_fast_success"] == 1
    assert metrics["mark_escalated_cases_fallbacks"] == 0


