def test_multisurface_chunk_records_from_frame_falls_back_to_row_rust_bridge(monkeypatch) -> None:
    class FakeRust:
        def multisurface_chunk_record_indices_columns(self, *_args):
            raise RuntimeError("column bridge unavailable")

        def multisurface_chunk_record_indices(self, records, chunk_count):
            records = list(records)
            chunks = multisurface_audit._chunk_records_py(records, chunk_count=chunk_count)
            return [[records.index(record) for record in chunk] for chunk in chunks]

    monkeypatch.setattr(multisurface_audit, "_lm2011_rust", FakeRust())
    multisurface_audit.reset_multisurface_audit_rust_accel_metrics()

    frame = _multisurface_chunk_records_frame()
    assert multisurface_audit._chunk_records_from_frame(frame, chunk_count=3) == (
        multisurface_audit._chunk_records_py(frame.to_dicts(), chunk_count=3)
    )

    metrics = multisurface_audit.get_multisurface_audit_rust_accel_metrics()
    assert metrics["chunk_records_column_fast_failures"] == 1
    assert metrics["chunk_records_column_fallbacks"] == 1
    assert metrics["chunk_records_fast_success"] == 1
    assert metrics["chunk_records_fallbacks"] == 0


