class _FakeFinbertConfig:
    def __init__(self, *, id2label: object = None, label2id: object = None) -> None:
        self.id2label = id2label
        self.label2id = label2id


class _FakeFinbertModel:
    def __init__(self, *, id2label: object = None, label2id: object = None) -> None:
        self.config = _FakeFinbertConfig(id2label=id2label, label2id=label2id)


def test_finbert_benchmark_label_mapping_uses_real_rust_extension_when_built() -> None:
    if not finbert_benchmark.get_finbert_benchmark_rust_accel_metrics()["rust_accel_available"]:
        pytest.skip("LM2011 Rust extension is not built in this environment")
    finbert_benchmark.reset_finbert_benchmark_rust_accel_metrics()

    model = _FakeFinbertModel(id2label={"2": "Bullish", 0: "NEG", 1.0: "Neutral"})

    assert finbert_benchmark.resolve_finbert_label_mapping(model) == {
        0: "negative",
        1: "neutral",
        2: "positive",
    }
    metrics = finbert_benchmark.get_finbert_benchmark_rust_accel_metrics()
    assert metrics["label_mapping_fast_success"] == 1
    assert metrics["label_mapping_fallbacks"] == 0


def test_finbert_benchmark_label_mapping_matches_python_fallback_for_sample_values() -> None:
    samples = [
        _FakeFinbertModel(id2label={"2": "positive", "0": "negative", "1": "neutral"}),
        _FakeFinbertModel(id2label=None, label2id={"NEG": "0", "Neutral": 1.0, "Bullish": 2}),
        _FakeFinbertModel(id2label={"bad": "negative", 1: "neutral", 2: "positive", 0: "bearish"}),
    ]
    for model in samples:
        assert finbert_benchmark.resolve_finbert_label_mapping(model) == (
            finbert_benchmark._resolve_finbert_label_mapping_py(
                model.config.id2label,
                model.config.label2id,
            )
        )

    duplicate_model = _FakeFinbertModel(id2label={0: "negative", 1: "bearish", 2: "positive"})
    with pytest.raises(ValueError, match="Duplicate normalized FinBERT label"):
        finbert_benchmark.resolve_finbert_label_mapping(duplicate_model)

    incomplete_model = _FakeFinbertModel(id2label={0: "negative", 1: "neutral"})
    with pytest.raises(ValueError, match="Could not normalize FinBERT labels"):
        finbert_benchmark.resolve_finbert_label_mapping(incomplete_model)


