def test_finbert_staged_bucket_summary_uses_real_rust_extension_when_built(tmp_path: Path) -> None:
    if not finbert_staged_inference.get_finbert_staged_rust_accel_metrics()["rust_accel_available"]:
        pytest.skip("LM2011 Rust extension is not built in this environment")
    finbert_staged_inference.reset_finbert_staged_rust_accel_metrics()

    summary = finbert_staged_inference._build_bucket_summary(
        pl.DataFrame(
            {
                "finbert_token_bucket_512": ["short", "short", "medium", "long", "other", None],
                "finbert_token_count_512": [10, 20, 30, None, 40, 50],
            }
        ),
        filing_year=2001,
        source_path=tmp_path / "sentences.parquet",
    )

    rows = {row["bucket"]: row for row in summary.to_dicts()}
    assert rows["short"]["sentence_rows"] == 2
    assert rows["short"]["token_count_mean"] == pytest.approx(15.0)
    assert rows["short"]["token_count_median"] == pytest.approx(15.0)
    assert rows["medium"]["sentence_rows"] == 1
    assert rows["medium"]["token_count_mean"] == pytest.approx(30.0)
    assert rows["long"]["sentence_rows"] == 1
    assert rows["long"]["token_count_mean"] is None
    metrics = finbert_staged_inference.get_finbert_staged_rust_accel_metrics()
    assert metrics["bucket_summary_fast_success"] == 1
    assert metrics["bucket_summary_fallbacks"] == 0


