def _finbert_coverage_inputs() -> tuple[pl.DataFrame, pl.DataFrame]:
    item_features = pl.DataFrame(
        {
            "doc_id": ["doc2", "doc1", "doc1", "outside-doc", None, "doc3"],
            "benchmark_item_code": ["item_7", "item_1", "item_1a", "item_7", "item_1", None],
        }
    )
    backbone = pl.DataFrame({"doc_id": ["doc3", "doc1", "doc2", "doc2", None, "doc4"]})
    return item_features, backbone


def _assert_finbert_coverage_equal(
    actual: tuple[pl.DataFrame, dict[str, int]],
    expected: tuple[pl.DataFrame, dict[str, int]],
) -> None:
    actual_coverage, actual_summary = actual
    expected_coverage, expected_summary = expected
    assert actual_coverage.columns == expected_coverage.columns
    assert actual_coverage.schema == expected_coverage.schema
    assert actual_coverage.to_dicts() == expected_coverage.to_dicts()
    assert actual_summary == expected_summary


def test_finbert_analysis_coverage_report_uses_real_rust_extension_when_built() -> None:
    if not finbert_analysis.get_finbert_analysis_rust_accel_metrics()["rust_accel_available"]:
        pytest.skip("LM2011 Rust extension is not built in this environment")
    finbert_analysis.reset_finbert_analysis_rust_accel_metrics()
    item_features, backbone = _finbert_coverage_inputs()

    result = finbert_analysis.build_coverage_report(item_features, backbone)
    expected = finbert_analysis._build_coverage_report_py(item_features, backbone)

    _assert_finbert_coverage_equal(result, expected)
    coverage, summary = result
    assert coverage["doc_id"].to_list() == ["doc1", "doc2", "doc3", "doc4"]
    assert summary == {
        "backbone_doc_count": 4,
        "covered_doc_count": 3,
        "covered_item_1_doc_count": 1,
        "covered_item_1a_doc_count": 1,
        "covered_item_7_doc_count": 1,
    }
    metrics = finbert_analysis.get_finbert_analysis_rust_accel_metrics()
    assert metrics["coverage_report_fast_success"] == 1
    assert metrics["coverage_report_fallbacks"] == 0


def test_finbert_analysis_coverage_report_matches_python_fallback_for_sample_values() -> None:
    item_features, backbone = _finbert_coverage_inputs()
    samples = [
        (item_features, backbone),
        (pl.DataFrame({"doc_id": [], "benchmark_item_code": []}, schema={"doc_id": pl.Utf8, "benchmark_item_code": pl.Utf8}), backbone),
        (item_features, pl.DataFrame({"doc_id": []}, schema={"doc_id": pl.Utf8})),
    ]
    for features, backbone_df in samples:
        _assert_finbert_coverage_equal(
            finbert_analysis.build_coverage_report(features, backbone_df),
            finbert_analysis._build_coverage_report_py(features, backbone_df),
        )


