def test_finbert_preprocessing_manifest_counts_fall_back_to_row_rust_bridge(monkeypatch) -> None:
    class FakeRust:
        def finbert_preprocessing_manifest_count_columns(self, *_args):
            raise ValueError("force column bridge fallback")

        def finbert_preprocessing_manifest_counts(self, rows):
            return finbert_sentence_preprocessing._manifest_counts_py(rows, pl.DataFrame(rows))

    monkeypatch.setattr(finbert_sentence_preprocessing, "_lm2011_rust", FakeRust())
    finbert_sentence_preprocessing.reset_finbert_preprocessing_rust_accel_metrics()
    rows = _finbert_preprocessing_summary_rows()

    assert finbert_sentence_preprocessing._manifest_counts(rows, pl.DataFrame(rows)) == (
        finbert_sentence_preprocessing._manifest_counts_py(rows, pl.DataFrame(rows))
    )
    metrics = finbert_sentence_preprocessing.get_finbert_preprocessing_rust_accel_metrics()
    assert metrics["manifest_counts_column_fast_failures"] == 1
    assert metrics["manifest_counts_column_fallbacks"] == 1
    assert metrics["manifest_counts_fast_success"] == 1
    assert metrics["manifest_counts_fallbacks"] == 0


