def test_finbert_benchmark_bucket_max_length_uses_real_rust_extension_when_built(tmp_path: Path) -> None:
    if not finbert_benchmark.get_finbert_benchmark_rust_accel_metrics()["rust_accel_available"]:
        pytest.skip("LM2011 Rust extension is not built in this environment")
    finbert_benchmark.reset_finbert_benchmark_rust_accel_metrics()

    lengths = BucketLengthSpec(short_max_length=96, medium_max_length=224, long_max_length=512)
    run_cfg = FinbertBenchmarkRunConfig(
        dataset_manifest_path=tmp_path / "manifest.json",
        out_root=tmp_path / "out",
        batch_config=BucketBatchConfig("unit", 2, 3, 4),
        bucket_lengths=lengths,
    )

    assert finbert_benchmark._bucket_max_length("short", lengths) == 96
    assert finbert_benchmark._bucket_max_length("medium", lengths) == 224
    assert finbert_benchmark._bucket_max_length("long", lengths) == 512
    assert finbert_benchmark._bucket_max_length("medium", run_cfg) == 224

    metrics = finbert_benchmark.get_finbert_benchmark_rust_accel_metrics()
    assert metrics["bucket_max_length_fast_success"] == 4
    assert metrics["bucket_max_length_fallbacks"] == 0


