class _FakeCudaModule:
    def __init__(self, available: bool) -> None:
        self._available = available

    def is_available(self) -> bool:
        return self._available


class _FakeTorchModule:
    def __init__(self, cuda_available: bool) -> None:
        self.cuda = _FakeCudaModule(cuda_available)


def test_finbert_benchmark_amp_dtype_uses_real_rust_extension_when_built() -> None:
    if not finbert_benchmark.get_finbert_benchmark_rust_accel_metrics()["rust_accel_available"]:
        pytest.skip("LM2011 Rust extension is not built in this environment")
    finbert_benchmark.reset_finbert_benchmark_rust_accel_metrics()

    torch_mod = _FakeTorchModule(cuda_available=True)
    assert finbert_benchmark._resolved_amp_dtype_name(torch_mod, FinbertRuntimeConfig(), "cuda:0") == "float16"
    assert finbert_benchmark._resolved_amp_dtype_name(
        torch_mod,
        FinbertRuntimeConfig(amp_dtype="bfloat16"),
        "cuda",
    ) == "bfloat16"
    assert finbert_benchmark._resolved_amp_dtype_name(
        torch_mod,
        FinbertRuntimeConfig(use_autocast=False),
        "cuda",
    ) is None
    assert finbert_benchmark._resolved_amp_dtype_name(torch_mod, FinbertRuntimeConfig(), "cpu") is None
    assert finbert_benchmark._resolved_amp_dtype_name(
        _FakeTorchModule(cuda_available=False),
        FinbertRuntimeConfig(),
        "cuda",
    ) is None

    metrics = finbert_benchmark.get_finbert_benchmark_rust_accel_metrics()
    assert metrics["amp_dtype_fast_success"] == 5
    assert metrics["amp_dtype_fallbacks"] == 0


def test_finbert_benchmark_amp_dtype_matches_python_fallback_for_sample_values() -> None:
    cases = [
        (_FakeTorchModule(True), FinbertRuntimeConfig(), "cuda"),
        (_FakeTorchModule(True), FinbertRuntimeConfig(amp_dtype="float16"), "cuda:1"),
        (_FakeTorchModule(True), FinbertRuntimeConfig(amp_dtype="bfloat16"), "cuda"),
        (_FakeTorchModule(True), FinbertRuntimeConfig(use_autocast=False), "cuda"),
        (_FakeTorchModule(True), FinbertRuntimeConfig(), "cpu"),
        (_FakeTorchModule(False), FinbertRuntimeConfig(), "cuda"),
    ]
    for torch_mod, runtime, device in cases:
        assert finbert_benchmark._resolved_amp_dtype_name(torch_mod, runtime, device) == (
            finbert_benchmark._resolved_amp_dtype_name_py(torch_mod, runtime, device)
        )


