def test_finbert_benchmark_softmax_uses_real_rust_extension_when_built() -> None:
    if not finbert_benchmark.get_finbert_benchmark_rust_accel_metrics()["rust_accel_available"]:
        pytest.skip("LM2011 Rust extension is not built in this environment")
    finbert_benchmark.reset_finbert_benchmark_rust_accel_metrics()

    assert finbert_benchmark._softmax_row([1.0, 2.0, 3.0]) == pytest.approx(
        finbert_benchmark._softmax_row_py([1.0, 2.0, 3.0])
    )
    probability_rows = finbert_benchmark._probability_rows_from_logits([[1.0, 2.0], [0.0, 0.0]], object())
    expected_rows = [
        finbert_benchmark._softmax_row_py([1.0, 2.0]),
        finbert_benchmark._softmax_row_py([0.0, 0.0]),
    ]
    assert len(probability_rows) == len(expected_rows)
    for actual, expected in zip(probability_rows, expected_rows):
        assert actual == pytest.approx(expected)

    metrics = finbert_benchmark.get_finbert_benchmark_rust_accel_metrics()
    assert metrics["softmax_row_fast_success"] == 1
    assert metrics["softmax_row_fallbacks"] == 0
    assert metrics["softmax_rows_fast_success"] == 1
    assert metrics["softmax_rows_fallbacks"] == 0


