def test_finbert_bucket_length_summary_rows_use_real_rust_extension_when_built() -> None:
    if not finbert_bucket_length_tuning.get_bucket_length_tuning_rust_accel_metrics()["rust_accel_available"]:
        pytest.skip("LM2011 Rust extension is not built in this environment")
    finbert_bucket_length_tuning.reset_bucket_length_tuning_rust_accel_metrics()
    edges = BucketEdgeSpec(short_edge=96, medium_edge=224)
    lengths = BucketLengthSpec(short_max_length=96, medium_max_length=224, long_max_length=512)

    actual = finbert_bucket_length_tuning._bucket_summary_rows(
        _bucket_length_grouped_summary(),
        current_edges=edges,
        current_lengths=lengths,
    )
    expected = finbert_bucket_length_tuning._bucket_summary_rows_py(
        _bucket_length_grouped_summary(),
        current_edges=edges,
        current_lengths=lengths,
    )

    assert actual == expected
    assert [row[finbert_bucket_length_tuning.TOKEN_BUCKET_COLUMN] for row in actual] == [
        "short",
        "medium",
        "long",
    ]
    assert actual[1]["sentence_rows"] == 0
    assert actual[1]["token_p999"] is None
    metrics = finbert_bucket_length_tuning.get_bucket_length_tuning_rust_accel_metrics()
    assert metrics["bucket_summary_rows_column_fast_success"] == 1
    assert metrics["bucket_summary_rows_fast_success"] == 0
    assert metrics["bucket_summary_rows_column_fallbacks"] == 0
    assert metrics["bucket_summary_rows_fallbacks"] == 0


def test_finbert_bucket_length_summary_rows_fall_back_to_row_rust_bridge(monkeypatch) -> None:
    edges = BucketEdgeSpec(short_edge=96, medium_edge=224)
    lengths = BucketLengthSpec(short_max_length=96, medium_max_length=224, long_max_length=512)

    class FakeRust:
        def finbert_bucket_length_summary_columns(self, *_args):
            raise RuntimeError("column bridge unavailable")

        def finbert_bucket_length_summary_rows(
            self,
            grouped_rows,
            _bucket_col,
            _short_edge,
            _medium_edge,
            _long_edge,
            _short_length,
            _medium_length,
            _long_length,
        ):
            return finbert_bucket_length_tuning._bucket_summary_rows_py(
                pl.DataFrame(list(grouped_rows)),
                current_edges=edges,
                current_lengths=lengths,
            )

    monkeypatch.setattr(finbert_bucket_length_tuning, "_lm2011_rust", FakeRust())
    finbert_bucket_length_tuning.reset_bucket_length_tuning_rust_accel_metrics()

    actual = finbert_bucket_length_tuning._bucket_summary_rows(
        _bucket_length_grouped_summary(),
        current_edges=edges,
        current_lengths=lengths,
    )

    assert actual == finbert_bucket_length_tuning._bucket_summary_rows_py(
        _bucket_length_grouped_summary(),
        current_edges=edges,
        current_lengths=lengths,
    )
    metrics = finbert_bucket_length_tuning.get_bucket_length_tuning_rust_accel_metrics()
    assert metrics["bucket_summary_rows_column_fast_failures"] == 1
    assert metrics["bucket_summary_rows_column_fallbacks"] == 1
    assert metrics["bucket_summary_rows_fast_success"] == 1
    assert metrics["bucket_summary_rows_fallbacks"] == 0


