def _sentence_example_sample_row(
    sentence_id: str,
    *,
    doc_id: str,
    item_code: str,
    sentiment: str,
    probability: float,
    filing_year: int,
    filing_date: dt.date,
) -> dict[str, object]:
    return {
        finbert_sentence_examples.BENCHMARK_SENTENCE_ID_COLUMN: sentence_id,
        finbert_sentence_examples.DOC_ID_COLUMN: doc_id,
        finbert_sentence_examples.CIK_COLUMN: "0000123456",
        finbert_sentence_examples.ACCESSION_COLUMN: f"{filing_year}000001",
        finbert_sentence_examples.FILING_DATE_COLUMN: filing_date,
        finbert_sentence_examples.FILING_YEAR_COLUMN: filing_year,
        finbert_sentence_examples.BENCHMARK_ITEM_CODE_COLUMN: item_code,
        finbert_sentence_examples.BENCHMARK_ITEM_LABEL_COLUMN: item_code.upper(),
        finbert_sentence_examples.SENTENCE_INDEX_COLUMN: 7,
        finbert_sentence_examples.SENTENCE_TEXT_COLUMN: f"{sentence_id} sample text",
        finbert_sentence_examples.WORD_COUNT_COLUMN: 4,
        finbert_sentence_examples.SENTIMENT_COLUMN: sentiment,
        finbert_sentence_examples.SENTIMENT_PROBABILITY_COLUMN: probability,
        finbert_sentence_examples.NEGATIVE_PROB_COLUMN: 1.0 - probability if sentiment == "positive" else probability,
        finbert_sentence_examples.NEUTRAL_PROB_COLUMN: 0.01,
        finbert_sentence_examples.POSITIVE_PROB_COLUMN: probability if sentiment == "positive" else 1.0 - probability,
        finbert_sentence_examples.PREDICTED_LABEL_COLUMN: sentiment,
        "_sample_key": 10,
        "_normalized_text": f"{sentence_id} normalized",
    }


def _sentence_example_consider_row(sentence_id: str, doc_id: str) -> dict[str, object]:
    return _sentence_example_sample_row(
        sentence_id,
        doc_id=doc_id,
        item_code="item_7",
        sentiment="positive",
        probability=0.95,
        filing_year=2001,
        filing_date=dt.date(2001, 5, 1),
    )


def _sentence_example_consider_sample_rows() -> list[tuple[dict[str, object], int, str]]:
    return [
        (_sentence_example_consider_row("sent-1", "doc-1"), 100, "duplicate text"),
        (_sentence_example_consider_row("sent-2", "doc-2"), 50, "duplicate text"),
        (_sentence_example_consider_row("sent-3", "doc-2"), 70, "fresh text"),
        (_sentence_example_consider_row("sent-4", "doc-4"), 60, "fourth text"),
        (_sentence_example_consider_row("sent-5", "doc-5"), 10, "fifth text"),
    ]


def _run_sentence_example_consider_sample(
    helper,
    rows: list[tuple[dict[str, object], int, str]],
    *,
    sample_size_per_group: int = 2,
) -> list[dict[str, object]]:
    selected: list[dict[str, object]] = []
    for row, sample_key, normalized_text in rows:
        helper(
            selected,
            row,
            sample_size_per_group=sample_size_per_group,
            seed=42,
            sample_key=sample_key,
            normalized_text=normalized_text,
        )
    return selected


def test_finbert_sentence_examples_consider_sample_uses_real_rust_extension_when_built() -> None:
    if not finbert_sentence_examples.get_sentence_examples_rust_accel_metrics()["rust_accel_available"]:
        pytest.skip("LM2011 Rust extension is not built in this environment")
