def _sentence_example_update_rows_frame() -> pl.DataFrame:
    rows = [
        _sentence_example_sample_row(
            "sent-u1",
            doc_id="doc-u1",
            item_code="item_7",
            sentiment="positive",
            probability=0.95,
            filing_year=2001,
            filing_date=dt.date(2001, 5, 1),
        ),
        _sentence_example_sample_row(
            "sent-u2",
            doc_id="doc-u2",
            item_code="item_7",
            sentiment="positive",
            probability=0.93,
            filing_year=2001,
            filing_date=dt.date(2001, 6, 1),
        ),
        _sentence_example_sample_row(
            "sent-u3",
            doc_id="doc-u3",
            item_code="item_7",
            sentiment="negative",
            probability=0.97,
            filing_year=2002,
            filing_date=dt.date(2002, 5, 1),
        ),
        _sentence_example_sample_row(
            "sent-u4",
            doc_id="doc-u4",
            item_code="item_1a",
            sentiment="positive",
            probability=0.96,
            filing_year=2002,
            filing_date=dt.date(2002, 6, 1),
        ),
    ]
    rows[1][finbert_sentence_examples.SENTENCE_TEXT_COLUMN] = "sent-u1 sample text"
    return pl.DataFrame(rows)


def _run_sentence_example_update_accumulators(helper) -> tuple[
    dict[tuple[str, str], dict[str, object]],
    dict[tuple[int, str, str], dict[str, object]],
    dict[tuple[str, str], list[dict[str, object]]],
    set[str],
]:
    counts_by_item_sentiment: dict[tuple[str, str], dict[str, object]] = {}
    counts_by_year_item_sentiment: dict[tuple[int, str, str], dict[str, object]] = {}
    selected_samples: dict[tuple[str, str], list[dict[str, object]]] = {}
    all_doc_ids: set[str] = set()
    helper(
        _sentence_example_update_rows_frame(),
        counts_by_item_sentiment=counts_by_item_sentiment,
        counts_by_year_item_sentiment=counts_by_year_item_sentiment,
        selected_samples=selected_samples,
        sample_size_per_group=2,
        seed=42,
        all_doc_ids=all_doc_ids,
    )
    return (
        counts_by_item_sentiment,
        counts_by_year_item_sentiment,
        selected_samples,
        all_doc_ids,
    )


