def _sentence_example_markdown_inputs() -> tuple[pl.DataFrame, pl.DataFrame, dict[str, object]]:
    sample_rows = finbert_sentence_examples._sample_candidate_rows(
        _sentence_example_selected_samples(),
        ordered_items=("item_7", "item_1a"),
    )
    sample_candidates = pl.DataFrame(sample_rows, schema_overrides=finbert_sentence_examples.SAMPLE_OUTPUT_SCHEMA)
    counts_by_item_sentiment = pl.DataFrame(
        {
            finbert_sentence_examples.BENCHMARK_ITEM_CODE_COLUMN: ["item_7", "item_7", "item_1a"],
            finbert_sentence_examples.SENTIMENT_COLUMN: ["positive", "negative", "positive"],
            "candidate_rows": [7, 2, 3],
            "doc_count": [6, 2, 3],
        }
    )
    metadata: dict[str, object] = {
        "sentence_scores_dir": "scores/by_year",
        "filters": {
            "item_codes": ["item_7", "item_1a"],
            "min_probability": 0.95,
            "min_word_count": 6,
            "batch_size": 50000,
        },
        "candidate_rows": 12,
        "candidate_doc_count": 10,
        "sample_size_per_group": 2,
        "sample_seed": 42,
        "item_codes_present_ordered": ["item_7", "item_1a"],
    }
    return sample_candidates, counts_by_item_sentiment, metadata


def test_finbert_sentence_examples_markdown_renderer_uses_real_rust_extension_when_built() -> None:
    if not finbert_sentence_examples.get_sentence_examples_rust_accel_metrics()["rust_accel_available"]:
        pytest.skip("LM2011 Rust extension is not built in this environment")
    finbert_sentence_examples.reset_sentence_examples_rust_accel_metrics()

    sample_candidates, counts_by_item_sentiment, metadata = _sentence_example_markdown_inputs()
    actual = finbert_sentence_examples._render_sample_markdown(
        sample_candidates,
        counts_by_item_sentiment,
        metadata,
    )
    expected = finbert_sentence_examples._render_sample_markdown_py(
        sample_candidates,
        counts_by_item_sentiment,
        metadata,
    )

    assert actual == expected
    assert "## Item 7 | Positive" in actual
    assert "Eligible candidates: 7 | Listed samples: 3" in actual
    metrics = finbert_sentence_examples.get_sentence_examples_rust_accel_metrics()
    assert metrics["render_markdown_column_fast_success"] == 1
    assert metrics["render_markdown_fast_success"] == 0
    assert metrics["render_markdown_column_fallbacks"] == 0
    assert metrics["render_markdown_fallbacks"] == 0


def test_finbert_sentence_examples_markdown_renderer_fall_back_to_row_rust_bridge(monkeypatch) -> None:
    class FakeRust:
        def finbert_sentence_render_sample_markdown_columns(self, *_args):
            raise RuntimeError("column bridge unavailable")

        def finbert_sentence_render_sample_markdown(
            self,
            sample_rows,
            count_rows,
            metadata,
            _sentiment_order,
        ):
            return finbert_sentence_examples._render_sample_markdown_py(
                pl.DataFrame(list(sample_rows), schema_overrides=finbert_sentence_examples.SAMPLE_OUTPUT_SCHEMA),
                pl.DataFrame(list(count_rows)),
                metadata,
            )

    monkeypatch.setattr(finbert_sentence_examples, "_lm2011_rust", FakeRust())
    finbert_sentence_examples.reset_sentence_examples_rust_accel_metrics()

    sample_candidates, counts_by_item_sentiment, metadata = _sentence_example_markdown_inputs()
    assert finbert_sentence_examples._render_sample_markdown(
        sample_candidates,
        counts_by_item_sentiment,
        metadata,
    ) == finbert_sentence_examples._render_sample_markdown_py(
        sample_candidates,
        counts_by_item_sentiment,
        metadata,
    )

    metrics = finbert_sentence_examples.get_sentence_examples_rust_accel_metrics()
    assert metrics["render_markdown_column_fast_failures"] == 1
    assert metrics["render_markdown_column_fallbacks"] == 1
    assert metrics["render_markdown_fast_success"] == 1
    assert metrics["render_markdown_fallbacks"] == 0


