def test_finbert_tail_doc_surface_falls_back_to_row_rust_bridge(monkeypatch) -> None:
    class FakeRust:
        def finbert_tail_doc_surface_columns(self, *_args):
            raise ValueError("force column bridge fallback")

        def finbert_tail_doc_surface_rows(self, rows, text_scopes):
            return finbert_tail_features._build_finbert_tail_doc_surface_py(
                pl.DataFrame(rows),
                text_scopes=text_scopes,
            ).to_dicts()

    scores = _tail_doc_surface_sentence_scores()
    expected = finbert_tail_features._build_finbert_tail_doc_surface_py(
        scores,
        text_scopes=("item_7_mda", "item_1a_risk_factors"),
    )
    monkeypatch.setattr(finbert_tail_features, "_lm2011_rust", FakeRust())
    finbert_tail_features.reset_finbert_tail_rust_accel_metrics()

    actual = finbert_tail_features.build_finbert_tail_doc_surface(
        scores,
        text_scopes=("item_7_mda", "item_1a_risk_factors"),
    )

    _assert_tail_doc_surface_equal(actual, expected)
    metrics = finbert_tail_features.get_finbert_tail_rust_accel_metrics()
    assert metrics["doc_surface_column_fast_failures"] == 1
    assert metrics["doc_surface_column_fallbacks"] == 1
    assert metrics["doc_surface_fast_success"] == 1
    assert metrics["doc_surface_fallbacks"] == 0


