def test_finbert_sentence_confusion_sampling_helpers_use_real_rust_extension_when_built() -> None:
    if not finbert_sentence_confusion_review.get_confusion_review_rust_accel_metrics()["rust_accel_available"]:
        pytest.skip("LM2011 Rust extension is not built in this environment")
    finbert_sentence_confusion_review.reset_confusion_review_rust_accel_metrics()

    assert finbert_sentence_confusion_review._candidate_threshold(100, 20, 2.0) == pytest.approx(0.4)
    assert finbert_sentence_confusion_review._candidate_threshold(10, 20, 10.0) == 1.0
    assert finbert_sentence_confusion_review._candidate_threshold(0, 20, 2.0) == 0.0
    assert finbert_sentence_confusion_review._confusion_cell("negative", "yes") == "TP"
    assert finbert_sentence_confusion_review._confusion_cell("negative", "no") == "FP"
    assert finbert_sentence_confusion_review._confusion_cell("positive", "yes") == "FN"
    assert finbert_sentence_confusion_review._confusion_cell("neutral", "no") == "TN"
    assert finbert_sentence_confusion_review._confusion_cell("negative", "uncertain") == "uncertain"

    metrics = finbert_sentence_confusion_review.get_confusion_review_rust_accel_metrics()
    assert metrics["candidate_threshold_fast_success"] == 3
    assert metrics["candidate_threshold_fallbacks"] == 0
    assert metrics["confusion_cell_fast_success"] == 5
    assert metrics["confusion_cell_fallbacks"] == 0


def test_finbert_sentence_confusion_sampling_helpers_match_python_fallback_for_sample_values() -> None:
    threshold_cases = [
        (100, 20, 2.0),
        (10, 20, 10.0),
        (0, 20, 2.0),
        (100, 0, 2.0),
        (-1, 5, 2.0),
    ]
    for population_count, sample_count, oversampling_factor in threshold_cases:
        assert finbert_sentence_confusion_review._candidate_threshold(
            population_count,
            sample_count,
            oversampling_factor,
        ) == pytest.approx(
            finbert_sentence_confusion_review._candidate_threshold_py(
                population_count,
                sample_count,
                oversampling_factor,
            )
        )

    cell_cases = [
        ("negative", "yes"),
        ("negative", "no"),
        ("positive", "yes"),
        ("neutral", "no"),
        ("negative", "uncertain"),
        ("NEGATIVE", "yes"),
    ]
    for predicted_label, gold_negative in cell_cases:
        assert finbert_sentence_confusion_review._confusion_cell(predicted_label, gold_negative) == (
            finbert_sentence_confusion_review._confusion_cell_py(predicted_label, gold_negative)
        )


