    assert actual_rows[1]["confusion_cell"] == "TN"
    assert actual_rows[2]["gold_negative_final"] == "uncertain"
    assert actual_rows[3]["gold_negative_source"] == "missing"
    assert actual_rows[3]["confusion_cell"] == "uncertain"


