def test_finbert_sentence_confusion_metric_payload_matches_python_fallback_for_sample_values() -> None:
    cases = [
        {},
        {"TP": 0.0, "FP": 0.0, "FN": 0.0, "TN": 0.0},
        {"TP": 8.0, "FP": 2.0, "FN": 4.0, "TN": 6.0},
        {"TP": 1.5, "FP": 0.5, "FN": 0.0, "TN": 2.0},
    ]
    for counts in cases:
        payload = finbert_sentence_confusion_review._metric_payload(counts)
        expected = finbert_sentence_confusion_review._metric_payload_py(counts)
        assert payload.keys() == expected.keys()
        for key, expected_value in expected.items():
            if expected_value is None:
                assert payload[key] is None
            else:
                assert payload[key] == pytest.approx(expected_value)


