def test_finbert_sentence_confusion_bucket_metric_rows_fall_back_to_row_rust_bridge(
    monkeypatch,
) -> None:
    class FakeRust:
        def finbert_confusion_bucket_metric_columns(self, *_args):
            raise ValueError("force column bridge fallback")

        def finbert_confusion_bucket_metric_rows(self, rows):
            return [
                tuple(row.values())
                for row in finbert_sentence_confusion_review._bucket_metric_rows_py(
                    pl.DataFrame(rows)
                )
                .select(
                    [
                        "probability_majority_bucket",
                        "row_count",
                        "weighted_TP",
                        "weighted_FP",
                        "weighted_FN",
                        "weighted_TN",
                        "weighted_uncertain",
                        "precision",
                        "recall",
                        "specificity",
                    ]
                )
                .to_dicts()
            ]

    monkeypatch.setattr(finbert_sentence_confusion_review, "_lm2011_rust", FakeRust())
    finbert_sentence_confusion_review.reset_confusion_review_rust_accel_metrics()

    frame = pl.DataFrame(_confusion_review_metric_rows())
    _assert_bucket_metric_frames_equal(
        finbert_sentence_confusion_review._bucket_metric_rows(frame),
        finbert_sentence_confusion_review._bucket_metric_rows_py(frame),
    )
    metrics = finbert_sentence_confusion_review.get_confusion_review_rust_accel_metrics()
    assert metrics["bucket_metric_rows_column_fast_failures"] == 1
    assert metrics["bucket_metric_rows_column_fallbacks"] == 1
    assert metrics["bucket_metric_rows_fast_success"] == 1
    assert metrics["bucket_metric_rows_fallbacks"] == 0


