def _finbert_share_row_frames() -> tuple[pl.DataFrame, pl.DataFrame]:
    eligible = pl.DataFrame(
        {
            "filing_year": [2000, 2000, 2000, 2001, 2001, 2001],
            "benchmark_item_code": ["item_7", "item_1a", "item_1a", "item_7", "item_7", "item_1a"],
            "doc_id": ["a", "b", "c", "d", "e", "f"],
        }
    )
    selected = pl.DataFrame(
        {
            "filing_year": [2000, 2000, 2001],
            "benchmark_item_code": ["item_7", "item_1a", "item_7"],
            "doc_id": ["a", "b", "d"],
        }
    )
    return eligible, selected


def _assert_finbert_share_rows_equal(
    actual: list[dict[str, object]],
    expected: list[dict[str, object]],
) -> None:
    def sort_key(row: dict[str, object]) -> tuple[str, ...]:
        return tuple(
            repr(row.get(column))
            for column in (
                "filing_year",
                "benchmark_item_code",
                "filing_year_right",
                "benchmark_item_code_right",
            )
        )

    actual = sorted(actual, key=sort_key)
    expected = sorted(expected, key=sort_key)
    assert len(actual) == len(expected)
    for actual_row, expected_row in zip(actual, expected, strict=True):
        assert actual_row.keys() == expected_row.keys()
        for key, expected_value in expected_row.items():
            if isinstance(expected_value, float):
                assert actual_row[key] == pytest.approx(expected_value)
            else:
                assert actual_row[key] == expected_value


