    if not finbert_dataset.get_finbert_dataset_rust_accel_metrics()["rust_accel_available"]:
        pytest.skip("LM2011 Rust extension is not built in this environment")
    finbert_dataset.reset_finbert_dataset_rust_accel_metrics()

    eligible, selected = _finbert_share_row_frames()
    keys = ["filing_year", "benchmark_item_code"]
    actual = finbert_dataset._share_rows(eligible, selected, keys, total_keys=["filing_year"])
    expected = finbert_dataset._share_rows_py(eligible, selected, keys, total_keys=["filing_year"])

    _assert_finbert_share_rows_equal(actual, expected)
    metrics = finbert_dataset.get_finbert_dataset_rust_accel_metrics()
    assert metrics["share_rows_column_fast_success"] == 1
    assert metrics["share_rows_fast_success"] == 0
    assert metrics["share_rows_column_fallbacks"] == 0
    assert metrics["share_rows_fallbacks"] == 0


