    class FakeRust:
        def finbert_dataset_share_row_columns(self, *_args):
            raise RuntimeError("column bridge unavailable")

        def finbert_dataset_share_rows(self, groups):
            return finbert_dataset._share_rows_from_sorted_groups_py(groups)

    monkeypatch.setattr(finbert_dataset, "_lm2011_rust", FakeRust())
    finbert_dataset.reset_finbert_dataset_rust_accel_metrics()

    eligible, selected = _finbert_share_row_frames()
