    _assert_finbert_share_rows_equal(actual, expected)
    metrics = finbert_dataset.get_finbert_dataset_rust_accel_metrics()
    assert metrics["share_rows_column_fast_failures"] == 1
    assert metrics["share_rows_column_fallbacks"] == 1
