def _manifest_guard_pair() -> tuple[dict[str, object], dict[str, object]]:
    existing = {
        "version": "v1",
        "payload": {
            "authority": "model-a",
            "years": [2001, 2002],
            "stale_only": True,
        },
        "fingerprints": {
            "source": {"sha256": "aaa", "rows": 10},
            "backbone": "old",
        },
    }
    expected = {
        "version": "v2",
        "payload": {
            "authority": "model-a",
            "years": [2001, 2003],
            "new_key": "added",
        },
        "fingerprints": {
            "source": {"sha256": "aaa", "rows": 10},
            "backbone": "new",
        },
    }
    return existing, expected


