def test_manifest_contract_hash_helpers_match_python_fallback_for_sample_values(tmp_path: Path) -> None:
    payloads = [
        {},
        {"b": 2, "a": ["one", 3]},
        {"unicode": "StraÃŸe"},
    ]
    for payload in payloads:
        assert manifest_contracts.json_sha256(payload) == manifest_contracts.json_sha256_py(payload)

    value_sets = [
        [],
        ["b", None, "a", "b"],
        ["line\nbreak", "plain"],
        [3, None, 1, 3],
    ]
    for values in value_sets:
        assert manifest_contracts.stable_string_fingerprint(values) == (
            manifest_contracts.stable_string_fingerprint_py(values)
        )

    for length in (0, 3, 55, 56, 64, 65):
        path = tmp_path / f"sha256_parity_{length}.bin"
        path.write_bytes(bytes((idx % 251 for idx in range(length))))
        assert manifest_contracts._file_sha256(path) == manifest_contracts._file_sha256_py(path)

    guard_cases = [
        _manifest_guard_pair(),
        ({"version": "v1"}, {"version": "v1", "payload": {"x": 1}}),
        (
            {"version": None, "payload": {"x": None}, "fingerprints": {}},
            {"version": None, "payload": {}, "fingerprints": {"file": "abc"}},
        ),
    ]
    for existing, expected in guard_cases:
        assert manifest_contracts.semantic_guard_mismatches(existing, expected) == (
            manifest_contracts.semantic_guard_mismatches_py(existing, expected)
        )


