def test_lm2011_microbatch_span_planner_uses_real_rust_extension_when_built() -> None:
    if not lm2011_text.get_lm2011_rust_accel_metrics()["rust_accel_available"]:
        pytest.skip("LM2011 Rust extension is not built in this environment")
    lm2011_text.reset_lm2011_rust_accel_metrics()

    spans = lm2011_text._eager_text_microbatch_spans(
        [5, 8, 2, 30, 4],
        max_docs_per_batch=2,
        max_input_text_bytes_per_microbatch=10,
    )
    assert spans == [(0, 1), (1, 2), (3, 1), (4, 1)]

    batch = pl.DataFrame(
        {
            "doc_id": ["d1", "d2", "d3", "d4", "d5"],
            "text": ["a" * 5, "b" * 8, "cc", "d" * 30, "eeee"],
        }
    )
    shards = list(
        lm2011_text._eager_text_microbatch_slices(
            batch,
            text_col="text",
            max_docs_per_batch=2,
            max_input_text_bytes_per_microbatch=10,
        )
    )
    assert [shard.get_column("doc_id").to_list() for shard in shards] == [["d1"], ["d2", "d3"], ["d4"], ["d5"]]

    metrics = lm2011_text.get_lm2011_rust_accel_metrics()
    assert metrics["microbatch_plan_fast_success"] == 2
    assert metrics["microbatch_plan_fallbacks"] == 0


