def test_lm2011_doc_id_validation_uses_real_rust_extension_when_built() -> None:
    if not lm2011_text.get_lm2011_rust_accel_metrics()["rust_accel_available"]:
        pytest.skip("LM2011 Rust extension is not built in this environment")
    lm2011_text.reset_lm2011_rust_accel_metrics()

    seen_doc_ids: set[str | None] = {"already-seen"}
    batch = pl.DataFrame({"doc_id": ["doc-1", "doc-2", None]})
    lm2011_text._validate_incremental_text_doc_ids(batch, seen_doc_ids=seen_doc_ids)

    assert seen_doc_ids == {"already-seen", "doc-1", "doc-2", None}

    duplicate_batch = pl.DataFrame({"doc_id": ["doc-3", "doc-3", "already-seen"]})
    with pytest.raises(ValueError, match="LM2011 text scoring requires doc_id to be unique"):
        lm2011_text._validate_incremental_text_doc_ids(duplicate_batch, seen_doc_ids=seen_doc_ids)

    metrics = lm2011_text.get_lm2011_rust_accel_metrics()
    assert metrics["doc_id_validation_fast_success"] == 2
    assert metrics["doc_id_validation_fallbacks"] == 0


def test_lm2011_doc_id_validation_matches_python_fallback_for_sample_values() -> None:
    cases = [
        (["doc-1", "doc-2", None], {"old-doc"}),
        (["doc-1", "doc-1"], set()),
        ([None, None], set()),
        (["old-doc"], {"old-doc"}),
    ]
    for doc_ids, initial_seen in cases:
        batch = pl.DataFrame({"doc_id": doc_ids})
        rust_seen = set(initial_seen)
        py_seen = set(initial_seen)
        try:
            lm2011_text._validate_incremental_text_doc_ids(batch, seen_doc_ids=rust_seen)
        except ValueError as rust_exc:
            with pytest.raises(ValueError) as py_exc:
                lm2011_text._validate_incremental_text_doc_ids_py(batch, seen_doc_ids=py_seen)
            assert str(rust_exc) == str(py_exc.value)
        else:
            lm2011_text._validate_incremental_text_doc_ids_py(batch, seen_doc_ids=py_seen)
            assert rust_seen == py_seen


