def test_lm2011_text_feature_builder_uses_rust_counter_when_available(monkeypatch) -> None:
    class _FakeCounter:
        def __init__(self, vocabulary: list[str], master_dictionary_words: list[str]) -> None:
            self.vocabulary = set(vocabulary)
            self.master_dictionary_words = set(master_dictionary_words)

        def count_document_tokens(self, text: str | None) -> tuple[int, int, dict[str, int]]:
            tokens = list(lm2011_text._iter_lm2011_tokens_py(text))
            counts = Counter(token for token in tokens if token in self.vocabulary)
            recognized = sum(1 for token in tokens if token in self.master_dictionary_words)
            return len(tokens), recognized, dict(counts)

    class _FakeRustModule:
        Lm2011TokenCounter = _FakeCounter

        @staticmethod
        def tokenize_lm2011_text(text: str | None) -> list[str]:
            return list(lm2011_text._iter_lm2011_tokens_py(text))

        @staticmethod
        def normalize_lm2011_dictionary_tokens(values: list[str]) -> list[str]:
            return sorted(lm2011_text._normalize_dictionary_tokens_py(values))

        @staticmethod
        def prepare_lm2011_document_stats(
            batches: list[list[dict[str, object]]],
            text_col: str,
            vocabulary: list[str],
            master_dictionary_words: list[str],
        ) -> tuple[list[dict[str, object]], dict[str, Counter[str]], dict[str, int], dict[str, int], dict[str, float]]:
            frames = [pl.DataFrame(batch) for batch in batches]
            return lm2011_text._prepare_document_stats_py(
                frames,
                text_col=text_col,
                vocabulary=frozenset(vocabulary),
                master_dictionary_words=frozenset(master_dictionary_words),
            )

        @staticmethod
        def prepare_lm2011_pass1_rows(
            rows: list[dict[str, object]],
            text_col: str,
            vocabulary: list[str],
            master_dictionary_words: list[str],
            token_count_col: str,
            total_token_count_col: str,
        ) -> tuple[list[dict[str, object]], Counter[str]]:
            return lm2011_text._prepare_pass1_rows_py(
                pl.DataFrame(rows),
                text_col=text_col,
                vocabulary=frozenset(vocabulary),
                master_dictionary_words=frozenset(master_dictionary_words),
                token_count_col=token_count_col,
                total_token_count_col=total_token_count_col,
            )

        @staticmethod
        def build_lm2011_feature_rows(
            base_rows: list[dict[str, object]],
            doc_token_counts: dict[str, Counter[str]],
            doc_token_totals: dict[str, int],
            doc_recognized_word_totals: dict[str, int],
            idf_by_token: dict[str, float],
            token_count_col: str,
            total_token_count_col: str,
            signal_specs: tuple[tuple[str, frozenset[str], bool], ...],
        ) -> list[dict[str, object]]:
            return lm2011_text._build_feature_rows_py(
                base_rows,
                doc_token_counts=doc_token_counts,
                doc_token_totals=doc_token_totals,
                doc_recognized_word_totals=doc_recognized_word_totals,
                idf_by_token=idf_by_token,
                token_count_col=token_count_col,
                total_token_count_col=total_token_count_col,
                signal_specs=signal_specs,
            )

        @staticmethod
        def build_lm2011_feature_rows_from_pass1(
            pass1_rows: list[dict[str, object]],
            raw_form_col: str,
            token_count_col: str,
            total_token_count_col: str,
            signal_specs: tuple[tuple[str, frozenset[str], bool], ...],
            idf_by_token: dict[str, float],
            cleaning_policy_id: str | None,
        ) -> list[dict[str, object]]:
            return lm2011_text._feature_rows_from_pass1_py(
                pass1_rows,
                raw_form_col=raw_form_col,
                token_count_col=token_count_col,
                total_token_count_col=total_token_count_col,
                signal_specs=signal_specs,
                idf_by_token=idf_by_token,
                cleaning_policy_id=cleaning_policy_id,
            )

    monkeypatch.setattr(lm2011_text, "_lm2011_rust", _FakeRustModule())
    lm2011_text.reset_lm2011_rust_accel_metrics()

    sec_items = pl.DataFrame(
        {
            "doc_id": ["d1"],
            "cik_10": ["0000000001"],
            "filing_date": [dt.date(2020, 1, 1)],
            "document_type_filename": ["10-K"],
            "item_id": ["7"],
            "full_text": ["Loss loss gain uncertain must may lawsuit alpha-\n beta"],
        }
    )

    out = lm2011_text.build_lm2011_text_features_mda(
        sec_items.lazy(),
        dictionary_lists=_dictionary_lists(),
        harvard_negative_word_list=["loss"],
        master_dictionary_words=["loss", "gain", "uncertain", "must", "may", "lawsuit"],
    ).collect()

    assert out.item(0, "total_token_count_mda") == 8
    assert out.item(0, "token_count_mda") == 7
    assert out.item(0, "lm_negative_prop") == 2 / 8
    metrics = lm2011_text.get_lm2011_rust_accel_metrics()
    assert metrics["counter_init_success"] == 1
    assert metrics["count_fast_success"] == 1
    assert metrics["count_fallbacks"] == 0


def test_parquet_stream_copy_uses_real_rust_extension_when_built(tmp_path: Path) -> None:
    if not parquet_io.get_parquet_rust_accel_metrics()["rust_accel_available"]:
        pytest.skip("LM2011 Rust extension is not built in this environment")
    parquet_io.reset_parquet_rust_accel_metrics()

    payload = b"alpha" + bytes(range(128)) + (b"omega" * 17)
    src = tmp_path / "source.bin"
    dst = tmp_path / "copied.bin"
    src.write_bytes(payload)

    parquet_io._copy_file_stream(src, dst, buffer_size=13)

    assert dst.read_bytes() == payload
    metrics = parquet_io.get_parquet_rust_accel_metrics()
    assert metrics["copy_file_stream_fast_success"] == 1
    assert metrics["copy_file_stream_fallbacks"] == 0


