def test_parquet_stream_copy_falls_back_after_rust_failure(monkeypatch, tmp_path: Path) -> None:
    class _FailingRustModule:
        @staticmethod
        def copy_file_stream(src: str, dst: str, buffer_size: int) -> None:
            raise RuntimeError("forced copy failure")

    monkeypatch.setattr(parquet_io, "_lm2011_rust", _FailingRustModule())
    parquet_io.reset_parquet_rust_accel_metrics()

    src = tmp_path / "source.bin"
    dst = tmp_path / "copied.bin"
    src.write_bytes(b"retry-after-rust-error")

    parquet_io._copy_file_stream(src, dst, buffer_size=7)

    assert dst.read_bytes() == b"retry-after-rust-error"
    metrics = parquet_io.get_parquet_rust_accel_metrics()
    assert metrics["copy_file_stream_fast_failures"] == 1
    assert metrics["copy_file_stream_fallbacks"] == 1


def test_parquet_magic_probe_uses_real_rust_extension_when_built(tmp_path: Path) -> None:
    if not parquet_io.get_parquet_rust_accel_metrics()["rust_accel_available"]:
        pytest.skip("LM2011 Rust extension is not built in this environment")
    parquet_io.reset_parquet_rust_accel_metrics()

    valid = tmp_path / "valid.parquet"
    bad_header = tmp_path / "bad_header.parquet"
    valid.write_bytes(b"PAR1payloadPAR1")
    bad_header.write_bytes(b"NOPEpayloadPAR1")

    parquet_io._assert_parquet_magic(valid)
    with pytest.raises(OSError, match="magic header missing"):
        parquet_io._assert_parquet_magic(bad_header)

    metrics = parquet_io.get_parquet_rust_accel_metrics()
    assert metrics["magic_probe_fast_success"] == 2
    assert metrics["magic_probe_fallbacks"] == 0


def test_parquet_magic_probe_matches_python_fallback_for_sample_values(tmp_path: Path) -> None:
    cases = {
        "valid.parquet": b"PAR1payloadPAR1",
        "too_small.parquet": b"PAR1",
        "bad_header.parquet": b"NOPEpayloadPAR1",
        "bad_footer.parquet": b"PAR1payloadNOPE",
    }

    for filename, payload in cases.items():
        path = tmp_path / filename
        path.write_bytes(payload)
        try:
            parquet_io._assert_parquet_magic(path)
        except OSError as rust_exc:
            with pytest.raises(OSError) as py_exc:
                parquet_io._assert_parquet_magic_py(path)
            assert str(rust_exc) == str(py_exc.value)
        else:
            parquet_io._assert_parquet_magic_py(path)


