    request_doc_ids = ["doc-1", "doc-2", None, "", "doc-3"]
    retrieval_eligible = [True, True, True, True, None]
    returned_doc_ids = ["doc-2", None, "doc-2", ""]

    assert lseg_recovery._doc_unresolved_mask(
        request_doc_ids,
        retrieval_eligible,
        returned_doc_ids,
    ) == lseg_recovery._doc_unresolved_mask_py(
        request_doc_ids,
        retrieval_eligible,
        returned_doc_ids,
    )
    assert lseg_recovery._doc_unresolved_mask(
        request_doc_ids,
        retrieval_eligible,
        returned_doc_ids,
    ) == [True, False, False, False, False]
    metrics = lseg_recovery.get_lseg_recovery_rust_accel_metrics()
    assert metrics["doc_unresolved_mask_fast_success"] == 2
    assert metrics["doc_unresolved_mask_fallbacks"] == 0


