def test_lseg_recovery_doc_unresolved_artifact_preserves_row_order_and_contract(tmp_path: Path) -> None:
    lseg_recovery.reset_lseg_recovery_rust_accel_metrics()
    requests_path = tmp_path / "doc_requests.parquet"
    raw_path = tmp_path / "doc_raw.parquet"
    output_path = tmp_path / "doc_unresolved.parquet"

    pl.DataFrame(
        {
            "doc_id": ["doc-1", "doc-2", None, "", "doc-3", "doc-4"],
            "retrieval_eligible": [True, True, True, True, False, None],
            "request_stage": ["EXACT", "EXACT", "EXACT", "FALLBACK", "EXACT", "EXACT"],
        }
    ).write_parquet(requests_path)
    pl.DataFrame(
        {
            "doc_id": ["doc-2", None, "doc-2", ""],
            "response_stage": ["EXACT", "EXACT", "FALLBACK", "FALLBACK"],
        }
    ).write_parquet(raw_path)

    artifact = lseg_recovery.build_doc_unresolved_recovery_artifact(
        recovery_mode="doc_exact_unresolved",
        requests_parquet_path=requests_path,
        raw_parquet_path=raw_path,
        output_path=output_path,
    )

    assert artifact.row_count == 1
    assert artifact.source_artifacts == {
        "requests_parquet": requests_path,
        "raw_parquet": raw_path,
    }
    assert pl.read_parquet(output_path).to_dicts() == [
        {"doc_id": "doc-1", "retrieval_eligible": True, "request_stage": "EXACT"}
    ]
